import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAIHint = async (targetWord: string, distractor: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Lumina Quest adlı bilim kurgu temalı bir oyunda oyuncu "${targetWord}" ve "${distractor}" kelimeleri arasında kaldı. 
      Lumina rehberi (bilge bir yapay zeka) gibi davranarak, "${targetWord}" kelimesini seçmesi için gizemli, kısa ve şiirsel bir ipucu ver. 
      Asla doğrudan kelimeyi söyleme. Maksimum 15 kelime.`,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Evrenin enerjisi şu an bulanık, birazdan tekrar dene...";
  }
};

import React, { useState, useEffect } from 'react';
import { GameState, UserStats, HubSubView } from './types';
import { LoadingScreen } from './screens/LoadingScreen';
import { HubScreen } from './screens/HubScreen';
import { MemoryGame } from './screens/MemoryGame';
import { WordPuzzle } from './screens/WordPuzzle';
import { TermsModal } from './components/TermsModal';
import { LevelCompleteModal } from './components/LevelCompleteModal';
import { LevelFailModal } from './components/LevelFailModal';
import { ChestModal } from './components/ChestModal';
import { MemoryTransitionModal } from './components/MemoryTransitionModal';
import { SoundManager } from './managers/SoundManager';
import { auth, syncUserStats, getUserStats } from './lib/firebase';
import { onAuthStateChanged, User } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

const REFILL_TIME = 10 * 60 * 1000;
const STORAGE_KEY = 'lumina_stats';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [gameState, setGameState] = useState<GameState>(GameState.LOADING);
  const [hubSubView, setHubSubView] = useState<HubSubView>(HubSubView.MAIN);

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { console.error(e); }
    }
    return {
      coins: 2063, hearts: 5, stars: 12, level: 1,
      lastLifeRefillTime: Date.now(),
      difficultyFactor: 1.0, performanceHistory: [],
      streak: 0, maxStreak: 0
    };
  });

  // Firebase Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      setUser(firebaseUser);
      if (firebaseUser) {
        const cloudStats = await getUserStats(firebaseUser.uid);
        if (cloudStats) {
          setStats(prev => ({ ...prev, ...cloudStats }));
        }
      }
    });
    return () => unsubscribe();
  }, []);

  // Sync to Cloud & Local on changes
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stats));
    if (user) {
      syncUserStats(user.uid, stats);
    }
  }, [stats, user]);

  const [targetWords, setTargetWords] = useState<string[]>([]);
  const [fullWordPool, setFullWordPool] = useState<string[]>([]);
  const [showTerms, setShowTerms] = useState(false);
  const [showChest, setShowChest] = useState(false);
  const [bonusEarned, setBonusEarned] = useState(0);
  const [sessionScore, setSessionScore] = useState(0);
  const [starsEarnedInLevel, setStarsEarnedInLevel] = useState(0);
  const [transitionState, setTransitionState] = useState<'idle' | 'animating'>('idle');
  const [flashEffect, setFlashEffect] = useState(false);

  useEffect(() => {
    SoundManager.getInstance().setLevel(stats.level);
    SoundManager.getInstance().setDifficulty(stats.difficultyFactor);
  }, [stats.level, stats.difficultyFactor]);

  useEffect(() => {
    if (stats.hearts >= 5) return;
    const interval = setInterval(() => {
      const now = Date.now();
      const diff = now - stats.lastLifeRefillTime;
      if (diff >= REFILL_TIME) {
        const heartsToAdd = Math.floor(diff / REFILL_TIME);
        setStats(prev => ({
          ...prev,
          hearts: Math.min(5, prev.hearts + heartsToAdd),
          lastLifeRefillTime: prev.hearts + heartsToAdd >= 5 ? now : prev.lastLifeRefillTime + (heartsToAdd * REFILL_TIME)
        }));
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [stats.hearts, stats.lastLifeRefillTime]);

  const updateDifficulty = (isSuccess: boolean, perfection: number = 0) => {
    setStats(prev => {
      let newFactor = prev.difficultyFactor;
      const history = [...prev.performanceHistory, isSuccess].slice(-5);
      let newStreak = isSuccess ? prev.streak + 1 : 0;
      let newMaxStreak = Math.max(prev.maxStreak, newStreak);
      if (isSuccess) {
        const boost = perfection === 5 ? 0.15 : 0.05;
        newFactor = Math.min(2.0, newFactor + boost);
      } else {
        newFactor = Math.max(0.5, newFactor - 0.1);
      }
      return { ...prev, difficultyFactor: newFactor, performanceHistory: history, streak: newStreak, maxStreak: newMaxStreak };
    });
  };

  const changeGameState = (newState: GameState) => {
    setTransitionState('animating');
    setTimeout(() => {
      setGameState(newState);
      setFlashEffect(true);
      setTimeout(() => setFlashEffect(false), 300);
      setTimeout(() => setTransitionState('idle'), 50);
    }, 300);
  };

  const handleLoadingFinished = () => {
    const hasAccepted = localStorage.getItem('terms_accepted');
    if (hasAccepted) { changeGameState(GameState.HUB); } 
    else { setGameState(GameState.TERMS); setShowTerms(true); }
  };

  const handleTermsAccept = () => {
    localStorage.setItem('terms_accepted', 'true');
    setShowTerms(false);
    changeGameState(GameState.HUB);
  };

  const handlePuzzleComplete = (earned: number, allTargets: string[], allDistractors: string[]) => {
    setStats(prev => ({ ...prev, coins: prev.coins + earned }));
    setSessionScore(earned);
    setTargetWords(allTargets);
    const pooledWords = [...allTargets, ...allDistractors].sort(() => Math.random() - 0.5);
    setFullWordPool(pooledWords);
    changeGameState(GameState.MEMORY_PREPARE);
  };

  const handleManualQuit = () => {
    setStats(prev => ({ ...prev, hearts: Math.max(0, prev.hearts - 1), streak: 0 }));
    updateDifficulty(false);
    changeGameState(GameState.HUB);
  };

  const handleGameFail = () => {
    setStats(prev => {
      setTimeout(() => changeGameState(GameState.LEVEL_FAIL), 500);
      return { ...prev, hearts: Math.max(0, prev.hearts - 1), streak: 0 };
    });
    updateDifficulty(false);
  };

  const handleGameComplete = (correctCount: number) => {
    let bonus = 0; let stars = 0;
    if (correctCount === 3) { stars = 1; } 
    else if (correctCount === 4) { bonus = 100; stars = 2; } 
    else if (correctCount === 5) { bonus = 250; stars = 3; }
    setStarsEarnedInLevel(stars);
    setBonusEarned(bonus);
    updateDifficulty(true, correctCount);
    changeGameState(GameState.LEVEL_COMPLETE);
  };

  const handleLevelContinue = () => {
    setStats(prev => ({ ...prev, level: prev.level + 1, coins: prev.coins + 150 + bonusEarned, stars: prev.stars + starsEarnedInLevel }));
    setBonusEarned(0); setSessionScore(0); setStarsEarnedInLevel(0); setTargetWords([]); setFullWordPool([]);
    changeGameState(GameState.WORD_PUZZLE);
  };

  const handleLevelExitToMenu = () => {
    setStats(prev => ({ ...prev, level: prev.level + 1, coins: prev.coins + 150 + bonusEarned, stars: prev.stars + starsEarnedInLevel }));
    setBonusEarned(0); setSessionScore(0); setStarsEarnedInLevel(0); setTargetWords([]); setFullWordPool([]);
    changeGameState(GameState.HUB);
  };

  const handleBuyHearts = (cost: number, amount: number) => {
    if (stats.coins >= cost) {
      setStats(prev => ({ ...prev, coins: prev.coins - cost, hearts: Math.min(5, prev.hearts + amount) }));
    }
  };

  const handleAddCoins = (amount: number) => {
    setStats(prev => ({ ...prev, coins: prev.coins + amount }));
  };

  const renderScreen = () => {
    switch (gameState) {
      case GameState.LOADING: return <LoadingScreen onFinished={handleLoadingFinished} />;
      case GameState.TERMS: return <div className="h-full w-full"><LoadingScreen />{showTerms && <TermsModal onAccept={handleTermsAccept} />}</div>;
      case GameState.HUB: return <><HubScreen stats={stats} user={user} hubSubView={hubSubView} setHubSubView={setHubSubView} onStartGame={() => stats.hearts > 0 ? changeGameState(GameState.WORD_PUZZLE) : setHubSubView(HubSubView.SHOP)} onAddCoins={handleAddCoins} onBuyHearts={handleBuyHearts} onOpenChest={() => setShowChest(true)} />{showChest && <ChestModal onClose={() => setShowChest(false)} onReward={(amt) => handleAddCoins(amt)} />}</>;
      case GameState.WORD_PUZZLE: return <WordPuzzle stats={stats} onComplete={handlePuzzleComplete} onExit={handleManualQuit} />;
      case GameState.MEMORY_PREPARE: return <div className="h-full w-full"><WordPuzzle stats={stats} onComplete={() => {}} onExit={() => {}} /><MemoryTransitionModal onConfirm={() => changeGameState(GameState.MEMORY_GAME)} onExit={handleManualQuit} /></div>;
      case GameState.MEMORY_GAME: return <MemoryGame stats={stats} words={fullWordPool} targetWords={targetWords} onNext={handleGameComplete} onFail={handleGameFail} onExit={handleManualQuit} initialScore={sessionScore} />;
      case GameState.LEVEL_COMPLETE: return <LevelCompleteModal level={stats.level} coinsEarned={150 + bonusEarned} starsEarned={starsEarnedInLevel} onContinue={handleLevelContinue} onMenu={handleLevelExitToMenu} />;
      case GameState.LEVEL_FAIL: return <LevelFailModal hearts={stats.hearts} lastLifeRefillTime={stats.lastLifeRefillTime} onRetry={() => stats.hearts > 0 ? changeGameState(GameState.WORD_PUZZLE) : setHubSubView(HubSubView.SHOP)} onShop={() => setHubSubView(HubSubView.SHOP)} onExit={() => changeGameState(GameState.HUB)} />;
      default: return <LoadingScreen />;
    }
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-[#020617] overflow-hidden select-none">
      <div className={`w-full h-full transition-all duration-500 ease-out ${transitionState === 'animating' ? 'opacity-0 scale-95 blur-md' : 'opacity-100 scale-100 blur-0'}`}>
        {renderScreen()}
      </div>
      <div className={`fixed inset-0 z-[1000] bg-white pointer-events-none transition-opacity duration-300 ${flashEffect ? 'opacity-20' : 'opacity-0'}`} />
    </div>
  );
};

export default App;

