import React, { useState, useMemo, useEffect, useRef } from 'react';
import { UserStats } from '../types';
import { Cube3D, CubeVisualStyle } from '../components/Cube3D';
import { SideMenu } from '../components/SideMenu';
import { ParticleBackground } from '../components/ParticleBackground';
import { Button } from '../components/Button';
import { SoundManager } from '../managers/SoundManager';
import { QuitConfirmationModal } from '../components/QuitConfirmationModal';
import { getAIHint } from '../lib/gemini';

// Kelime Havuzu... (Kısaltıldı)
const ALL_ROUNDS_POOL = [ { target: "EVRENSEL", distractor: "EYLEMSEL" }, { target: "PULSAR", distractor: "PARSEL" } ]; 
const COLORS = ["#22d3ee", "#fbbf24", "#f472b6", "#818cf8", "#4ade80"];
const MEMORIZE_DURATION = 30; 
const BASE_ROUND_TIME = 10;

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void }> = ({ stats, onComplete, onExit }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);
  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [rotationOffset, setRotationOffset] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [revealedIndex, setRevealedIndex] = useState(-1);
  const [roundResults, setRoundResults] = useState<( 'success' | 'fail' | null)[]>(new Array(5).fill(null));
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showQuitModal, setShowQuitModal] = useState(false);
  const [aiHint, setAiHint] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const timerRef = useRef<number | null>(null);

  const activeRoundData = ALL_ROUNDS_POOL[currentRound % ALL_ROUNDS_POOL.length];
  const activeOptions = useMemo(() => [activeRoundData.target, activeRoundData.distractor].sort(() => Math.random() - 0.5), [activeRoundData]);

  const handleAIHint = async () => {
    if (isAiLoading || aiHint) return;
    setIsAiLoading(true);
    const hint = await getAIHint(activeRoundData.target, activeRoundData.distractor);
    setAiHint(hint);
    setIsAiLoading(false);
  };

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || isMenuOpen || isTransitioning || showQuitModal) return;
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        const nextTime = prev - 0.05;
        if (gamePhase === 'MEMORIZE' && nextTime <= 0) { setGamePhase('GUESS'); return dynamicRoundTime; }
        if (gamePhase === 'GUESS' && nextTime <= 0) { handleChoice("TIME_UP"); return dynamicRoundTime; }
        return nextTime;
      });
      if (gamePhase === 'MEMORIZE') setRotationOffset(prev => prev + 0.6);
    }, 50);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [choiceStatus, selectedChoice, isMenuOpen, isTransitioning, gamePhase, dynamicRoundTime]);

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle' || isTransitioning) return;
    setSelectedChoice(choice);
    setTimeout(() => {
      const isCorrect = choice === activeRoundData.target;
      setChoiceStatus(isCorrect ? 'success' : 'fail');
      setAiHint(null);
      setTimeout(() => {
        if (currentRound === 4) onComplete(sessionScore, [], []);
        else { setCurrentRound(r => r + 1); setGamePhase('MEMORIZE'); setTimeLeft(MEMORIZE_DURATION); setChoiceStatus('idle'); setSelectedChoice(null); }
      }, 2000);
    }, 600);
  };

  return (
    <div className="absolute inset-0 bg-[#020617] flex flex-col overflow-hidden">
      <ParticleBackground />
      <div className="pt-10 px-8 flex justify-between z-20">
        <div className="flex flex-col gap-1">
          <span className="text-[10px] text-cyan-400 font-black tracking-widest uppercase">GEÇİT {currentRound + 1}/5</span>
        </div>
        <button 
          onClick={handleAIHint}
          disabled={gamePhase !== 'GUESS' || isAiLoading}
          className={`h-12 px-6 rounded-2xl border-b-4 border-amber-600 bg-amber-400 text-amber-950 font-black text-xs transition-all active:border-b-0 active:translate-y-1 ${isAiLoading ? 'animate-pulse opacity-50' : ''}`}
        >
          {isAiLoading ? 'REHBER GELİYOR...' : 'AI İPUCU (50 🪙)'}
        </button>
      </div>

      <div className="flex-1 relative flex items-center justify-center">
         {aiHint && (
           <div className="absolute top-24 left-8 right-8 p-6 bg-indigo-900/80 border-2 border-cyan-400/30 rounded-3xl backdrop-blur-xl animate-bounce">
             <p className="text-white text-sm font-bold italic text-center">"{aiHint}"</p>
           </div>
         )}
         <div className="text-white text-6xl font-black">{timeLeft.toFixed(0)}s</div>
      </div>

      <div className="px-8 pb-10 flex flex-col gap-4">
        {gamePhase === 'GUESS' && activeOptions.map(opt => (
          <Button key={opt} variant="cyan" onClick={() => handleChoice(opt)}>{opt}</Button>
        ))}
      </div>
    </div>
  );
};

