  hubSubView: HubSubView;
  setHubSubView: (view: HubSubView) => void;
  onStartGame: () => void;
  onAddCoins: (amount: number) => void;
  onBuyHearts: (cost: number, amount: number) => void;
  onOpenChest: () => void;
}

