      <div 
        className="absolute inset-[-15px] blur-3xl opacity-50 rounded-full animate-pulse pointer-events-none" 
        style={{ backgroundColor: color }} 
      />
    )}
    <div className={`relative z-10 text-4xl transition-all duration-500 ${active ? 'drop-shadow-[0_0_12px_rgba(255,255,255,0.6)]' : ''}`}>
      {icon}
    </div>
  </div>
);

export const HubScreen: React.FC<HubScreenProps> = ({ 
  stats, 
  user, // Fix: Destructure user prop
  hubSubView, 
  setHubSubView, 
  onStartGame, 
  onAddCoins, 
  onBuyHearts,
  onOpenChest 
}) => {
