import React, { useState, useEffect } from 'react';
import { GameState, UserStats, HubSubView } from './types';
import { LoadingScreen } from './screens/LoadingScreen';
import { HubScreen } from './screens/HubScreen';
import { MemoryGame } from './screens/MemoryGame';
import { WordPuzzle } from './screens/WordPuzzle';
import { TermsModal } from './components/TermsModal';
import { LevelCompleteModal } from './components/LevelCompleteModal';
import { LevelFailModal } from './components/LevelFailModal';
import { ChestModal } from './components/ChestModal';
import { MemoryTransitionModal } from './components/MemoryTransitionModal';
import { SoundManager } from './managers/SoundManager';
import { auth, syncUserStats, getUserStats } from './lib/firebase';
import { onAuthStateChanged, User } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

const REFILL_TIME = 10 * 60 * 1000;
const STORAGE_KEY = 'lumina_stats';
// Fix: Define a default background URL for game screens
const DEFAULT_BG = "https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&q=80&w=1080&h=1920";

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [gameState, setGameState] = useState<GameState>(GameState.LOADING);
  const [hubSubView, setHubSubView] = useState<HubSubView>(HubSubView.MAIN);

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { console.error(e); }
    }
    return {
      coins: 2063, hearts: 5, stars: 12, level: 1,
      lastLifeRefillTime: Date.now(),
      difficultyFactor: 1.0, performanceHistory: [],
      streak: 0, maxStreak: 0
    };
  });

  // Firebase Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      setUser(firebaseUser);
      if (firebaseUser) {
        const cloudStats = await getUserStats(firebaseUser.uid);
        if (cloudStats) {
          setStats(prev => ({ ...prev, ...cloudStats }));
        }
      }
    });
    return () => unsubscribe();
  }, []);

  // Sync to Cloud & Local on changes
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stats));
    if (user) {
      syncUserStats(user.uid, stats);
    }
  }, [stats, user]);

  const [targetWords, setTargetWords] = useState<string[]>([]);
  const [fullWordPool, setFullWordPool] = useState<string[]>([]);
  const [showTerms, setShowTerms] = useState(false);
  const [showChest, setShowChest] = useState(false);
  const [bonusEarned, setBonusEarned] = useState(0);
  const [sessionScore, setSessionScore] = useState(0);
  const [starsEarnedInLevel, setStarsEarnedInLevel] = useState(0);
  const [transitionState, setTransitionState] = useState<'idle' | 'animating'>('idle');
  const [flashEffect, setFlashEffect] = useState(false);

  useEffect(() => {
    SoundManager.getInstance().setLevel(stats.level);
    SoundManager.getInstance().setDifficulty(stats.difficultyFactor);
  }, [stats.level, stats.difficultyFactor]);

  useEffect(() => {
    if (stats.hearts >= 5) return;
    const interval = setInterval(() => {
      const now = Date.now();
      const diff = now - stats.lastLifeRefillTime;
      if (diff >= REFILL_TIME) {
        const heartsToAdd = Math.floor(diff / REFILL_TIME);
        setStats(prev => ({
          ...prev,
          hearts: Math.min(5, prev.hearts + heartsToAdd),
          lastLifeRefillTime: prev.hearts + heartsToAdd >= 5 ? now : prev.lastLifeRefillTime + (heartsToAdd * REFILL_TIME)
        }));
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [stats.hearts, stats.lastLifeRefillTime]);

  const updateDifficulty = (isSuccess: boolean, perfection: number = 0) => {
    setStats(prev => {
      let newFactor = prev.difficultyFactor;
      const history = [...prev.performanceHistory, isSuccess].slice(-5);
      let newStreak = isSuccess ? prev.streak + 1 : 0;
      let newMaxStreak = Math.max(prev.maxStreak, newStreak);
      if (isSuccess) {
        const boost = perfection === 5 ? 0.15 : 0.05;
        newFactor = Math.min(2.0, newFactor + boost);
      } else {
        newFactor = Math.max(0.5, newFactor - 0.1);
      }
      return { ...prev, difficultyFactor: newFactor, performanceHistory: history, streak: newStreak, maxStreak: newMaxStreak };
    });
  };

  const changeGameState = (newState: GameState) => {
    setTransitionState('animating');
    setTimeout(() => {
      setGameState(newState);
      setFlashEffect(true);
      setTimeout(() => setFlashEffect(false), 300);
      setTimeout(() => setTransitionState('idle'), 50);
    }, 300);
  };

  const handleLoadingFinished = () => {
    const hasAccepted = localStorage.getItem('terms_accepted');
    if (hasAccepted) { changeGameState(GameState.HUB); } 
    else { setGameState(GameState.TERMS); setShowTerms(true); }
  };

  const handleTermsAccept = () => {
    localStorage.setItem('terms_accepted', 'true');
    setShowTerms(false);
    changeGameState(GameState.HUB);
  };

  const handlePuzzleComplete = (earned: number, allTargets: string[], allDistractors: string[]) => {
    setStats(prev => ({ ...prev, coins: prev.coins + earned }));
    setSessionScore(earned);
    setTargetWords(allTargets);
    const pooledWords = [...allTargets, ...allDistractors].sort(() => Math.random() - 0.5);
    setFullWordPool(pooledWords);
    changeGameState(GameState.MEMORY_PREPARE);
  };

  const handleManualQuit = () => {
    setStats(prev => ({ ...prev, hearts: Math.max(0, prev.hearts - 1), streak: 0 }));
    updateDifficulty(false);
    changeGameState(GameState.HUB);
  };

  const handleGameFail = () => {
    setStats(prev => {
      setTimeout(() => changeGameState(GameState.LEVEL_FAIL), 500);
      return { ...prev, hearts: Math.max(0, prev.hearts - 1), streak: 0 };
    });
    updateDifficulty(false);
  };

  const handleGameComplete = (correctCount: number) => {
    let bonus = 0; let stars = 0;
    if (correctCount === 3) { stars = 1; } 
    else if (correctCount === 4) { bonus = 100; stars = 2; } 
    else if (correctCount === 5) { bonus = 250; stars = 3; }
    setStarsEarnedInLevel(stars);
    setBonusEarned(bonus);
    updateDifficulty(true, correctCount);
    changeGameState(GameState.LEVEL_COMPLETE);
  };

  const handleLevelContinue = () => {
    setStats(prev => ({ ...prev, level: prev.level + 1, coins: prev.coins + 150 + bonusEarned, stars: prev.stars + starsEarnedInLevel }));
    setBonusEarned(0); setSessionScore(0); setStarsEarnedInLevel(0); setTargetWords([]); setFullWordPool([]);
    changeGameState(GameState.WORD_PUZZLE);
  };

  const handleLevelExitToMenu = () => {
    setStats(prev => ({ ...prev, level: prev.level + 1, coins: prev.coins + 150 + bonusEarned, stars: prev.stars + starsEarnedInLevel }));
    setBonusEarned(0); setSessionScore(0); setStarsEarnedInLevel(0); setTargetWords([]); setFullWordPool([]);
    changeGameState(GameState.HUB);
  };

  const handleBuyHearts = (cost: number, amount: number) => {
    if (stats.coins >= cost) {
      setStats(prev => ({ ...prev, coins: prev.coins - cost, hearts: Math.min(5, prev.hearts + amount) }));
    }
  };

  const handleAddCoins = (amount: number) => {
    setStats(prev => ({ ...prev, coins: prev.coins + amount }));
  };

  const renderScreen = () => {
    switch (gameState) {
      case GameState.LOADING: return <LoadingScreen onFinished={handleLoadingFinished} />;
      case GameState.TERMS: return <div className="h-full w-full"><LoadingScreen />{showTerms && <TermsModal onAccept={handleTermsAccept} />}</div>;
      case GameState.HUB: return <><HubScreen stats={stats} user={user} hubSubView={hubSubView} setHubSubView={setHubSubView} onStartGame={() => stats.hearts > 0 ? changeGameState(GameState.WORD_PUZZLE) : setHubSubView(HubSubView.SHOP)} onAddCoins={handleAddCoins} onBuyHearts={handleBuyHearts} onOpenChest={() => setShowChest(true)} />{showChest && <ChestModal onClose={() => setShowChest(false)} onReward={(amt) => handleAddCoins(amt)} />}</>;
      case GameState.WORD_PUZZLE: return <WordPuzzle stats={stats} onComplete={handlePuzzleComplete} onExit={handleManualQuit} />;
      case GameState.MEMORY_PREPARE: return <div className="h-full w-full"><WordPuzzle stats={stats} onComplete={() => {}} onExit={() => {}} /><MemoryTransitionModal onConfirm={() => changeGameState(GameState.MEMORY_GAME)} onExit={handleManualQuit} /></div>;
      // Fix: Pass required backgroundUrl prop to MemoryGame
      case GameState.MEMORY_GAME: return <MemoryGame stats={stats} backgroundUrl={DEFAULT_BG} words={fullWordPool} targetWords={targetWords} onNext={handleGameComplete} onFail={handleGameFail} onExit={handleManualQuit} initialScore={sessionScore} />;
      case GameState.LEVEL_COMPLETE: return <LevelCompleteModal level={stats.level} coinsEarned={150 + bonusEarned} starsEarned={starsEarnedInLevel} onContinue={handleLevelContinue} onMenu={handleLevelExitToMenu} />;
      case GameState.LEVEL_FAIL: return <LevelFailModal hearts={stats.hearts} lastLifeRefillTime={stats.lastLifeRefillTime} onRetry={() => stats.hearts > 0 ? changeGameState(GameState.WORD_PUZZLE) : setHubSubView(HubSubView.SHOP)} onShop={() => setHubSubView(HubSubView.SHOP)} onExit={() => changeGameState(GameState.HUB)} />;
      default: return <LoadingScreen />;
    }
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-[#020617] overflow-hidden select-none">
      <div className={`w-full h-full transition-all duration-500 ease-out ${transitionState === 'animating' ? 'opacity-0 scale-95 blur-md' : 'opacity-100 scale-100 blur-0'}`}>
        {renderScreen()}
      </div>
      <div className={`fixed inset-0 z-[1000] bg-white pointer-events-none transition-opacity duration-300 ${flashEffect ? 'opacity-20' : 'opacity-0'}`} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { UserStats } from '../types';
import { Cube3D } from '../components/Cube3D';
import { ParticleBackground } from '../components/ParticleBackground';
import { Button } from '../components/Button';
import { SoundManager } from '../managers/SoundManager';
import { QuitConfirmationModal } from '../components/QuitConfirmationModal';

// Kelime Havuzu
const ALL_ROUNDS_POOL = [
  { target: "EVRENSEL", distractor: "EYLEMSEL" },
  { target: "PULSAR", distractor: "PARSEL" },
  { target: "NEBULA", distractor: "NODÜL" },
  { target: "KUANTUM", distractor: "KURAM" },
  { target: "GEÇİT", distractor: "KESİT" }
]; 

const MEMORIZE_DURATION = 3; // Ezberleme süresi (saniye)
const BASE_ROUND_TIME = 10; // Tahmin süresi (saniye)

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void }> = ({ stats, onComplete, onExit }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);
  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [rotationOffset, setRotationOffset] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showQuitModal, setShowQuitModal] = useState(false);

  const timerRef = useRef<number | null>(null);

  const activeRoundData = ALL_ROUNDS_POOL[currentRound % ALL_ROUNDS_POOL.length];
  const activeOptions = useMemo(() => [activeRoundData.target, activeRoundData.distractor].sort(() => Math.random() - 0.5), [activeRoundData]);

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || isMenuOpen || isTransitioning || showQuitModal) return;

    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        const nextTime = prev - 0.05;
        if (gamePhase === 'MEMORIZE' && nextTime <= 0) {
          SoundManager.getInstance().playPop();
          setGamePhase('GUESS');
          return dynamicRoundTime;
        }
        if (gamePhase === 'GUESS' && nextTime <= 0) {
          handleChoice("TIME_UP");
          return dynamicRoundTime;
        }
        return nextTime;
      });

      if (gamePhase === 'MEMORIZE') {
        setRotationOffset(prev => prev + 0.6);
      }
    }, 50);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [choiceStatus, selectedChoice, isMenuOpen, isTransitioning, gamePhase, dynamicRoundTime, showQuitModal]);

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle' || isTransitioning) return;

    setSelectedChoice(choice);
    const isCorrect = choice === activeRoundData.target;

    setTimeout(() => {
      setChoiceStatus(isCorrect ? 'success' : 'fail');
      if (isCorrect) {
        SoundManager.getInstance().playSuccess();
        setSessionScore(prev => prev + 50);
      } else {
        SoundManager.getInstance().playFail();
      }

      setTimeout(() => {
        if (currentRound === 4) {
          onComplete(sessionScore + (isCorrect ? 50 : 0), [], []);
        } else {
          setIsTransitioning(true);
          setTimeout(() => {
            setCurrentRound(r => r + 1);
            setGamePhase('MEMORIZE');
            setTimeLeft(MEMORIZE_DURATION);
            setChoiceStatus('idle');
            setSelectedChoice(null);
            setIsTransitioning(false);
          }, 400);
        }
      }, 1500);
    }, 300);
  };

  return (
    <div className="absolute inset-0 bg-[#020617] flex flex-col overflow-hidden">
      <ParticleBackground />

      {/* Üst Bilgi Barı */}
      <div className="pt-10 px-8 flex justify-between items-center z-20">
        <div className="flex flex-col gap-1">
          <span className="text-[10px] text-cyan-400 font-black tracking-widest uppercase opacity-60">GEÇİT VERİSİ</span>
          <h2 className="text-white text-2xl font-black tracking-tighter uppercase">TUR {currentRound + 1}/5</h2>
        </div>
        <div className="bg-black/40 backdrop-blur-xl border-2 border-white/10 px-4 py-2 rounded-2xl flex items-center gap-2">
           <span className="text-amber-400">🪙</span>
           <span className="text-white font-black tabular-nums">{sessionScore}</span>
        </div>
      </div>

      {/* Orta Oyun Alanı */}
      <div className="flex-1 relative flex flex-col items-center justify-center p-8">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 bg-cyan-500/10 blur-[100px] rounded-full animate-pulse" />

        <div className="relative mb-12">
          <div className={`transition-all duration-700 ${choiceStatus === 'success' ? 'scale-110' : choiceStatus === 'fail' ? 'animate-shake' : ''}`}>
            <Cube3D 
              size={160}
              color={choiceStatus === 'success' ? "#4ade80" : choiceStatus === 'fail' ? "#f87171" : "#22d3ee"}
              speed={gamePhase === 'MEMORIZE' ? 2 : 0}
              label={gamePhase === 'MEMORIZE' ? activeRoundData.target : "?"}
              isGlassy={true}
              visualStyle={gamePhase === 'MEMORIZE' ? 'NEON' : 'GLASS'}
              status={choiceStatus}
            />
          </div>

          {/* Geri Sayım Halkası */}
          <div className="absolute -inset-8 pointer-events-none">
            <svg className="w-full h-full rotate-[-90deg]">
              <circle 
                cx="50%" cy="50%" r="45%" 
                fill="none" stroke="white" strokeWidth="2" strokeOpacity="0.1" 
              />
              <circle 
                cx="50%" cy="50%" r="45%" 
                fill="none" stroke={gamePhase === 'MEMORIZE' ? "#22d3ee" : "#fbbf24"} 
                strokeWidth="4" 
                strokeDasharray="100 100"
                style={{ 
                  strokeDashoffset: 100 - (timeLeft / (gamePhase === 'MEMORIZE' ? MEMORIZE_DURATION : dynamicRoundTime) * 100),
                  transition: 'stroke-dashoffset 0.1s linear'
                }}
              />
            </svg>
          </div>
        </div>

        <div className="text-center z-10">
          <p className="text-white/40 text-[10px] font-black tracking-[0.4em] uppercase mb-2">
            {gamePhase === 'MEMORIZE' ? 'KELİMEYİ AKLINDA TUT' : 'HANGİSİ DOĞRUYDU?'}
          </p>
          <div className="text-white text-6xl font-black tracking-tighter tabular-nums drop-shadow-2xl">
            {Math.ceil(timeLeft)}
          </div>
        </div>
      </div>

      {/* Seçenekler / Alt Alan */}
      <div className={`px-8 pb-12 flex flex-col gap-4 z-20 transition-all duration-500 ${gamePhase === 'MEMORIZE' ? 'opacity-0 translate-y-10 pointer-events-none' : 'opacity-100 translate-y-0'}`}>
        {activeOptions.map((opt, i) => (
          <Button 
            key={opt} 
            variant={selectedChoice === opt ? (choiceStatus === 'fail' ? 'coral' : 'white') : 'cyan'} 
            onClick={() => handleChoice(opt)}
            disabled={selectedChoice !== null}
            className={`w-full !py-6 !text-2xl transition-all ${selectedChoice && selectedChoice !== opt ? 'opacity-20 scale-95' : ''}`}
          >
            {opt}
          </Button>
        ))}
      </div>

      {/* Çıkış Butonu */}
      <button 
        onClick={() => setShowQuitModal(true)}
        className="absolute bottom-6 left-1/2 -translate-x-1/2 text-white/20 hover:text-white/60 font-black text-[10px] tracking-[0.3em] uppercase transition-all"
      >
        OYUNDAN AYRIL
      </button>

      {showQuitModal && (
        <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />
      )}

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-10px); }
          75% { transform: translateX(10px); }
        }
        .animate-shake { animation: shake 0.2s ease-in-out 3; }
      `}</style>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { UserStats } from '../types';
import { Cube3D } from '../components/Cube3D';
import { ParticleBackground } from '../components/ParticleBackground';
import { Button } from '../components/Button';
import { SoundManager } from '../managers/SoundManager';
import { QuitConfirmationModal } from '../components/QuitConfirmationModal';

const ALL_ROUNDS_POOL = [
  { target: "EVRENSEL", distractor: "EYLEMSEL" },
  { target: "PULSAR", distractor: "PARSEL" },
  { target: "NEBULA", distractor: "NODÜL" },
  { target: "KUANTUM", distractor: "KURAM" },
  { target: "GEÇİT", distractor: "KESİT" },
  { target: "KOZMOZ", distractor: "KOMBİN" },
  { target: "FOTON", distractor: "FORMEL" }
]; 

const MEMORIZE_DURATION = 3; 
const BASE_ROUND_TIME = 8;

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void }> = ({ stats, onComplete, onExit }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);
  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [showQuitModal, setShowQuitModal] = useState(false);
  const [collectedTargets, setCollectedTargets] = useState<string[]>([]);
  const [collectedDistractors, setCollectedDistractors] = useState<string[]>([]);

  const timerRef = useRef<number | null>(null);

  const activeRoundData = useMemo(() => {
    const pool = [...ALL_ROUNDS_POOL].sort(() => Math.random() - 0.5);
    return pool[currentRound % pool.length];
  }, [currentRound]);

  const activeOptions = useMemo(() => [activeRoundData.target, activeRoundData.distractor].sort(() => Math.random() - 0.5), [activeRoundData]);

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || showQuitModal) return;

    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        const nextTime = prev - 0.05;
        if (gamePhase === 'MEMORIZE' && nextTime <= 0) {
          SoundManager.getInstance().playPop();
          setGamePhase('GUESS');
          return dynamicRoundTime;
        }
        if (gamePhase === 'GUESS' && nextTime <= 0) {
          handleChoice("TIME_UP");
          return dynamicRoundTime;
        }
        return nextTime;
      });
    }, 50);

    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [choiceStatus, selectedChoice, gamePhase, dynamicRoundTime, showQuitModal]);

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle') return;

    setSelectedChoice(choice);
    const isCorrect = choice === activeRoundData.target;

    setChoiceStatus(isCorrect ? 'success' : 'fail');
    if (isCorrect) {
      SoundManager.getInstance().playSuccess();
      setSessionScore(prev => prev + 50);
      setCollectedTargets(prev => [...prev, activeRoundData.target]);
      setCollectedDistractors(prev => [...prev, activeRoundData.distractor]);
    } else {
      SoundManager.getInstance().playFail();
      setCollectedDistractors(prev => [...prev, choice === "TIME_UP" ? activeRoundData.distractor : choice]);
    }

    setTimeout(() => {
      if (currentRound === 4) {
        // Hafıza oyununa geçiş için verileri gönder
        onComplete(sessionScore + (isCorrect ? 50 : 0), collectedTargets, collectedDistractors);
      } else {
        setCurrentRound(r => r + 1);
        setGamePhase('MEMORIZE');
        setTimeLeft(MEMORIZE_DURATION);
        setChoiceStatus('idle');
        setSelectedChoice(null);
      }
    }, 1500);
  };

  return (
    <div className="absolute inset-0 bg-[#020617] flex flex-col overflow-hidden">
      <ParticleBackground level={stats.level} />

      <div className="pt-12 px-8 flex justify-between items-center z-20">
        <div className="flex flex-col">
          <span className="text-[10px] text-cyan-400 font-black tracking-[0.3em] uppercase opacity-60">SENKRONİZASYON</span>
          <h2 className="text-white text-3xl font-black tracking-tighter uppercase">TUR {currentRound + 1}/5</h2>
        </div>
        <div className="h-14 px-6 bg-black/40 backdrop-blur-2xl border-2 border-white/10 rounded-2xl flex items-center gap-3">
           <span className="text-2xl">🪙</span>
           <span className="text-white font-black text-xl tabular-nums">{sessionScore}</span>
        </div>
      </div>

      <div className="flex-1 relative flex flex-col items-center justify-center">
        {/* Küp Alanı */}
        <div className="relative mb-8">
          <div className={`transition-all duration-500 ${choiceStatus === 'success' ? 'scale-125' : choiceStatus === 'fail' ? 'animate-shake' : ''}`}>
            <Cube3D 
              size={180}
              color={choiceStatus === 'success' ? "#4ade80" : choiceStatus === 'fail' ? "#f87171" : "#22d3ee"}
              speed={gamePhase === 'MEMORIZE' ? 3 : 0}
              label={gamePhase === 'MEMORIZE' ? activeRoundData.target : "?"}
              isGlassy={true}
              visualStyle={gamePhase === 'MEMORIZE' ? 'NEON' : 'GLASS'}
              status={choiceStatus}
              rotationAxis="XY"
            />
          </div>

          {/* Progress Ring */}
          <div className="absolute -inset-10 pointer-events-none opacity-20">
            <svg className="w-full h-full rotate-[-90deg] scale-150">
              <circle cx="50%" cy="50%" r="40%" fill="none" stroke="white" strokeWidth="1" />
              <circle 
                cx="50%" cy="50%" r="40%" 
                fill="none" stroke={gamePhase === 'MEMORIZE' ? "#22d3ee" : "#fbbf24"} 
                strokeWidth="2" 
                strokeDasharray="100 100"
                style={{ 
                  strokeDashoffset: 100 - (timeLeft / (gamePhase === 'MEMORIZE' ? MEMORIZE_DURATION : dynamicRoundTime) * 100),
                  transition: 'stroke-dashoffset 0.1s linear'
                }}
              />
            </svg>
          </div>
        </div>

        <div className="text-center z-10">
          <p className="text-white/40 text-[11px] font-black tracking-[0.5em] uppercase mb-3">
            {gamePhase === 'MEMORIZE' ? 'VERİYİ BELLEĞE AL' : 'GEÇİT ANAHTARINI SEÇ'}
          </p>
          <div className="text-white text-7xl font-black tracking-tighter tabular-nums drop-shadow-[0_10px_30px_rgba(34,211,238,0.3)]">
            {Math.ceil(timeLeft)}
          </div>
        </div>
      </div>

      <div className={`px-10 pb-16 flex flex-col gap-5 z-20 transition-all duration-700 ${gamePhase === 'MEMORIZE' ? 'opacity-0 translate-y-10 pointer-events-none' : 'opacity-100 translate-y-0'}`}>
        {activeOptions.map((opt) => (
          <Button 
            key={opt} 
            variant={selectedChoice === opt ? (choiceStatus === 'fail' ? 'coral' : 'green') : 'cyan'} 
            onClick={() => handleChoice(opt)}
            disabled={selectedChoice !== null}
            className={`w-full !py-8 !text-3xl !rounded-[40px] !border-b-[12px] shadow-2xl active:!border-b-0 active:!translate-y-2 transition-all ${selectedChoice && selectedChoice !== opt ? 'opacity-10 scale-95 blur-sm' : ''}`}
          >
            {opt}
          </Button>
        ))}
      </div>

      <button onClick={() => setShowQuitModal(true)} className="absolute bottom-6 left-0 right-0 text-center text-white/20 font-black text-[10px] tracking-[0.4em] uppercase hover:text-white/50 transition-all">OYUNDAN AYRIL</button>
      {showQuitModal && <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />}
      <style>{`@keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-10px); } 75% { transform: translateX(10px); } } .animate-shake { animation: shake 0.2s ease-in-out 3; }`}</style>
    </div>
  );
};

import React, { memo } from 'react';

export type RotationAxis = 'X' | 'Y' | 'XY' | 'TUMBLE';
export type CubeVisualStyle = 'GLASS' | 'CRYSTAL' | 'METAL' | 'NEON' | 'GHOST' | 'DARK' | 'PLASMA' | 'CHROME' | 'LAVA' | 'AETHER' | 'VOID';

interface Cube3DProps {
  size?: number;
  width?: number; 
  height?: number; 
  depth?: number; 
  className?: string;
  speed?: number;
  opacity?: number;
  label?: string;
  centerLabel?: string; 
  faceLabels?: string[]; 
  isGlassy?: boolean;
  color?: string;
  rotationAxis?: RotationAxis;
  visualStyle?: CubeVisualStyle;
  status?: 'idle' | 'success' | 'fail';
  delay?: number;
  isRevealed?: boolean;
  isSelected?: boolean;
}

export const Cube3D: React.FC<Cube3DProps> = memo(({ 
  size = 32,
  width,
  height,
  depth,
  className = "", 
  speed = 4,
  opacity = 1,
  label = "",
  centerLabel = "",
  faceLabels,
  isGlassy = true,
  color = "rgba(34, 211, 238, 1)",
  rotationAxis = 'XY',
  visualStyle = 'GLASS',
  status = 'idle',
  delay = 0,
  isRevealed = true,
  isSelected = false
}) => {
  const isSuccess = status === 'success';
  const isFail = status === 'fail';
  const mainText = (centerLabel || label);

  const w = width || size;
  const h = height || size;
  const d = depth || size;

  const getRotationClass = () => {
    if (isSelected || isSuccess || speed === 0) return "";
    switch (rotationAxis) {
      case 'X': return "animate-cube-x";
      case 'Y': return "animate-cube-y";
      case 'XY': return "animate-cube-xy";
      case 'TUMBLE': return "animate-cube-tumble";
      default: return "animate-cube-xy";
    }
  };

  const renderCube = () => {
    let baseColor = color;
    if (isSuccess) baseColor = '#4ade80'; 
    if (isFail) baseColor = '#f87171';

    const faces = [
      { id: 'front', rot: 'rotateY(0deg)', tz: (d / 2) },
      { id: 'back', rot: 'rotateY(180deg)', tz: (d / 2) },
      { id: 'right', rot: 'rotateY(90deg)', tz: (w / 2) },
      { id: 'left', rot: 'rotateY(-90deg)', tz: (w / 2) },
      { id: 'top', rot: 'rotateX(90deg)', tz: (h / 2) },
      { id: 'bottom', rot: 'rotateX(-90deg)', tz: (h / 2) },
    ];

    return (
      <div className="w-full h-full relative" style={{ transformStyle: 'preserve-3d' }}>
        {faces.map((f, i) => {
          const faceText = (faceLabels && faceLabels[i]) ? faceLabels[i] : mainText;

          let faceStyles: React.CSSProperties = {
            position: 'absolute',
            width: (f.id === 'right' || f.id === 'left') ? d : w,
            height: (f.id === 'top' || f.id === 'bottom') ? d : h,
            left: '50%',
            top: '50%',
            transform: `translate(-50%, -50%) ${f.rot} translateZ(${f.tz}px)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backfaceVisibility: 'visible',
            borderRadius: '24px',
            transformStyle: 'preserve-3d',
            border: `4px solid ${baseColor}`,
            background: isGlassy ? `linear-gradient(135deg, ${baseColor}44 0%, ${baseColor}22 100%)` : baseColor,
            backdropFilter: isGlassy ? 'blur(12px)' : 'none',
            boxShadow: `inset 0 0 30px ${baseColor}44, 0 0 20px ${baseColor}22`,
          };

          if (visualStyle === 'NEON') {
             faceStyles.boxShadow = `0 0 30px ${baseColor}, inset 0 0 20px ${baseColor}`;
             faceStyles.background = 'rgba(2, 6, 23, 0.8)';
          }

          return (
            <div key={i} style={faceStyles}>
              {faceText && (
                <span 
                  className="font-[900] uppercase text-white pointer-events-none drop-shadow-[0_5px_15px_rgba(0,0,0,0.8)]"
                  style={{ fontSize: (size * 0.4) / (faceText.length > 5 ? 2 : 1) }}
                >
                  {faceText}
                </span>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div 
      className={`relative ${className} animate-cube-drift`} 
      style={{ width: w, height: h, perspective: '1200px', transformStyle: 'preserve-3d', opacity }}
    >
      <div 
        className={`w-full h-full ${getRotationClass()}`}
        style={{ 
          transformStyle: 'preserve-3d', 
          '--cube-speed': `${speed}s`,
          transition: 'transform 0.8s cubic-bezier(0.34, 1.56, 0.64, 1)'
        } as any}
      >
        {renderCube()}
      </div>
    </div>
  );
});

