/**
 * Kullanıcı istatistiklerini Firestore'a senkronize eder.
 * @param uid Kullanıcı benzersiz kimliği
 * @param stats Senkronize edilecek istatistikler
 */
export const syncUserStats = async (uid: string, stats: UserStats): Promise<void> => {
  try {
    const userDocRef = doc(db, "users", uid);
    await setDoc(userDocRef, { ...stats, updatedAt: Date.now() }, { merge: true });
  } catch (error) {
    console.error("Bulut senkronizasyon hatası:", error);
  }
};

/**
 * Kullanıcı istatistiklerini Firestore'dan çeker.
 * @param uid Kullanıcı benzersiz kimliği
 */
export const getUserStats = async (uid: string): Promise<UserStats | null> => {
  try {
    const userDocRef = doc(db, "users", uid);
    const docSnap = await getDoc(userDocRef);
    if (docSnap.exists()) {
      return docSnap.data() as UserStats;
    }
  } catch (error) {
    console.error("Veri çekme hatası:", error);
  }
  return null;
};

