const COLORS = ["#22d3ee", "#fbbf24", "#f472b6", "#818cf8", "#4ade80"];
const MEMORIZE_DURATION = 30; 
const BASE_ROUND_TIME = 10;
const STYLES: RingStyle[] = [
  'STANDART', 'BALERİN', 'DÖNMEDOLAP', 'ATLIKARINCA', 'DEĞİRMEN',
  'DNA', 'NABIZ', 'SARKAÇ', 'GİRDAP', 'DALGA',
  'SONSUZLUK', 'KELEBEK', 'FIRTINA', 'SEKSEK', 'KUŞAK',
  'MERCEK', 'BASAMAK', 'SİKLON', 'PİRAMİT', 'ZİGZAG',
  'KASIRGA', 'KARMAŞA', 'TRAMPOLİN', 'YOYO', 'HALKALI',
  'ÇAPRAZ', 'ASANSÖR', 'BOOMERANG', 'LABİRENT',
  'KALEYDOSKOP', 'KUANTUM', 'SARMAN', 'VALS'
];

const VISUAL_STYLES: CubeVisualStyle[] = ['GLASS', 'CRYSTAL', 'METAL', 'NEON', 'GHOST', 'DARK', 'PLASMA', 'CHROME', 'LAVA', 'AETHER', 'VOID'];

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void }> = ({ stats, onComplete, onExit }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);

  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [rotationOffset, setRotationOffset] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [revealedIndex, setRevealedIndex] = useState(-1);
  const [roundResults, setRoundResults] = useState<( 'success' | 'fail' | null)[]>(new Array(5).fill(null));
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showQuitModal, setShowQuitModal] = useState(false);
  const [comboCount, setComboCount] = useState(0);

  // İpucu Sistemi State
  const [showHintMenu, setShowHintMenu] = useState(false);
  const [isTimeFrozen, setIsTimeFrozen] = useState(false);
  const [slowMoFactor, setSlowMoFactor] = useState(1);
  const [hintUsedThisRound, setHintUsedThisRound] = useState(false);

  const timerRef = useRef<number | null>(null);

  const currentStyle = useMemo(() => {
    const randomIndex = Math.floor(Math.random() * STYLES.length);
    return STYLES[randomIndex];
  }, [currentRound]);

  const currentCubeVisualStyle = useMemo(() => {
    const pool = stats.difficultyFactor > 1.5 
      ? ['LAVA', 'VOID', 'PLASMA', 'NEON', 'CHROME'] 
      : VISUAL_STYLES;
    const randomIndex = Math.floor(Math.random() * pool.length);
    return pool[randomIndex] as CubeVisualStyle;
  }, [currentRound, stats.difficultyFactor]);

  const puzzleRounds = useMemo(() => {
    const minLength = stats.difficultyFactor > 1.6 ? 7 : stats.difficultyFactor > 1.2 ? 5 : 3;
    const filteredPool = ALL_ROUNDS_POOL.filter(item => item.target.length >= minLength);
    return [...filteredPool].sort(() => Math.random() - 0.5).slice(0, 5);
  }, [stats.difficultyFactor]);

  const activeRoundData = puzzleRounds[currentRound];
  const activeOptions = useMemo(() => [activeRoundData.target, activeRoundData.distractor].sort(() => Math.random() - 0.5), [activeRoundData]);

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || isMenuOpen || isTransitioning || showQuitModal) return;

    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (isTimeFrozen && gamePhase === 'MEMORIZE') return prev;

        const nextTime = prev - 0.05;
        if (gamePhase === 'MEMORIZE' && nextTime <= 0) {
          setGamePhase('GUESS');
          SoundManager.getInstance().playPop();
          return dynamicRoundTime;
        }
        if (gamePhase === 'GUESS' && nextTime <= 0) {
          handleChoice("TIME_UP");
          return dynamicRoundTime;
        }
        return nextTime;
      });
      if (gamePhase === 'MEMORIZE') {
        setRotationOffset(prev => prev + (0.6 * stats.difficultyFactor * slowMoFactor));
      }
    }, 50);
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [choiceStatus, selectedChoice, isMenuOpen, isTransitioning, currentRound, showQuitModal, dynamicRoundTime, stats.difficultyFactor, gamePhase, isTimeFrozen, slowMoFactor]);

  useEffect(() => {
    if (choiceStatus === 'success') {
      let currentIdx = 0;
      const interval = setInterval(() => {
        setRevealedIndex(currentIdx);
        currentIdx++;
        if (currentIdx >= activeRoundData.target.length) {
          clearInterval(interval);
        }
      }, 150);
      return () => clearInterval(interval);
    } else {
      setRevealedIndex(-1);
    }
  }, [choiceStatus, activeRoundData.target]);

  const handleSkipMemorize = () => {
    if (gamePhase === 'MEMORIZE' && !isTransitioning) {
      setGamePhase('GUESS');
      setTimeLeft(dynamicRoundTime);
      SoundManager.getInstance().playPop();
    }
  };

  const useHint = (type: 'SLOW' | 'FREEZE' | 'REVEAL') => {
    if (hintUsedThisRound) return;
    SoundManager.getInstance().playCoin();
    setHintUsedThisRound(true);
    setShowHintMenu(false);

    if (type === 'SLOW') {
      setSlowMoFactor(0.2);
      setTimeout(() => setSlowMoFactor(1), 5000);
    } else if (type === 'FREEZE') {
      setIsTimeFrozen(true);
      setTimeout(() => setIsTimeFrozen(false), 5000);
    } else if (type === 'REVEAL') {
      setRotationOffset(0); 
    }
  };

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle' || isTransitioning) return;
    setSelectedChoice(choice);
    setShowHintMenu(false);
    setTimeout(() => {
      const isCorrect = choice === activeRoundData.target;
      if (isCorrect) {
        SoundManager.getInstance().playSuccess();
        setComboCount(prev => prev + 1);
      } else {
        if (choice !== "TIME_UP") SoundManager.getInstance().playFail();
        setComboCount(0);
      }
      const points = Math.floor((100 + timeLeft * 10) * (1 + (comboCount * 0.1)));
      const nextResults = [...roundResults];
      setChoiceStatus(isCorrect ? 'success' : 'fail');
      nextResults[currentRound] = isCorrect ? 'success' : 'fail';
      const nextScore = isCorrect ? sessionScore + points : Math.max(0, sessionScore - 50);
      setSessionScore(nextScore);
      const delay = isCorrect ? (activeRoundData.target.length * 150 + 1000) : 1000;
      setTimeout(() => {
        setIsTransitioning(true);
        setTimeout(() => {
          if (currentRound === puzzleRounds.length - 1) {
            onComplete(nextScore, puzzleRounds.map(r => r.target), puzzleRounds.map(r => r.distractor));
          } else {
            setCurrentRound(prev => prev + 1);
            setTimeLeft(MEMORIZE_DURATION);
            setGamePhase('MEMORIZE');
            setChoiceStatus('idle');
            setSelectedChoice(null);
            setRevealedIndex(-1);
            setRoundResults(nextResults);
            setIsTransitioning(false);
            setHintUsedThisRound(false);
            setSlowMoFactor(1);
            setIsTimeFrozen(false);
          }
        }, 400);
      }, delay);
    }, 600); 
  };

  const ringItems = useMemo(() => {
    return activeRoundData.target.split("").map((char, i) => ({
      char,
      color: COLORS[i % COLORS.length]
    }));
  }, [activeRoundData]);

  const renderRing = () => {
    const dist = 120; 
    const isSuccess = choiceStatus === 'success';

    const screenWidth = typeof window !== 'undefined' ? window.innerWidth : 360;
    const safeContainerWidth = screenWidth * 0.85;
    const dynamicSpacing = Math.min(52, safeContainerWidth / Math.max(1, ringItems.length - 0.5));
    const dynamicCubeSize = Math.min(58, dynamicSpacing * 1.2);

    const cubeAnimSpeed = 4 / stats.difficultyFactor;

    return (
      <div 
        className={`relative w-full h-full flex items-center justify-center transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-75 blur-lg' : 'opacity-100 scale-100'}`} 
        style={{ transformStyle: 'preserve-3d' }}
      >
        {ringItems.map((item, idx) => {
          const angle = (idx / ringItems.length) * 360 + rotationOffset;
          const rad = (angle * Math.PI) / 180;

          let x = 0, y = 0, z = 0;
          let rotX = 0, rotY = 0, rotZ = 0;
          let scale = 1;

          if (isSuccess) {
            x = (idx - (ringItems.length - 1) / 2) * dynamicSpacing;
            y = 0;
            z = 20;
            scale = 1.1 + (revealedIndex === idx ? 0.15 : 0);
          } else {
            switch (currentStyle) {
              case 'BALERİN':
                x = Math.cos(rad) * dist;
                y = Math.sin(rotationOffset * 0.05) * 20;
                z = Math.sin(rad) * dist;
                rotY = rotationOffset * 2;
                break;
              case 'DÖNMEDOLAP':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                z = 0;
                rotZ = -angle; 
                break;
              case 'ATLIKARINCA':
                x = Math.cos(rad) * dist;
                y = Math.sin(rotationOffset * 0.1 + idx) * 30;
                z = Math.sin(rad) * dist;
                break;
              case 'DEĞİRMEN':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                z = -50;
                rotZ = rotationOffset;
                break;
              case 'DNA':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad * 2 + rotationOffset * 0.1) * 40;
                z = Math.sin(rad) * dist;
                rotY = angle;
                break;
              case 'NABIZ':
                x = Math.cos(rad) * (dist + Math.sin(rotationOffset * 0.2) * 20);
                y = Math.sin(rad) * (dist + Math.sin(rotationOffset * 0.2) * 20);
                scale = 1 + Math.sin(rotationOffset * 0.2) * 0.1;
                break;
              case 'SARKAÇ':
                const swingAngle = Math.sin(rotationOffset * 0.05) * 60;
                const swingRad = ((angle + swingAngle) * Math.PI) / 180;
                x = Math.cos(swingRad) * dist;
                y = Math.sin(swingRad) * dist;
                break;
              case 'GİRDAP':
                const spiralDist = dist + Math.sin(rotationOffset * 0.1 + idx) * 30;
                x = Math.cos(rad) * spiralDist;
                y = Math.sin(rad) * spiralDist;
                z = Math.cos(rotationOffset * 0.1 + idx) * 40;
                break;
              case 'DALGA':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad * 3 + rotationOffset * 0.1) * 30;
                z = Math.sin(rad) * dist;
                break;
              case 'SONSUZLUK':
                const t = rad + rotationOffset * 0.01;
                const den = 1 + Math.pow(Math.sin(t), 2);
                x = (dist * 1.5 * Math.cos(t)) / den;
                y = (dist * 1.5 * Math.sin(t) * Math.cos(t)) / den;
                break;
              case 'KELEBEK':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                rotX = Math.sin(rotationOffset * 0.1 + idx) * 45;
                break;
              case 'FIRTINA':
                x = Math.cos(rad) * dist + (Math.random() - 0.5) * 5;
                y = Math.sin(rad) * dist + (Math.random() - 0.5) * 5;
                rotZ = rotationOffset * 5;
                break;
              case 'SEKSEK':
                const step = Math.floor(rotationOffset * 0.1) % 2;
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist + (step === 0 ? 20 : -20);
                break;
              case 'KUŞAK':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * (dist * 0.3);
                z = Math.sin(rad) * dist;
                rotX = 60;
                break;
              case 'MERCEK':
                const focus = Math.sin(rad + rotationOffset * 0.05);
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                scale = 1 + focus * 0.4;
                z = focus * 50;
                break;
              case 'BASAMAK':
                x = Math.cos(rad) * dist;
                y = (idx - ringItems.length / 2) * 40;
                z = Math.sin(rad) * dist;
                break;
              case 'SİKLON':
                const cycloneDist = dist + Math.sin(rotationOffset * 0.1) * 40;
                x = Math.cos(rad) * cycloneDist;
                y = Math.sin(rad) * cycloneDist;
                rotZ = rotationOffset * 2;
                break;
              case 'PİRAMİT':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                z = idx * 20;
                scale = 1 - (idx * 0.05);
                break;
              case 'ZİGZAG':
                x = Math.cos(rad) * dist;
                y = Math.sin(rotationOffset * 0.2 + idx) * 50;
                break;
              case 'KASIRGA':
                x = Math.cos(rad + rotationOffset * 0.05) * (dist + idx * 10);
                y = Math.sin(rad + rotationOffset * 0.05) * (dist + idx * 10);
                z = Math.sin(rotationOffset * 0.1 + idx) * 100;
                break;
              case 'KARMAŞA':
                x = Math.cos(rad) * dist + Math.sin(rotationOffset * 0.1 + idx) * 10;
                y = Math.sin(rad) * dist + Math.cos(rotationOffset * 0.1 + idx) * 10;
                rotX = rotationOffset;
                rotY = rotationOffset;
                break;
              case 'TRAMPOLİN':
                x = Math.cos(rad) * dist;
                y = Math.abs(Math.sin(rotationOffset * 0.1 + idx)) * -100 + 50;
                break;
              case 'YOYO':
                const yoyoDist = dist + Math.sin(rotationOffset * 0.15) * 80;
                x = Math.cos(rad) * yoyoDist;
                y = Math.sin(rad) * yoyoDist;
                break;
              case 'HALKALI':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * 20;
                z = Math.sin(rad) * dist;
                rotX = 75;
                break;
              case 'ÇAPRAZ':
                const cross = idx % 2 === 0 ? 1 : -1;
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist * cross;
                break;
              case 'ASANSÖR':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                z = Math.sin(rotationOffset * 0.05) * 200;
                break;
              case 'BOOMERANG':
                const boom = Math.sin(rotationOffset * 0.08);
                x = Math.cos(rad) * (dist + boom * 150);
                y = Math.sin(rad) * (dist + boom * 150);
                break;
              case 'LABİRENT':
                x = Math.cos(rad) * dist + (idx % 3) * 30;
                y = Math.sin(rad) * dist + (Math.floor(idx / 3)) * 30;
                break;
              case 'KALEYDOSKOP':
                const multi = idx % 2 === 0 ? 1 : -1;
                x = Math.cos(rad) * dist;
                y = Math.sin(rad * multi) * dist;
                rotZ = rotationOffset * multi;
                break;
              case 'KUANTUM':
                const jitter = (Math.random() - 0.5) * 4;
                x = Math.cos(rad) * dist + jitter;
                y = Math.sin(rad) * dist + jitter;
                z = Math.sin(rotationOffset * 0.3 + idx) * 20;
                break;
              case 'SARMAN':
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                z = (idx - ringItems.length / 2) * 60;
                rotZ = rotationOffset;
                break;
              case 'VALS':
                const vT = rotationOffset * 0.05 + idx;
                x = Math.sin(vT) * 140;
                y = Math.sin(vT * 2) * 70;
                z = Math.cos(vT) * 40;
                break;
              default: 
                x = Math.cos(rad) * dist;
                y = Math.sin(rad) * dist;
                z = 0;
                break;
            }
          }

          return (
            <div 
              key={`${currentRound}-${idx}`} 
              className="absolute transition-all duration-300 ease-out"
              style={{ 
                transform: `translate3d(${x}px, ${y}px, ${z}px) rotateX(${rotX}deg) rotateY(${rotY}deg) rotateZ(${rotZ}deg) scale(${scale})`, 
                transformStyle: 'preserve-3d', 
                zIndex: (revealedIndex === idx) ? 300 : 20
              }}
            >
              <Cube3D 
                size={isSuccess ? dynamicCubeSize : 58} 
                label={gamePhase === 'GUESS' && !isSuccess ? '?' : item.char} 
                color={item.color} 
                visualStyle={currentCubeVisualStyle}
                status={choiceStatus} 
                isRevealed={true}
                delay={idx * 0.05}
                speed={isSuccess || gamePhase === 'GUESS' ? 0 : cubeAnimSpeed}
              />
            </div>
          );
        })}
      </div>
    );
  };

  const isBarUrgent = (gamePhase === 'GUESS' && timeLeft < dynamicRoundTime * 0.3) || (gamePhase === 'MEMORIZE' && timeLeft < 2);
  const barJitter = isBarUrgent && stats.difficultyFactor > 1.4 ? (Math.random() - 0.5) * 4 : 0;
  const barMax = gamePhase === 'MEMORIZE' ? MEMORIZE_DURATION : dynamicRoundTime;

  const getBarColor = () => {
    if (gamePhase === 'MEMORIZE') return '#22d3ee';
    const percent = timeLeft / dynamicRoundTime;
    if (percent > 0.6) return '#22d3ee';
    if (percent > 0.3) return '#fbbf24';
    return '#f87171';
  };

  const isHintPhase = gamePhase === 'MEMORIZE' && timeLeft <= MEMORIZE_DURATION / 2 && !hintUsedThisRound;

  const renderButtonContent = (text: string) => {
    if (gamePhase !== 'MEMORIZE') return text;

    return (
      <div className="flex flex-wrap justify-center gap-x-2 gap-y-1 px-4 items-center h-full relative z-[50]">
        {text.split('').map((_, idx) => (
          <div 
            key={idx} 
            className="h-[10px] rounded-full transition-all duration-300 animate-[pulse_1.5s_infinite_ease-in-out] relative"
            style={{ 
              width: '24px',
              backgroundColor: COLORS[idx % COLORS.length],
              boxShadow: `0 0 15px ${COLORS[idx % COLORS.length]}, 0 0 5px ${COLORS[idx % COLORS.length]}`,
              animationDelay: `${idx * 0.1}s`,
              border: '1.5px solid white',
              zIndex: 60
            }} 
          >
            <div 
              className="absolute inset-0 bg-white opacity-80 rounded-full blur-[1px]" 
              style={{ boxShadow: `0 0 8px white` }}
            />
          </div>
        ))}
      </div>
    );
  };

  return (
    <div className="absolute inset-0 bg-[#020617] flex flex-col overflow-hidden">
      <ParticleBackground speedMultiplier={choiceStatus === 'success' ? 0.05 : 0.25 * stats.difficultyFactor} />

      <div 
        className={`fixed inset-0 z-[250] bg-black/20 backdrop-blur-lg transition-opacity duration-500 pointer-events-none ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} 
      />

      <div className={`pt-10 px-8 flex justify-between items-start z-20 ${isMenuOpen || choiceStatus !== 'idle' ? 'opacity-0' : 'opacity-100'} transition-opacity duration-500 shrink-0`}>
        <div className="flex flex-col gap-2">
          <div className="flex gap-1.5 p-2 bg-black/40 backdrop-blur-2xl rounded-xl border border-white/10 shadow-2xl">
            {roundResults.map((res, i) => (
              <div key={i} className={`w-3 h-3 rounded-md border-2 transition-all duration-500 ${res === 'success' ? 'bg-[#4ade80] border-white shadow-[0_0_8px_#4ade80]' : res === 'fail' ? 'bg-[#f87171] border-white shadow-[0_0_8px_#f87171]' : i === currentRound ? 'bg-[#22d3ee] border-white animate-pulse' : 'bg-white/10 border-white/10'}`} />
            ))}
          </div>
          <div className="flex flex-col ml-1">
            <span className="text-[8px] font-[900] text-[#22d3ee] tracking-[0.2em] uppercase mt-0.5">
              {gamePhase === 'MEMORIZE' ? 'ODAKLAN!' : `${currentStyle} MODU`}
            </span>
          </div>
        </div>

        <div className="text-3xl font-[900] text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.4)]">{sessionScore.toLocaleString()}</div>
      </div>

      <div className={`flex-1 relative flex items-center justify-center perspective-[1200px] z-10 min-h-0 transition-all duration-500 ${isMenuOpen ? 'blur-sm brightness-50' : ''}`}>
        <div className="relative w-full h-full max-h-[400px] flex items-center justify-center" style={{ transformStyle: 'preserve-3d' }}>
          {renderRing()}
        </div>
      </div>

      <div className="fixed right-2 bottom-2 z-[300]">
        <SideMenu onExit={() => setShowQuitModal(true)} onToggle={setIsMenuOpen} isMinimal={true} expandDirection="up" />
      </div>

      {gamePhase === 'MEMORIZE' && !isTransitioning && (
        <div className="fixed right-6 bottom-24 z-[300] animate-[popIn_0.5s_cubic-bezier(0.34,1.56,0.64,1)]">
          {/* İpucu Menüsü */}
          <div className={`absolute bottom-full left-0 right-0 mb-4 flex flex-col gap-2 transition-all duration-500 origin-bottom ${showHintMenu ? 'scale-100 opacity-100 translate-y-0' : 'scale-0 opacity-0 translate-y-10 pointer-events-none'}`}>
            <button 
              onClick={() => useHint('SLOW')}
              className="w-full bg-[#fbbf24] border-b-[6px] border-[#d97706] rounded-2xl py-3 px-4 flex items-center gap-3 active:translate-y-1 active:border-b-0 transition-all"
            >
              <span className="text-xl">🐢</span>
              <span className="text-[10px] font-black text-amber-900 uppercase">YAVAŞLAT</span>
            </button>
            <button 
              onClick={() => useHint('FREEZE')}
              className="w-full bg-[#22d3ee] border-b-[6px] border-[#0891b2] rounded-2xl py-3 px-4 flex items-center gap-3 active:translate-y-1 active:border-b-0 transition-all"
            >
              <span className="text-xl">❄️</span>
              <span className="text-[10px] font-black text-cyan-900 uppercase">DONDUR</span>
            </button>
            <button 
              onClick={() => useHint('REVEAL')}
              className="w-full bg-[#f472b6] border-b-[6px] border-[#db2777] rounded-2xl py-3 px-4 flex items-center gap-3 active:translate-y-1 active:border-b-0 transition-all"
            >
              <span className="text-xl">🎯</span>
              <span className="text-[10px] font-black text-pink-900 uppercase">ODAKLA</span>
            </button>
          </div>

          <button 
            onClick={isHintPhase ? () => setShowHintMenu(!showHintMenu) : handleSkipMemorize}
            className={`group relative w-32 h-24 flex items-center justify-center transition-all active:scale-95`}
          >
            <div className={`absolute inset-0 blur-3xl rounded-full animate-pulse scale-110 pointer-events-none group-active:scale-150 transition-all duration-300 ${isHintPhase ? 'bg-amber-400/40' : 'bg-[#22d3ee]/40'}`} />
            <div className={`absolute inset-[-10px] border-[2px] border-dashed rounded-full animate-[spin_6s_linear_infinite] opacity-50 transition-colors ${isHintPhase ? 'border-amber-400/60' : 'border-[#22d3ee]/60'}`} />
            <div className={`absolute inset-[-4px] border-[3px] rounded-[32px] group-hover:border-opacity-80 transition-all duration-500 ${isHintPhase ? 'border-amber-400/20' : 'border-[#22d3ee]/20'}`} />

            <div className={`relative w-full h-full bg-[#1e293b]/95 border-[4px] border-b-[12px] rounded-[32px] backdrop-blur-3xl flex flex-col items-center justify-center shadow-[0_25px_50_rgba(0,0,0,0.8)] active:border-b-[4px] active:translate-y-2 transition-all ${isHintPhase ? 'border-amber-400/50 border-b-amber-600' : 'border-[#22d3ee]/50 border-b-[#0891b2]'}`}>
               <div className={`absolute inset-0 bg-gradient-to-tr from-white/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity animate-pulse`} />
               <span className="text-[17px] font-[900] text-white tracking-widest uppercase leading-none drop-shadow-[0_4px_10px_rgba(0,0,0,0.5)] z-10 group-hover:scale-110 transition-transform text-center px-2">
                 {isHintPhase ? 'İPUCU' : 'BULDUM'}
               </span>
               <div className="absolute top-0 left-0 w-full h-1/2 bg-white/10 rounded-t-[26px] pointer-events-none" />
               <div className={`absolute -bottom-1 w-8 h-1 rounded-full blur-sm animate-pulse opacity-50 ${isHintPhase ? 'bg-amber-400' : 'bg-[#22d3ee]'}`} />
            </div>
          </button>
        </div>
      )}

      <div className={`px-8 pb-10 flex flex-col gap-6 z-20 transition-all duration-700 shrink-0 ${isTransitioning || choiceStatus === 'success' ? 'opacity-0 translate-y-20 scale-95 pointer-events-none' : 'opacity-100 translate-y-0 scale-100'} ${isMenuOpen ? 'blur-sm pointer-events-none' : ''}`}>

        <div 
          className="w-full h-2 bg-black/60 rounded-full overflow-hidden relative border border-white/5 shadow-[inset_0_2px_8px_rgba(0,0,0,0.8)]" 
          style={{ transform: `translateX(${barJitter}px)` }}
        >
          <div className="absolute top-0 left-0 w-full h-[35%] bg-white/5 z-20 pointer-events-none" />
          <div 
            className={`h-full relative transition-all duration-300 shadow-[0_0_15px_rgba(0,0,0,0.5)] flex items-center justify-end overflow-hidden`} 
            style={{ 
              width: `${(timeLeft / barMax) * 100}%`,
              backgroundColor: getBarColor(),
              boxShadow: `0 0 25px ${getBarColor()}66`
            }}
          >
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/25 to-transparent -translate-x-full animate-plasma-flow" />
            <div className={`w-4 h-full bg-white/60 blur-md absolute right-0 transition-opacity duration-300 ${timeLeft > 0 ? 'opacity-100' : 'opacity-0'}`} />
            <div className={`w-1 h-full bg-white absolute right-0 shadow-[0_0_10px_#fff] transition-opacity duration-300 ${timeLeft > 0 ? 'opacity-100' : 'opacity-0'}`} />
          </div>
        </div>

        <div className={`flex flex-col gap-4 transition-all duration-500`}>
          {activeOptions.map((opt, i) => {
            const isSelected = selectedChoice === opt;
            const isDimmed = selectedChoice !== null && !isSelected;

            const guessVariants: Array<'indigo' | 'pink' | 'amber' | 'cyan'> = ['indigo', 'pink', 'amber', 'cyan'];
            let variant: 'cyan' | 'indigo' | 'pink' | 'amber' | 'green' | 'coral' | 'white' = guessVariants[i % guessVariants.length];
            let extraShadow = "";

            if (isSelected) {
              if (choiceStatus === 'success') {
                variant = 'green';
                extraShadow = "shadow-[0_0_35px_rgba(74,222,128,0.7)]"; 
              } else if (choiceStatus === 'fail') {
                variant = 'coral';
                extraShadow = "shadow-[0_0_35px_rgba(248,113,113,0.7)]"; 
              } else {
                variant = 'white'; 
                extraShadow = "shadow-[0_0_45px_rgba(255,255,255,0.8)]"; 
              }
            } else if (gamePhase === 'GUESS' && !isSelected) {
               const shadowColors = {
                 indigo: 'rgba(129, 140, 248, 0.4)',
                 pink: 'rgba(244, 114, 182, 0.4)',
                 amber: 'rgba(251, 191, 36, 0.4)',
                 cyan: 'rgba(34, 211, 238, 0.4)'
               };
               extraShadow = `shadow-[0_15px_30px_${shadowColors[variant as keyof typeof shadowColors]}]`;
            }

            return (
              <Button 
                key={i} 
                variant={variant} 
                onClick={() => handleChoice(opt)} 
                className={`w-full !h-20 !rounded-[32px] !text-[34px] !leading-none !tracking-tighter !border-b-[8px] active:!border-b-[2px] transition-all duration-300 ${extraShadow} ${isDimmed ? 'opacity-20 scale-90 blur-[2px]' : isSelected ? 'scale-105 z-30' : 'opacity-100 scale-100'} ${gamePhase === 'MEMORIZE' ? 'pointer-events-none' : ''}`}
                disabled={selectedChoice !== null || (gamePhase !== 'GUESS' && gamePhase !== 'MEMORIZE')}
              >
                {renderButtonContent(opt)}
              </Button>
            );
          })}
        </div>
      </div>

      {showQuitModal && (
        <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />
      )}
    </div>
  );
};

