                    : 'bg-[#1e293b] border-[#0f172a] border-t-white/10'
                  }`}
                >
                  <div className="absolute top-0 left-0 right-0 h-1/2 bg-white/20 pointer-events-none" />
                  <div className="w-8 text-center shrink-0">
                    <span className={`text-base font-black ${player.isUser ? 'text-[#083344]' : 'text-white/20'}`}>#{player.rank}</span>
                  </div>
                  <div className="w-12 h-12 bg-black/20 rounded-xl flex items-center justify-center text-2xl border border-white/5 shrink-0 relative">
                    {player.avatar}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className={`font-black text-sm uppercase tracking-tighter truncate leading-none mb-0.5 ${player.isUser ? 'text-[#083344]' : 'text-white'}`}>
                      {player.name}
                    </h4>
                    <p className={`text-[8px] font-black uppercase tracking-[0.1em] ${player.isUser ? 'text-[#083344]/50' : 'text-white/30'}`}>
                      {player.score.toLocaleString()} PUAN • {player.title}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </>
        ) : (
          <div className="flex flex-col gap-4 animate-[fadeIn_0.5s_ease-out]">

            {/* KİŞİSEL ÖZET */}
            <div className="w-full bg-[#1e293b] border-b-[10px] border-x-[1.5px] border-t-[1.5px] border-[#0f172a] border-t-white/10 rounded-[32px] p-6 shadow-xl relative overflow-hidden text-center">
               <div className="absolute top-0 left-0 right-0 h-1/2 bg-gradient-to-b from-white/10 to-transparent pointer-events-none" />
               <div className="w-20 h-20 bg-gradient-to-b from-[#22d3ee] to-[#0891b2] border-[4px] border-white rounded-[24px] mx-auto flex items-center justify-center shadow-lg mb-3">
                  <span className="text-4xl">👾</span>
               </div>
               <h3 className="text-white text-2xl font-black tracking-tighter uppercase mb-0.5">LİG REKORU</h3>
               <p className="text-[#22d3ee] font-black text-[10px] uppercase tracking-[0.3em]">{userScore.toLocaleString()} GEÇİT PUANI</p>
            </div>

            {/* RÜTBE GEÇİDİ */}
            <div className="w-full bg-[#f472b6] border-b-[10px] border-x-[1.5px] border-t-[2px] border-[#db2777] border-t-[#fce7f3] rounded-[32px] p-5 shadow-xl relative overflow-hidden">
               <div className="absolute top-0 left-0 right-0 h-1/2 bg-gradient-to-b from-white/30 to-transparent pointer-events-none" />

               <div className="flex justify-between items-end mb-4">
                  <div>
                    <span className="text-white font-[900] text-[7px] uppercase tracking-[0.4em] mb-0.5 opacity-80">RÜTBE GEÇİDİ</span>
                    <span className="text-white text-lg font-black tracking-tighter uppercase block">{rankData.title}</span>
                  </div>
                  <div className="bg-black/30 px-3 py-1 rounded-lg border border-white/10">
                    <span className="text-white font-black text-base">{rankData.progress} <span className="text-[10px] opacity-30">/ 10</span></span>
                  </div>
               </div>

               {/* Segmentli 3D Bar */}
               <div className="flex gap-1 h-6">
                  {[...Array(10)].map((_, i) => (
                    <div 
                      key={i} 
                      className={`flex-1 h-full rounded-md border-x-[1px] border-t-[1px] border-b-[3px] transition-all duration-500 ${
                        (i + 1) <= rankData.progress 
                        ? 'bg-white border-white shadow-[0_0_10px_rgba(255,255,255,0.3)] border-b-[#f472b6]/20' 
                        : 'bg-black/20 border-white/5 border-b-black/40'
                      }`}
                    />
                  ))}
               </div>
            </div>

            {/* İSTATİSTİK GRID */}
            <div className="grid grid-cols-2 gap-3">
               {statsDisplay.map((s, i) => (
                 <div 
                   key={i} 
                   className="p-5 rounded-[24px] border-b-[8px] border-x-[1px] border-t-[1.5px] flex flex-col items-center shadow-lg relative overflow-hidden bg-gradient-to-br"
                   style={{ 
                     backgroundColor: s.accent, 
                     borderBottomColor: 'rgba(0,0,0,0.3)', 
                     borderTopColor: 'rgba(255,255,255,0.4)', 
                     borderColor: 'rgba(0,0,0,0.1)' 
                   }}
                 >
                   <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent pointer-events-none" />
                   <span className="text-3xl mb-2">{s.icon}</span>
                   <span className="text-[9px] font-black text-black/40 uppercase tracking-widest mb-1">{s.label}</span>
                   <span className="text-2xl font-black text-white tracking-tighter">{s.value}</span>
                 </div>
               ))}
            </div>

            {/* Kaydet Butonu */}
            <Button 
              variant="indigo" 
              onClick={() => setShowLogin(true)} 
              className="w-full !py-5 !text-lg !rounded-[28px] !border-b-[8px] shadow-xl mt-1"
            >
              <div className="flex items-center justify-center gap-3">
                <span className="text-2xl">👤</span>
                <span className="tracking-tighter">SIRALAMAYI BULUTA YEDEKLE</span>
              </div>
            </Button>

          </div>
        )}

      </div>

      {showLogin && <LoginModal onClose={() => setShowLogin(false)} />}

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes levitate {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-8px); }
        }
        .custom-scrollbar::-webkit-scrollbar {
          width: 0px;
          display: none;
        }
      `}</style>
    </div>
  );
};

payload.text:
Lumina Quest projesinin Senior Backend Architect'i olarak, oyunun mevcut akışını bozmadan, verileri güvenli bir şekilde buluta taşıyacak ve çoklu cihaz desteği sunacak **Firebase Entegrasyon Planı**'nı aşağıda mimari detaylarıyla sunuyorum.

### 🛠 Lumina Bulut Senkronizasyon Mimarisi

Bu plan, "Offline-First" (Önce Yerel) prensibine dayanır; yani oyuncu interneti kopsa dahi oynamaya devam eder, bağlantı geldiğinde veriler arka planda atomik bir şekilde Firestore ile eşleşir.

---

#### 1. Aşama: Kimlik Doğrulama (Firebase Auth)
Mevcut `LoginModal.tsx` içindeki Facebook ve Google butonlarını gerçek işlevselliğe bağlayacağız.
*   **Yöntem:** `signInWithPopup` (Web/Desktop) ve `signInWithRedirect` (Mobile Safari/Chrome) hibrit yapısı.
*   **Mimarisi:** Kullanıcı giriş yaptığı an, Firebase tarafında benzersiz bir `UID` oluşturulacak. Bu UID, Firestore'daki veri dökümanının anahtarı olacak.

#### 2. Aşama: Veri Modeli ve Firestore Şeması
NoSQL yapısında, okuma maliyetini düşürmek için **denormalize** bir yapı kullanacağız.

**Koleksiyon: `users`**
```typescript
{
  uid: string; // Belge ID
  stats: {
    coins: number;
    hearts: number;
    stars: number;
    level: number;
    hints: { freeze: number; reveal: number; };
    performance: boolean[]; // Son 10 oyun başarısı
  },
  meta: {
    lastSync: timestamp;
    platform: string;
    version: "2026.11";
  }
}
```

#### 3. Aşama: Senkronizasyon Stratejisi (The Bridge)
`App.tsx` içindeki `stats` state'ini koruyacağız ancak bir "Middleware" (Ara katman) ekleyeceğiz.
*   **Conflict Resolution (Çakışma Çözümü):** Eğer buluttaki `level` yereldeki `level`'dan yüksekse, buluttaki veri kazanır. Eğer yerel veride daha fazla `coin` varsa, yerel veri buluta yazılır (Merge logic).
*   **Debounced Writes:** Her coin kazanıldığında DB'ye yazmak yerine, belirli aralıklarla veya modal kapatıldığında toplu yazma (Batch write) yaparak API maliyetlerini düşüreceğiz.

#### 4. Aşama: Güvenlik Kuralları (Firestore Rules)
Verilerin manipüle edilmesini engellemek için sunucu tarafında şu kural setini uygulayacağız:
*   `allow read, write: if request.auth != null && request.auth.uid == userId;`
*   Bu sayede hiçbir kullanıcı, bir başkasının `coin` veya `level` bilgisini göremeyecek veya değiştiremeyecek.

#### 5. Aşama: Performans ve Hata Yönetimi
*   **Persistence:** `enableIndexedDbPersistence` kullanarak verilerin tarayıcı önbelleğinde şifreli saklanmasını sağlayacağız.
*   **Graceful Degradation:** Firebase bağlantısı başarısız olursa sistem otomatik olarak `LocalStorage` moduna dönecek ve kullanıcıya hiçbir hata hissettirmeyecek.

---

### 🚀 Uygulama Planı (Onayınızdan Sonra):
1.  **Firebase Init:** `lib/firebase.ts` dosyasını gerçek projenizle konfigüre edeceğiz.
2.  **Auth Integration:** `LoginModal` işlevlerini yazacağız.
3.  **Sync Hook:** `App.tsx` içine `useFirebaseSync` özel hook'unu entegre edeceğiz.

**Mimaride değiştirmemi istediğiniz bir nokta var mı? Eğer plan uygunsa, entegrasyon kodlarını hazırlamaya başlayabilirim.**

