import { initializeApp } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-app.js";
import { getAuth, GoogleAuthProvider, FacebookAuthProvider, signInWithPopup, signOut, onAuthStateChanged, User } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { getFirestore, doc, setDoc, getDoc } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { UserStats } from "../types";

// Firebase yapılandırması - Bu alan Firebase projenizden gelen bilgilerle güncellenmelidir.
// process.env.API_KEY genellikle Gemini içindir, Firebase için kendi config nesnenizi kullanın.
const firebaseConfig = {
  apiKey: "AIzaSyDummyKeyForInfrastructureSetup",
  authDomain: "lumina-quest.firebaseapp.com",
  projectId: "lumina-quest",
  storageBucket: "lumina-quest.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:abcdef"
};

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app);

// Sağlayıcılar
const googleProvider = new GoogleAuthProvider();
const facebookProvider = new FacebookAuthProvider();

/**
 * Google ile Giriş Yap
 */
export const signInWithGoogle = async () => {
  try {
    const result = await signInWithPopup(auth, googleProvider);
    return result.user;
  } catch (error) {
    console.error("Google login error:", error);
    throw error;
  }
};

/**
 * Facebook ile Giriş Yap
 */
export const signInWithFacebook = async () => {
  try {
    const result = await signInWithPopup(auth, facebookProvider);
    return result.user;
  } catch (error) {
    console.error("Facebook login error:", error);
    throw error;
  }
};

/**
 * Çıkış Yap
 */
export const logout = () => signOut(auth);

/**
 * Akıllı Senkronizasyon (Conflict Resolution)
 * Bulut ve Yerel veriyi karşılaştırıp en mantıklı olanı seçer.
 */
export const reconcileStats = (local: UserStats, cloud: UserStats): UserStats => {
  // 1. Seviye önceliği (En yüksek seviye kazanır)
  if (cloud.level > local.level) return cloud;
  if (local.level > cloud.level) return local;

  // 2. Seviyeler eşitse, en çok yıldız veya coin hangisindeyse onu al
  return {
    ...local,
    coins: Math.max(local.coins, cloud.coins),
    stars: Math.max(local.stars, cloud.stars),
    hearts: local.hearts, // Kalp gibi anlık tüketilenler yerelden alınabilir
    hintsFreeze: Math.max(local.hintsFreeze, cloud.hintsFreeze),
    hintsReveal: Math.max(local.hintsReveal, cloud.hintsReveal),
  };
};

/**
 * Kullanıcı istatistiklerini Firestore'a yedekle
 */
export const syncUserStats = async (uid: string, stats: UserStats): Promise<void> => {
  try {
    const userDocRef = doc(db, "users", uid);
    await setDoc(userDocRef, { ...stats, updatedAt: Date.now() }, { merge: true });
  } catch (error) {
    console.debug("Background sync skip (Offline or Config missing)");
  }
};

/**
 * Buluttan veri çek
 */
export const fetchCloudStats = async (uid: string): Promise<UserStats | null> => {
  try {
    const userDocRef = doc(db, "users", uid);
    const docSnap = await getDoc(userDocRef);
    if (docSnap.exists()) {
      return docSnap.data() as UserStats;
    }
  } catch (error) {
    console.error("Fetch error:", error);
  }
  return null;
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, UserStats, HubSubView } from './types';
import { LoadingScreen } from './screens/LoadingScreen';
import { HubScreen } from './screens/HubScreen';
import { MemoryGame } from './screens/MemoryGame';
import { WordPuzzle } from './screens/WordPuzzle';
import { LevelCompleteModal } from './components/LevelCompleteModal';
import { LevelFailModal } from './components/LevelFailModal';
import { ChestModal } from './components/ChestModal';
import { MemoryTransitionModal } from './components/MemoryTransitionModal';
import { auth, fetchCloudStats, syncUserStats, reconcileStats } from './lib/firebase.ts';
import { onAuthStateChanged, User } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

const STORAGE_KEY = 'lumina_stats';
const DEFAULT_BG = "https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&q=80&w=1080&h=1920";
const MISSIONS_REFRESH_INTERVAL = 24 * 60 * 60 * 1000;

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.LOADING);
  const [hubSubView, setHubSubView] = useState<HubSubView>(HubSubView.MAIN);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { console.error(e); }
    }
    return {
      coins: 2063, hearts: 5, stars: 12, level: 1,
      lastLifeRefillTime: Date.now(),
      hintsFreeze: 3, hintsReveal: 3,
      claimedMissions: [],
      lastMissionsRefresh: Date.now(),
      difficultyFactor: 1.0, performanceHistory: [],
      streak: 0, maxStreak: 0
    };
  });

  // Firebase Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      setCurrentUser(user);
      if (user) {
        console.log("Kullanıcı aktif:", user.displayName);
        // Bulut verilerini çek ve yerel ile birleştir
        const cloudData = await fetchCloudStats(user.uid);
        if (cloudData) {
          const merged = reconcileStats(stats, cloudData);
          setStats(merged);
        }
      }
    });
    return () => unsubscribe();
  }, []);

  // Yerel Kayıt ve Bulut Senkronizasyonu
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stats));
    if (currentUser) {
      // Debounced Sync (Ağ yükünü azaltmak için)
      const timeout = setTimeout(() => {
        syncUserStats(currentUser.uid, stats);
      }, 2000);
      return () => clearTimeout(timeout);
    }
  }, [stats, currentUser]);

  // Görev sıfırlama kontrolü
  useEffect(() => {
    const now = Date.now();
    if (now - stats.lastMissionsRefresh >= MISSIONS_REFRESH_INTERVAL) {
      setStats(prev => ({
        ...prev,
        claimedMissions: [],
        lastMissionsRefresh: now
      }));
    }
  }, [stats.lastMissionsRefresh]);

  const [targetWords, setTargetWords] = useState<string[]>([]);
  const [fullWordPool, setFullWordPool] = useState<string[]>([]);
  const [showChest, setShowChest] = useState(false);
  const [bonusEarned, setBonusEarned] = useState(0);
  const [sessionScore, setSessionScore] = useState(0);
  const [starsEarnedInLevel, setStarsEarnedInLevel] = useState(0);
  const [transitionState, setTransitionState] = useState<'idle' | 'animating'>('idle');

  const changeGameState = (newState: GameState) => {
    setTransitionState('animating');
    setTimeout(() => {
      setGameState(newState);
      setTransitionState('idle');
    }, 300);
  };

  const updateStats = (updates: Partial<UserStats>) => {
    setStats(prev => ({ ...prev, ...updates }));
  };

  const handleClaimMission = (id: number, reward: number) => {
    updateStats({
      coins: stats.coins + reward,
      claimedMissions: [...stats.claimedMissions, id]
    });
  };

  const handleStartGame = () => {
    if (stats.hearts > 0) {
      setSessionScore(0);
      changeGameState(GameState.WORD_PUZZLE);
    } else {
      setHubSubView(HubSubView.SHOP);
    }
  };

  const handleExitWithPenalty = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.HUB);
  };

  const handlePuzzleComplete = (earned: number, allTargets: string[], allDistractors: string[]) => {
    setSessionScore(earned);
    setTargetWords(allTargets);
    const pooledWords = [...allTargets, ...allDistractors].sort(() => Math.random() - 0.5);
    setFullWordPool(pooledWords);
    changeGameState(GameState.MEMORY_PREPARE);
  };

  const handleGameComplete = (correctCount: number) => {
    let stars = correctCount === 5 ? 3 : correctCount >= 4 ? 2 : 1;
    let bonus = correctCount * 50;
    setStarsEarnedInLevel(stars);
    setBonusEarned(bonus);
    changeGameState(GameState.LEVEL_COMPLETE);
  };

  const handleLevelFail = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.LEVEL_FAIL);
  };

  const handleBuyItem = (cost: number, type: 'HEART' | 'FREEZE' | 'REVEAL', amount: number) => {
    if (stats.coins < cost) return;
    setStats(prev => {
      const next = { ...prev, coins: prev.coins - cost };
      if (type === 'HEART') next.hearts = Math.min(5, prev.hearts + amount);
      if (type === 'FREEZE') next.hintsFreeze += amount;
      if (type === 'REVEAL') next.hintsReveal += amount;
      return next;
    });
  };

  const renderScreen = () => {
    switch (gameState) {
      case GameState.LOADING: return <LoadingScreen onFinished={() => changeGameState(GameState.HUB)} />;
      case GameState.HUB: return <HubScreen stats={stats} hubSubView={hubSubView} setHubSubView={setHubSubView} onStartGame={handleStartGame} onAddCoins={(amt) => updateStats({ coins: stats.coins + amt })} onBuyHearts={(c, a) => handleBuyItem(c, 'HEART', a)} onOpenChest={() => setShowChest(true)} onClaimMission={handleClaimMission} />;
      case GameState.WORD_PUZZLE: return <WordPuzzle stats={stats} onComplete={handlePuzzleComplete} onExit={handleExitWithPenalty} onUpdateStats={updateStats} />;
      case GameState.MEMORY_PREPARE: return <MemoryTransitionModal onConfirm={() => changeGameState(GameState.MEMORY_GAME)} onExit={handleExitWithPenalty} />;
      case GameState.MEMORY_GAME: return <MemoryGame stats={stats} backgroundUrl={DEFAULT_BG} words={fullWordPool} targetWords={targetWords} onNext={handleGameComplete} onFail={handleLevelFail} onExit={handleExitWithPenalty} initialScore={sessionScore} />;
      case GameState.LEVEL_COMPLETE: return <LevelCompleteModal level={stats.level} coinsEarned={sessionScore + bonusEarned} starsEarned={starsEarnedInLevel} onContinue={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); handleStartGame(); }} onMenu={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); changeGameState(GameState.HUB); }} />;
      case GameState.LEVEL_FAIL: return <LevelFailModal hearts={stats.hearts} lastLifeRefillTime={stats.lastLifeRefillTime} onRetry={() => { if(stats.hearts > 0) changeGameState(GameState.WORD_PUZZLE); else setHubSubView(HubSubView.SHOP); }} onShop={() => { changeGameState(GameState.HUB); setHubSubView(HubSubView.SHOP); }} onExit={() => changeGameState(GameState.HUB)} />;
      default: return <LoadingScreen />;
    }
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-[#020617] overflow-hidden select-none">
      <div className={`w-full h-full transition-all duration-500 ease-out ${transitionState === 'animating' ? 'opacity-0 scale-95 blur-md' : 'opacity-100 scale-100'}`}>
        {renderScreen()}
        {showChest && <ChestModal onClose={() => setShowChest(false)} onReward={(amt) => updateStats({ coins: stats.coins + amt })} />}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { signInWithGoogle, signInWithFacebook } from '../lib/firebase.ts';

interface LoginModalProps {
  onClose: () => void;
}

export const LoginModal: React.FC<LoginModalProps> = ({ onClose }) => {
  const [loading, setLoading] = useState<string | null>(null);

  const handleLogin = async (method: 'google' | 'facebook') => {
    setLoading(method);
    try {
      if (method === 'google') await signInWithGoogle();
      else await signInWithFacebook();
      onClose(); // Giriş başarılıysa kapat
    } catch (error) {
      alert("Giriş sırasında bir hata oluştu. Lütfen tekrar deneyin.");
    } finally {
      setLoading(null);
    }
  };

  return (
    <div className="absolute inset-0 z-[300] flex items-center justify-center p-6 bg-[#020617]/90 backdrop-blur-2xl">
      <div className="w-full max-w-[340px] flex flex-col items-center animate-[popIn_0.4s_cubic-bezier(0.34,1.56,0.64,1)]">

        {/* Banner */}
        <div className="w-full relative h-20 flex items-center justify-center mb-[-12px] z-10 px-4">
          <div className="absolute inset-0 bg-[#818cf8] border-y-[6px] border-white/20 rounded-[28px] shadow-2xl overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-b from-white/30 to-transparent" />
          </div>
          <h2 className="relative text-2xl font-[900] text-white tracking-tighter uppercase drop-shadow-[0_2px_0_#1e1b4b]">
            VERİLERİNİ KORU
          </h2>

          <button 
            onClick={onClose}
            className="absolute -top-3 -right-3 w-12 h-12 bg-[#f87171] border-[4px] border-white rounded-2xl flex items-center justify-center shadow-xl active:translate-y-1 active:shadow-none transition-all z-20"
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="5" className="w-6 h-6">
              <path d="M18 6L6 18M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Container */}
        <div className="w-full bg-[#1e293b] border-[8px] border-[#818cf8]/30 rounded-[48px] p-8 pt-12 shadow-[0_40px_80px_rgba(0,0,0,0.6)] space-y-8">
          <p className="text-white/60 text-center font-[900] text-sm uppercase leading-tight tracking-[0.1em]">
            İLERLEMENİ GEÇİT BULUTUNDA SAKLAMAK İÇİN GİRİŞ YAP!
          </p>

          <div className="flex flex-col gap-5">
            {/* Facebook */}
            <button 
