import React from 'react';
import { SoundManager } from '../managers/SoundManager';

interface ButtonProps {
  children: React.ReactNode;
  onClick: () => void;
  variant?: 'cyan' | 'indigo' | 'pink' | 'amber' | 'green' | 'coral' | 'white';
  className?: string;
  size?: 'sm' | 'md' | 'lg';
  disabled?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  onClick, 
  variant = 'cyan', 
  className = '',
  size = 'md',
  disabled = false
}) => {
  const handleInternalClick = () => {
    if (!disabled) {
      SoundManager.getInstance().playClick();
      onClick();
    }
  };

  const baseStyles = "relative font-[900] uppercase tracking-tighter rounded-[24px] flex items-center justify-center border-b-[8px] border-x-[2px] border-t-[2px] overflow-hidden select-none active:border-b-[2px] active:translate-y-[6px] transition-all duration-200";

  const variants = {
    cyan: "bg-[#7B99A5] text-[#262A2E] border-[#4A5E68] border-t-[#96B5C2] shadow-lg", // Dusty Blue
    indigo: "bg-[#9FAF90] text-[#262A2E] border-[#5E6A56] border-t-[#C2D1B3] shadow-lg", // Sage
    pink: "bg-[#D98A7F] text-white border-[#8C4F48] border-t-[#F2B6AF] shadow-lg", // Coral
    amber: "bg-[#D4AF37] text-[#262A2E] border-[#8C7424] border-t-[#EDD27B] shadow-lg", // Mustard
    green: "bg-[#A3B18A] text-[#262A2E] border-[#588157] border-t-[#DAD7CD] shadow-lg",
    coral: "bg-[#BC4749] text-white border-[#6A1B1D] border-t-[#D96C6E] shadow-lg",
    white: "bg-[#F2E9E1] text-[#262A2E] border-[#C2B9B1] border-t-white shadow-lg"
  };

  const sizes = {
    sm: "px-5 py-2 text-xs",
    md: "px-8 py-4 text-xl",
    lg: "px-10 py-5 text-2xl"
  };

  return (
    <button 
      onClick={handleInternalClick} 
      disabled={disabled}
      className={`
        ${baseStyles} 
        ${variants[variant as keyof typeof variants] || variants.cyan} 
        ${sizes[size]} 
        ${disabled ? 'opacity-50 grayscale cursor-not-allowed border-b-[4px] translate-y-[4px]' : 'cursor-pointer'}
        ${className}
      `}
    >
      {/* Matte Emboss Overlay */}
      <div className="absolute top-0 left-0 right-0 h-[45%] bg-white/10 pointer-events-none" />
      <span className="relative z-10 embossed-text">
        {children}
      </span>
      <div className="absolute inset-0 border border-white/5 rounded-[24px] pointer-events-none" />
    </button>
  );
};

