import React, { useEffect, useRef, memo, useMemo } from 'react';

interface ParticleBackgroundProps {
  speedMultiplier?: number;
  level?: number;
}

// Kelly Boesch Technicolor Palette
const BOESCH_PALETTES = [
  ['#D98A7F', '#262A2E'], // Coral & Dark
  ['#9FAF90', '#262A2E'], // Sage & Dark
  ['#D4AF37', '#262A2E'], // Mustard & Dark
  ['#7B99A5', '#262A2E'], // Dusty Blue & Dark
];

export const ParticleBackground: React.FC<ParticleBackgroundProps> = memo(({ speedMultiplier = 1, level = 1 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const palette = useMemo(() => {
    return BOESCH_PALETTES[Math.floor((level - 1) / 5) % BOESCH_PALETTES.length];
  }, [level]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    // Painted Nebula Clouds instead of particles
    let clouds: Array<{
      x: number;
      y: number;
      radius: number;
      vx: number;
      vy: number;
      color: string;
      alpha: number;
      pulse: number;
    }> = [];

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      init();
    };

    const init = () => {
      clouds = [];
      const count = 5;
      for (let i = 0; i < count; i++) {
        clouds.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          radius: Math.random() * (canvas.width * 0.8) + canvas.width * 0.4,
          vx: (Math.random() - 0.5) * 0.15,
          vy: (Math.random() - 0.5) * 0.15,
          color: palette[0],
          alpha: Math.random() * 0.1 + 0.05,
          pulse: Math.random() * Math.PI
        });
      }
    };

    const draw = () => {
      ctx.fillStyle = '#262A2E'; // Base Dark Paper
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      clouds.forEach((c) => {
        c.pulse += 0.003;
        const currentRadius = c.radius * (1 + Math.sin(c.pulse) * 0.1);

        const grad = ctx.createRadialGradient(c.x, c.y, 0, c.x, c.y, currentRadius);
        grad.addColorStop(0, `${c.color}${Math.floor(c.alpha * 255).toString(16).padStart(2, '0')}`);
        grad.addColorStop(1, 'transparent');

        ctx.fillStyle = grad;
        ctx.fillRect(c.x - currentRadius, c.y - currentRadius, currentRadius * 2, currentRadius * 2);

        c.x += c.vx * speedMultiplier;
        c.y += c.vy * speedMultiplier;

        // Wrap around
        if (c.x < -c.radius) c.x = canvas.width + c.radius;
        if (c.x > canvas.width + c.radius) c.x = -c.radius;
        if (c.y < -c.radius) c.y = canvas.height + c.radius;
        if (c.y > canvas.height + c.radius) n.y = -c.radius;
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    window.addEventListener('resize', resize);
    resize();
    draw();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, [speedMultiplier, palette]);

  return (
    <canvas 
      ref={canvasRef} 
      className="absolute inset-0 w-full h-full pointer-events-none z-[0]"
    />
  );
});

import React, { useState, useEffect, useMemo } from 'react';
import { Cube3D } from '../components/Cube3D';

interface LoadingScreenProps {
  backgroundUrl?: string;
  onFinished?: () => void;
}

export const LoadingScreen: React.FC<LoadingScreenProps> = ({ backgroundUrl, onFinished }) => {
  const [progress, setProgress] = useState(0);
  const [isAssembling, setIsAssembling] = useState(false);
  const letters = "LUMINA".split("");

  const technicolorColors = [
    "#D98A7F", // Coral
    "#9FAF90", // Sage
    "#D4AF37", // Mustard
    "#7B99A5", // Dusty Blue
    "#A3B18A", // Khaki Sage
    "#BC4749"  // Deep Coral
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return Math.min(prev + 0.8, 100);
      });
    }, 20);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (progress === 100) {
      const timer = setTimeout(() => {
        setIsAssembling(true);
        setTimeout(() => { if (onFinished) onFinished(); }, 1200);
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [progress, onFinished]);

  return (
    <div className="absolute inset-0 bg-[#262A2E] flex flex-col items-center justify-center p-8 overflow-hidden">

      {/* Background Painted Atmosphere */}
      <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')]" />
      <div className="absolute inset-[-100px] bg-[radial-gradient(circle_at_50%_50%,_#D4AF3722_0%,_transparent_60%)] animate-pulse" />

      {/* Mid-Century Embossed Logo */}
      <div className={`z-20 text-center mb-16 relative transition-all duration-1000 ${isAssembling ? 'opacity-0 scale-95 blur-md' : 'opacity-100'}`}>
        <h1 className="text-7xl font-[900] tracking-[0.3em] text-[#F2E9E1] embossed-text drop-shadow-[0_10px_0_rgba(0,0,0,0.3)]">
          LUMINA
        </h1>
        <p className="text-[#9FAF90] font-[900] text-[9px] tracking-[1em] mt-6 uppercase opacity-60">GEÇİT PROTOKOLÜ</p>
      </div>

      {/* Floating Matte Cubes */}
      <div className="relative w-80 h-80 mb-24 z-30 flex items-center justify-center">
        {letters.map((char, i) => {
          const orbitRotation = (progress * (1 + i * 0.1) + (i * 60));
          const orbitRadius = 110;

          const x = isAssembling ? (i - 2.5) * 50 : Math.cos(orbitRotation * Math.PI / 180) * orbitRadius;
          const y = isAssembling ? 0 : Math.sin(orbitRotation * Math.PI / 180) * orbitRadius;

          return (
            <div 
              key={i}
              className="absolute transition-all duration-[1000ms] ease-[cubic-bezier(0.34,1.56,0.64,1)]"
              style={{
                transform: `translate(${x}px, ${y}px)`,
                zIndex: isAssembling ? 100 : 10
              }}
            >
              <Cube3D 
                size={44} 
                speed={0} 
                label={char}
                visualStyle="GLASS"
                color={technicolorColors[i]}
              />
            </div>
          );
        })}
      </div>

      <div className={`w-full max-w-[240px] z-20 flex flex-col items-center transition-all duration-700 ${isAssembling ? 'opacity-0' : 'opacity-100'}`}>
        <div className="h-3 w-full bg-black/40 rounded-full overflow-hidden border-2 border-[#F2E9E1]/10 p-[2px] shadow-inner">
          <div 
            className="h-full bg-[#D4AF37] transition-all duration-300 ease-out rounded-full shadow-md"
            style={{ width: `${progress}%` }}
          />
        </div>
        <span className="text-[10px] font-[900] tracking-[0.5em] text-[#F2E9E1] uppercase mt-6 opacity-30">
          BAĞLANTI KURULUYOR
        </span>
      </div>
    </div>
  );
};

