import React, { useState, useMemo, useEffect, useRef } from 'react';
import { UserStats } from '../types';
import { Cube3D, CubeVisualStyle } from '../components/Cube3D';
import { SideMenu } from '../components/SideMenu';
import { ParticleBackground } from '../components/ParticleBackground';
import { Button } from '../components/Button';
import { SoundManager } from '../managers/SoundManager';
import { QuitConfirmationModal } from '../components/QuitConfirmationModal';

type RingStyle = 
  | 'STANDART' | 'BALERİN' | 'DÖNMEDOLAP' | 'ATLIKARINCA' | 'DEĞİRMEN'
  | 'DNA' | 'NABIZ' | 'SARKAÇ' | 'GİRDAP' | 'DALGA' 
  | 'SONSUZLUK' | 'KELEBEK' | 'FIRTINA' | 'SEKSEK' | 'KUŞAK'
  | 'MERCEK' | 'BASAMAK' | 'SİKLON' | 'PİRAMİT' | 'ZİGZAG' 
  | 'KASIRGA' | 'KARMAŞA' | 'TRAMPOLİN' | 'YOYO' | 'HALKALI' 
  | 'ÇAPRAZ' | 'ASANSÖR' | 'BOOMERANG' | 'LABİRENT'
  | 'KALEYDOSKOP' | 'KUANTUM' | 'SARMAN' | 'VALS';

// HARF VE SES BENZERLİĞİNE GÖRE OPTİMİZE EDİLMİŞ HAVUZ
const ALL_ROUNDS_POOL = [
  { target: "EVRENSEL", distractors: ["EYLEMSEL", "EVRİMSEL", "ERDEMSEL"] },
  { target: "GALAKSİ", distractors: ["GALAKTİK", "GALAKSİN", "GALAKSI"] },
  { target: "YILDIZLAR", distractors: ["YALDIZLAR", "YALNIZLAR", "YILDIRLAR"] },
  { target: "YÖRÜNGE", distractors: ["GÖRÜNGE", "SÜRÜNGE", "YÖRÜNGEL"] },
  { target: "GEZEGEN", distractors: ["GEREKEN", "GELECEK", "GÖZEGEN"] },
  { target: "ATMOSFER", distractors: ["ATMACACI", "ATLASLAR", "ATMOSFERİK"] },
  { target: "KRİSTAL", distractors: ["KARTELA", "KONTROL", "KRİSTİL"] },
  { target: "ELEMENT", distractors: ["EMANETİ", "ELAMETİ", "EKLEMENT"] },
  { target: "MOLEKÜL", distractors: ["MODÜLER", "MAMULLER", "MOLEKÜLER"] },
  { target: "FREKANS", distractors: ["FRAKSİYON", "FREKANSLI", "FREKANSIM"] },
  { target: "KİNETİK", distractors: ["GENETİK", "KİNETİKA", "KİNETİZM"] },
  { target: "PLAZMA", distractors: ["PRİZMA", "PULSAR", "PLAZMAY"] },
  { target: "AURORA", distractors: ["AVRUPA", "AVRORA", "AURORAL"] },
  { target: "SİNYAL", distractors: ["SİMSAR", "SİNYALİ", "SİNSİCE"] },
  { target: "SPEKTRUM", distractors: ["SPEKÜLER", "SPEKÜLÜM", "SPEKTROM"] },
  { target: "GRAVİTE", distractors: ["GRAVÜRE", "GRAVİTİ", "GRAVATLAR"] },
  { target: "PARTİKÜL", distractors: ["PATİKALI", "PARTİKÜLER", "PARTİKÜLÜ"] },
  { target: "NEBULA", distractors: ["PUSULA", "NEBULAR", "NEBÜLAS"] },
  { target: "VAKUM", distractors: ["BAKIM", "VAKUMU", "VAKUMLU"] },
  { target: "FOTON", distractors: ["KOTON", "FOTONİK", "FOTONU"] },
  { target: "RADYANT", distractors: ["VARYANT", "RADYAN", "RADYANTLI"] },
  { target: "REAKTÖR", distractors: ["REFAKAT", "REAKTİF", "REAKTÖRÜ"] },
  { target: "İVMELEME", distractors: ["İZLELEME", "İMGELEME", "İMLEMECE"] },
  { target: "HÜCRESEL", distractors: ["ZÜMRESEL", "SÜRESEL", "HÜCRESİ"] },
  { target: "MUTASYON", distractors: ["MOTİVASYON", "MUTASYONLU", "KUTASYON"] },
  { target: "İLETKEN", distractors: ["İZLENEN", "İLETİLEN", "İLETKENLİ"] },
  { target: "YALITKAN", distractors: ["YALITIM", "YALITLAN", "YALITKANS"] },
  { target: "GERİLİM", distractors: ["GERİLEYİŞ", "GERILEYİŞ", "GERİLİMLİ"] },
  { target: "ADAPTÖR", distractors: ["ADAPTASYON", "ADAPTİVE", "ADAPTÖRÜ"] },
  { target: "KARANLIK", distractors: ["KABARIK", "KARARLIK", "KARANLAK"] }
];

// Kelly Boesch Technicolor Palette
const COLORS = ["#7B99A5", "#D4AF37", "#D98A7F", "#9FAF90", "#A3B18A"];
const MEMORIZE_DURATION = 30; 
const BASE_ROUND_TIME = 10;
const STYLES: RingStyle[] = [
  'STANDART', 'BALERİN', 'DÖNMEDOLAP', 'ATLIKARINCA', 'DEĞİRMEN',
  'DNA', 'NABIZ', 'SARKAÇ', 'GİRDAP', 'DALGA',
  'SONSUZLUK', 'KELEBEK', 'FIRTINA', 'SEKSEK', 'KUŞAK',
  'MERCEK', 'BASAMAK', 'SİKLON', 'PİRAMİT', 'ZİGZAG',
  'KASIRGA', 'KARMAŞA', 'TRAMPOLİN', 'YOYO', 'HALKALI',
  'ÇAPRAZ', 'ASANSÖR', 'BOOMERANG', 'LABİRENT',
  'KALEYDOSKOP', 'KUANTUM', 'SARMAN', 'VALS'
];

const VISUAL_STYLES: CubeVisualStyle[] = ['GLASS', 'CRYSTAL', 'METAL', 'NEON', 'GHOST', 'DARK', 'PLASMA', 'CHROME', 'LAVA', 'AETHER', 'VOID'];

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void; onUpdateStats: (s: Partial<UserStats>) => void }> = ({ stats, onComplete, onExit, onUpdateStats }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);

  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [rotationOffset, setRotationOffset] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [revealedIndex, setRevealedIndex] = useState(-1);
  const [roundResults, setRoundResults] = useState<( 'success' | 'fail' | null)[]>(new Array(5).fill(null));
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showQuitModal, setShowQuitModal] = useState(false);
  const [comboCount, setComboCount] = useState(0);

  const [showHintMenu, setShowHintMenu] = useState(false);
  const [isTimeFrozen, setIsTimeFrozen] = useState(false);
  const [hintUsedThisRound, setHintUsedThisRound] = useState(false);
  const [firstLetterFlash, setFirstLetterFlash] = useState(false);

  const timerRef = useRef<number | null>(null);

  const currentStyle = useMemo(() => {
    const randomIndex = Math.floor(Math.random() * STYLES.length);
    return STYLES[randomIndex];
  }, [currentRound]);

  const currentCubeVisualStyle = useMemo(() => {
    const pool = stats.difficultyFactor > 1.5 
      ? ['LAVA', 'VOID', 'PLASMA', 'NEON', 'CHROME'] 
      : VISUAL_STYLES;
    const randomIndex = Math.floor(Math.random() * pool.length);
    return pool[randomIndex] as CubeVisualStyle;
  }, [currentRound, stats.difficultyFactor]);

  const puzzleRounds = useMemo(() => {
    const minLength = stats.difficultyFactor > 1.6 ? 7 : stats.difficultyFactor > 1.2 ? 5 : 3;
    const filteredPool = ALL_ROUNDS_POOL.filter(item => item.target.length >= minLength);
    return [...filteredPool].sort(() => Math.random() - 0.5).slice(0, 5);
  }, [stats.difficultyFactor]);

  const activeRoundData = puzzleRounds[currentRound];

  // 4 SEÇENEK: 1 Hedef + 3 Hazırlanmış Benzer Çeldirici
  const activeOptions = useMemo(() => {
    const target = activeRoundData.target;
    const distractors = activeRoundData.distractors;

    // Her zaman hedef ve ona en yakın 3 çeldiriciyi karıştırarak ver
    return [target, ...distractors].sort(() => Math.random() - 0.5);
  }, [activeRoundData]);

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || isMenuOpen || isTransitioning || showQuitModal) return;

    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if ((isTimeFrozen || showHintMenu) && gamePhase === 'MEMORIZE') return prev;

        const nextTime = prev - 0.05;

        if (gamePhase === 'MEMORIZE' && !hintUsedThisRound && Math.abs(nextTime - 15) < 0.03 && !showHintMenu) {
            setShowHintMenu(true);
            SoundManager.getInstance().playPop();
        }

        if (gamePhase === 'MEMORIZE' && nextTime <= 0) {
          setGamePhase('GUESS');
          SoundManager.getInstance().playPop();
          return dynamicRoundTime;
        }
        if (gamePhase === 'GUESS' && nextTime <= 0) {
          handleChoice("TIME_UP");
          return dynamicRoundTime;
        }
        return nextTime;
      });

      if (gamePhase === 'MEMORIZE') {
        if (!isTimeFrozen && !showHintMenu) {
            setRotationOffset(prev => prev + (0.6 * stats.difficultyFactor));
        }
      }
    }, 50);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [choiceStatus, selectedChoice, isMenuOpen, isTransitioning, currentRound, showQuitModal, dynamicRoundTime, stats.difficultyFactor, gamePhase, isTimeFrozen, hintUsedThisRound, showHintMenu]);

  useEffect(() => {
    if (choiceStatus === 'success') {
      let currentIdx = 0;
      const interval = setInterval(() => {
        setRevealedIndex(currentIdx);
        currentIdx++;
        if (currentIdx >= activeRoundData.target.length) {
          clearInterval(interval);
        }
      }, 150);
      return () => clearInterval(interval);
    } else {
      setRevealedIndex(-1);
    }
  }, [choiceStatus, activeRoundData.target]);

  const handleSkipMemorize = () => {
    if (gamePhase === 'MEMORIZE' && !isTransitioning) {
      setGamePhase('GUESS');
      setTimeLeft(dynamicRoundTime);
      SoundManager.getInstance().playPop();
    }
  };

  const useHint = (type: 'FREEZE' | 'REVEAL_FIRST' | 'NONE') => {
    if (hintUsedThisRound) return;

    if (type === 'FREEZE') {
      if (stats.hintsFreeze <= 0) return;
      onUpdateStats({ hintsFreeze: stats.hintsFreeze - 1 });
      SoundManager.getInstance().playCoin();
      setIsTimeFrozen(true);
      setTimeout(() => setIsTimeFrozen(false), 5000);
    } else if (type === 'REVEAL_FIRST') {
      if (stats.hintsReveal <= 0) return;
      onUpdateStats({ hintsReveal: stats.hintsReveal - 1 });
      SoundManager.getInstance().playCoin();
      setFirstLetterFlash(true);
      setTimeout(() => setFirstLetterFlash(false), 4000);
    } else {
      SoundManager.getInstance().playClick();
    }

    setHintUsedThisRound(true);
    setShowHintMenu(false);
  };

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle' || isTransitioning) return;
    setSelectedChoice(choice);
    setShowHintMenu(false);
    setTimeout(() => {
      const isCorrect = choice === activeRoundData.target;
      if (isCorrect) {
        SoundManager.getInstance().playSuccess();
        setComboCount(prev => prev + comboCount > 10 ? 0 : 1);
      } else {
        if (choice !== "TIME_UP") SoundManager.getInstance().playFail();
        setComboCount(0);
      }
      const points = Math.floor((100 + timeLeft * 10) * (1 + (comboCount * 0.1)));
      const nextResults = [...roundResults];
      setChoiceStatus(isCorrect ? 'success' : 'fail');
      nextResults[currentRound] = isCorrect ? 'success' : 'fail';
      const nextScore = isCorrect ? sessionScore + points : Math.max(0, sessionScore - 50);
      setSessionScore(nextScore);
      const delay = isCorrect ? (activeRoundData.target.length * 150 + 1000) : 1000;
      setTimeout(() => {
        setIsTransitioning(true);
        setTimeout(() => {
          if (currentRound === puzzleRounds.length - 1) {
            // Fix: Use flatMap to ensure a flat string[] for distractors
            onComplete(nextScore, puzzleRounds.map(r => r.target), puzzleRounds.flatMap(r => r.distractors));
          } else {
            setCurrentRound(prev => prev + 1);
            setTimeLeft(MEMORIZE_DURATION);
            setGamePhase('MEMORIZE');
            setChoiceStatus('idle');
            setSelectedChoice(null);
            setRevealedIndex(-1);
            setRoundResults(nextResults);
            setIsTransitioning(false);
            setHintUsedThisRound(false);
            setIsTimeFrozen(false);
            setFirstLetterFlash(false);
          }
        }, 400);
      }, delay);
    }, 600); 
  };

  const ringItems = useMemo(() => {
    return activeRoundData.target.split("").map((char, i) => ({
      char,
      color: COLORS[i % COLORS.length]
    }));
  }, [activeRoundData]);

  const renderRing = () => {
    const dist = 120; 
    const isSuccess = choiceStatus === 'success';
    const screenWidth = typeof window !== 'undefined' ? window.innerWidth : 360;
    const safeContainerWidth = screenWidth * 0.85;
    const dynamicSpacing = Math.min(52, safeContainerWidth / Math.max(1, ringItems.length - 0.5));
    const dynamicCubeSize = Math.min(58, dynamicSpacing * 1.2);
    const cubeAnimSpeed = 4 / stats.difficultyFactor;

    return (
      <div 
        className={`relative w-full h-full flex items-center justify-center transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-75 blur-lg' : 'opacity-100 scale-100'}`} 
        style={{ transformStyle: 'preserve-3d' }}
      >
        {ringItems.map((item, idx) => {
          const angle = (idx / ringItems.length) * 360 + rotationOffset;
          const rad = (angle * Math.PI) / 180;
          let x = 0, y = 0, z = 0, rotX = 0, rotY = 0, rotZ = 0, scale = 1;

          if (isSuccess) {
            x = (idx - (ringItems.length - 1) / 2) * dynamicSpacing;
            y = 0; z = 20; scale = 1.1 + (revealedIndex === idx ? 0.15 : 0);
          } else {
             switch (currentStyle) {
              case 'BALERİN': x = Math.cos(rad) * dist; y = Math.sin(rotationOffset * 0.05) * 20; z = Math.sin(rad) * dist; rotY = rotationOffset * 2; break;
              case 'DÖNMEDOLAP': x = Math.cos(rad) * dist; y = Math.sin(rad) * dist; z = 0; rotZ = -angle; break;
              case 'ATLIKARINCA': x = Math.cos(rad) * dist; y = Math.sin(rotationOffset * 0.1 + idx) * 30; z = Math.sin(rad) * dist; break;
              case 'DNA': x = Math.cos(rad) * dist; y = Math.sin(rad * 2 + rotationOffset * 0.1) * 40; z = Math.sin(rad) * dist; rotY = angle; break;
              default: x = Math.cos(rad) * dist; y = Math.sin(rad) * dist; z = 0; break;
             }
          }

          const isFlashing = firstLetterFlash && idx === 0;

          return (
            <div key={`${currentRound}-${idx}`} className={`absolute transition-all duration-300 ease-out ${isFlashing ? 'animate-pulse' : ''}`} style={{ transform: `translate3d(${x}px, ${y}px, ${z}px) rotateX(${rotX}deg) rotateY(${rotY}deg) rotateZ(${rotZ}deg) scale(${scale})`, transformStyle: 'preserve-3d', zIndex: (revealedIndex === idx) ? 300 : 20 }}>
              <Cube3D size={isSuccess ? dynamicCubeSize : 58} label={gamePhase === 'GUESS' && !isSuccess ? '?' : item.char} color={isFlashing ? '#ffffff' : item.color} visualStyle={isFlashing ? 'NEON' : currentCubeVisualStyle} status={choiceStatus} isRevealed={true} delay={idx * 0.05} speed={(isSuccess || gamePhase === 'GUESS' || (isTimeFrozen && gamePhase === 'MEMORIZE') || showHintMenu) ? 0 : cubeAnimSpeed} />
            </div>
          );
        })}
      </div>
    );
  };

  const barMax = gamePhase === 'MEMORIZE' ? MEMORIZE_DURATION : dynamicRoundTime;
  const isHintPhase = gamePhase === 'MEMORIZE' && timeLeft <= 15.1 && !hintUsedThisRound;

  const renderChoiceContent = (opt: string) => {
    if (gamePhase === 'MEMORIZE') {
      return (
        <div className="flex items-center justify-center opacity-30 animate-pulse">
           <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="3">
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
           </svg>
        </div>
      );
    }
    return opt;
  };

  return (
    <div className="absolute inset-0 bg-[#262A2E] flex flex-col overflow-hidden">
      <ParticleBackground speedMultiplier={choiceStatus === 'success' ? 0.05 : 0.25 * stats.difficultyFactor} />
      {/* Paper grain overlay */}
      <div className="absolute inset-0 opacity-[0.12] mix-blend-multiply bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] pointer-events-none z-[5]" />

      <div className={`fixed inset-0 z-[250] bg-black/20 backdrop-blur-lg transition-opacity duration-500 pointer-events-none ${isMenuOpen || showHintMenu ? 'opacity-100' : 'opacity-0'}`} />

      <div className={`pt-10 px-8 flex justify-between items-start z-20 ${isMenuOpen || choiceStatus !== 'idle' ? 'opacity-0' : 'opacity-100'} transition-opacity duration-500 shrink-0`}>
        <div className="flex flex-col gap-2">
          <div className="flex gap-1.5 p-2 bg-black/40 backdrop-blur-2xl rounded-xl border border-white/10 shadow-2xl">
            {roundResults.map((res, i) => (
              <div key={i} className={`w-3 h-3 rounded-md border-2 transition-all duration-500 ${res === 'success' ? 'bg-[#9FAF90] border-white shadow-[0_0_8px_#9FAF90]' : res === 'fail' ? 'bg-[#D98A7F] border-white shadow-[0_0_8px_#D98A7F]' : i === currentRound ? 'bg-[#7B99A5] border-white animate-pulse' : 'bg-white/10 border-white/10'}`} />
            ))}
          </div>
          <span className="text-[8px] font-[900] text-[#7B99A5] tracking-[0.2em] uppercase mt-0.5 ml-1">{gamePhase === 'MEMORIZE' ? 'ODAKLAN!' : `${currentStyle} MODU`}</span>
        </div>
        <div className="text-3xl font-[900] text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.4)]">{sessionScore.toLocaleString()}</div>
      </div>

      <div className={`flex-1 relative flex items-center justify-center perspective-[1200px] z-10 min-h-0 transition-all duration-500 ${isMenuOpen || showHintMenu ? 'blur-sm brightness-50' : ''}`}>{renderRing()}</div>

      {gamePhase === 'MEMORIZE' && !isTransitioning && (
        <div className="fixed right-6 bottom-24 z-[300] animate-[popIn_0.5s_cubic-bezier(0.34,1.56,0.64,1)]">
          <div className={`absolute bottom-full left-0 right-0 mb-4 flex flex-col gap-2 transition-all duration-500 origin-bottom ${showHintMenu ? 'scale-100 opacity-100 translate-y-0' : 'scale-0 opacity-0 translate-y-10 pointer-events-none'}`}>
            <button onClick={() => useHint('FREEZE')} className={`w-full bg-[#7B99A5] border-b-[6px] border-[#4A5E68] rounded-2xl py-3 px-4 flex items-center justify-between active:translate-y-1 active:border-b-0 transition-all shadow-xl ${stats.hintsFreeze <= 0 ? 'grayscale opacity-50' : ''}`}>
              <div className="flex items-center gap-2">
                <span className="text-xl">❄️</span>
                <span className="text-[10px] font-black text-slate-900 uppercase">DONDUR</span>
              </div>
              <span className="bg-white/30 px-2 py-0.5 rounded-lg text-[9px] font-black text-white">{stats.hintsFreeze}</span>
            </button>
            <button onClick={() => useHint('REVEAL_FIRST')} className={`w-full bg-[#D4AF37] border-b-[6px] border-[#8C7424] rounded-2xl py-3 px-4 flex items-center justify-between active:translate-y-1 active:border-b-0 transition-all shadow-xl ${stats.hintsReveal <= 0 ? 'grayscale opacity-50' : ''}`}>
              <div className="flex items-center gap-2">
                <span className="text-xl">🎯</span>
                <span className="text-[10px] font-black text-amber-900 uppercase tracking-tighter">BAŞ HARF</span>
              </div>
              <span className="bg-white/30 px-2 py-0.5 rounded-lg text-[9px] font-black text-white">{stats.hintsReveal}</span>
            </button>
            <button onClick={() => useHint('NONE')} className="w-full bg-[#D98A7F] border-b-[6px] border-[#8C4F48] rounded-2xl py-2 px-3 flex items-center gap-1.5 active:translate-y-1 active:border-b-0 transition-all shadow-xl overflow-hidden">
              <span className="text-base shrink-0">❌</span>
              <span className="text-[8px] font-[900] text-red-950 uppercase tracking-tighter leading-none">İSTEMİYORUM</span>
            </button>
          </div>

          <button onClick={isHintPhase ? () => setShowHintMenu(!showHintMenu) : handleSkipMemorize} className="group relative w-32 h-24 flex items-center justify-center transition-all active:scale-95">
            <div className={`absolute inset-0 blur-3xl rounded-full animate-pulse scale-110 pointer-events-none ${isHintPhase || showHintMenu ? 'bg-[#D4AF37]/40' : 'bg-[#7B99A5]/40'}`} />
            <div className={`relative w-full h-full bg-[#262A2E]/95 border-[4px] border-b-[12px] rounded-[32px] flex flex-col items-center justify-center shadow-2xl active:border-b-[4px] active:translate-y-2 transition-all ${isHintPhase || showHintMenu ? 'border-[#D4AF37]/50 border-b-[#8C7424]' : 'border-[#7B99A5]/50 border-b-[#4A5E68]'}`}>
               <span className="text-[17px] font-[900] text-[#F2E9E1] tracking-widest uppercase z-10 embossed-text">{isHintPhase || showHintMenu ? 'İPUCU' : 'BULDUM'}</span>
            </div>
          </button>
        </div>
      )}

      <div className={`px-6 pb-10 flex flex-col gap-5 z-20 transition-all duration-700 shrink-0 ${isTransitioning || choiceStatus === 'success' ? 'opacity-0 translate-y-20 scale-95 pointer-events-none' : 'opacity-100 translate-y-0 scale-100'} ${isMenuOpen || showHintMenu ? 'blur-sm pointer-events-none' : ''}`}>
        <div className="w-full h-2.5 bg-black/60 rounded-full overflow-hidden relative border border-white/5 shadow-inner p-[1.5px]">
          <div className="h-full relative transition-all duration-300 rounded-full" style={{ width: `${(timeLeft / barMax) * 100}%`, backgroundColor: gamePhase === 'MEMORIZE' ? '#7B99A5' : '#D4AF37', boxShadow: `0 0 25px rgba(123,153,165,0.4)` }} />
        </div>

        <div className="grid grid-cols-2 gap-3">
          {activeOptions.map((opt, i) => (
            <Button 
              key={i} 
              variant={(selectedChoice === opt) ? (choiceStatus === 'success' ? 'green' : 'pink') : (['indigo', 'pink', 'amber', 'cyan'][i % 4] as any)} 
              onClick={() => handleChoice(opt)} 
              className={`w-full !h-24 !rounded-[32px] !text-[22px] !border-b-[10px] active:!border-b-[2px] transition-all duration-300 ${(selectedChoice !== null && selectedChoice !== opt) ? 'opacity-20 scale-90 blur-[2px]' : ''} ${gamePhase === 'MEMORIZE' ? 'pointer-events-none grayscale opacity-40' : ''}`} 
              disabled={selectedChoice !== null || (gamePhase !== 'GUESS' && gamePhase !== 'MEMORIZE')}
            >
              <span className="truncate w-full px-2 leading-none">{renderChoiceContent(opt)}</span>
            </Button>
          ))}
        </div>
      </div>

      <div className="fixed right-2 bottom-2 z-[300]"><SideMenu onExit={() => setShowQuitModal(true)} onToggle={setIsMenuOpen} isMinimal={true} expandDirection="up" /></div>
      {showQuitModal && <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, UserStats, HubSubView } from './types';
import { LoadingScreen } from './screens/LoadingScreen';
import { HubScreen } from './screens/HubScreen';
import { MemoryGame } from './screens/MemoryGame';
import { WordPuzzle } from './screens/WordPuzzle';
import { LevelCompleteModal } from './components/LevelCompleteModal';
import { LevelFailModal } from './components/LevelFailModal';
import { ChestModal } from './components/ChestModal';
import { MemoryTransitionModal } from './components/MemoryTransitionModal';
import { auth, fetchCloudStats, syncUserStats, reconcileStats } from './lib/firebase.ts';
import { onAuthStateChanged, User } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

const STORAGE_KEY = 'lumina_stats';
const DEFAULT_BG = "https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&q=80&w=1080&h=1920";
const MISSIONS_REFRESH_INTERVAL = 24 * 60 * 60 * 1000;

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.LOADING);
  const [hubSubView, setHubSubView] = useState<HubSubView>(HubSubView.MAIN);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { console.error(e); }
    }
    return {
      coins: 2063, hearts: 5, stars: 12, level: 1,
      lastLifeRefillTime: Date.now(),
      hintsFreeze: 3, hintsReveal: 3,
      claimedMissions: [],
      lastMissionsRefresh: Date.now(),
      difficultyFactor: 1.0, performanceHistory: [],
      streak: 0, maxStreak: 0
    };
  });

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      setCurrentUser(user);
      if (user) {
        setIsSyncing(true);
        const cloudData = await fetchCloudStats(user.uid);
        if (cloudData) {
          const merged = reconcileStats(stats, cloudData);
          setStats(merged);
        }
        setIsSyncing(false);
      }
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stats));
    if (currentUser) {
      const timeout = setTimeout(async () => {
        setIsSyncing(true);
        await syncUserStats(currentUser.uid, stats, currentUser.displayName || "", currentUser.photoURL || "");
        setIsSyncing(false);
      }, 2000);
      return () => clearTimeout(timeout);
    }
  }, [stats, currentUser]);

  useEffect(() => {
    const now = Date.now();
    if (now - stats.lastMissionsRefresh >= MISSIONS_REFRESH_INTERVAL) {
      setStats(prev => ({
        ...prev,
        claimedMissions: [],
        lastMissionsRefresh: now
      }));
    }
  }, [stats.lastMissionsRefresh]);

  const [targetWords, setTargetWords] = useState<string[]>([]);
  const [fullWordPool, setFullWordPool] = useState<string[]>([]);
  const [showChest, setShowChest] = useState(false);
  const [bonusEarned, setBonusEarned] = useState(0);
  const [sessionScore, setSessionScore] = useState(0);
  const [starsEarnedInLevel, setStarsEarnedInLevel] = useState(0);
  const [transitionState, setTransitionState] = useState<'idle' | 'animating'>('idle');

  const changeGameState = (newState: GameState) => {
    setTransitionState('animating');
    setTimeout(() => {
      setGameState(newState);
      setTransitionState('idle');
    }, 300);
  };

  const updateStats = (updates: Partial<UserStats>) => {
    setStats(prev => ({ ...prev, ...updates }));
  };

  const handleClaimMission = (id: number, reward: number) => {
    updateStats({
      coins: stats.coins + reward,
      claimedMissions: [...stats.claimedMissions, id]
    });
  };

  const handleStartGame = () => {
    if (stats.hearts > 0) {
      setSessionScore(0);
      changeGameState(GameState.WORD_PUZZLE);
    } else {
      setHubSubView(HubSubView.SHOP);
    }
  };

  const handleExitWithPenalty = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.HUB);
  };

  const handlePuzzleComplete = (earned: number, allTargets: string[], allDistractors: string[]) => {
    setSessionScore(earned);
    setTargetWords(allTargets);
    const pooledWords = [...allTargets, ...allDistractors].sort(() => Math.random() - 0.5);
    setFullWordPool(pooledWords);
    changeGameState(GameState.MEMORY_PREPARE);
  };

  const handleGameComplete = (correctCount: number) => {
    let stars = correctCount === 5 ? 3 : correctCount >= 4 ? 2 : 1;
    let bonus = correctCount * 50;
    setStarsEarnedInLevel(stars);
    setBonusEarned(bonus);
    changeGameState(GameState.LEVEL_COMPLETE);
  };

  const handleLevelFail = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.LEVEL_FAIL);
  };

  const handleBuyItem = (cost: number, type: 'HEART' | 'FREEZE' | 'REVEAL', amount: number) => {
    if (stats.coins < cost) return;
    setStats(prev => {
      const next = { ...prev, coins: prev.coins - cost };
      if (type === 'HEART') next.hearts = Math.min(5, prev.hearts + amount);
      if (type === 'FREEZE') next.hintsFreeze += amount;
      if (type === 'REVEAL') next.hintsReveal += amount;
      return next;
    });
  };

  const renderScreen = () => {
    switch (gameState) {
      case GameState.LOADING: return <LoadingScreen onFinished={() => changeGameState(GameState.HUB)} />;
      case GameState.HUB: return <HubScreen stats={stats} currentUser={currentUser} isSyncing={isSyncing} hubSubView={hubSubView} setHubSubView={setHubSubView} onStartGame={handleStartGame} onAddCoins={(amt) => updateStats({ coins: stats.coins + amt })} onBuyHearts={(c, a) => handleBuyItem(c, 'HEART', a)} onOpenChest={() => setShowChest(true)} onClaimMission={handleClaimMission} />;
      case GameState.WORD_PUZZLE: return <WordPuzzle stats={stats} onComplete={handlePuzzleComplete} onExit={handleExitWithPenalty} onUpdateStats={updateStats} />;
      case GameState.MEMORY_PREPARE: return <MemoryTransitionModal onConfirm={() => changeGameState(GameState.MEMORY_GAME)} onExit={handleExitWithPenalty} />;
      case GameState.MEMORY_GAME: return <MemoryGame stats={stats} backgroundUrl={DEFAULT_BG} words={fullWordPool} targetWords={targetWords} onNext={handleGameComplete} onFail={handleLevelFail} onExit={handleExitWithPenalty} initialScore={sessionScore} />;
      case GameState.LEVEL_COMPLETE: return <LevelCompleteModal level={stats.level} coinsEarned={sessionScore + bonusEarned} starsEarned={starsEarnedInLevel} onContinue={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); handleStartGame(); }} onMenu={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); changeGameState(GameState.HUB); }} />;
      case GameState.LEVEL_FAIL: return <LevelFailModal hearts={stats.hearts} lastLifeRefillTime={stats.lastLifeRefillTime} onRetry={() => { if(stats.hearts > 0) changeGameState(GameState.WORD_PUZZLE); else setHubSubView(HubSubView.SHOP); }} onShop={() => { changeGameState(GameState.HUB); setHubSubView(HubSubView.SHOP); }} onExit={() => changeGameState(GameState.HUB)} />;
      default: return <LoadingScreen />;
    }
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-[#262A2E] overflow-hidden select-none">
      <div className={`w-full h-full transition-all duration-500 ease-out ${transitionState === 'animating' ? 'opacity-0 scale-95 blur-md' : 'opacity-100 scale-100'}`}>
        {renderScreen()}
        {showChest && <ChestModal onClose={() => setShowChest(false)} onReward={(amt) => updateStats({ coins: stats.coins + amt })} />}
      </div>
      {/* Global high grain paper print overlay for surreal Boesch atmosphere */}
      <div className="fixed inset-0 pointer-events-none opacity-[0.08] mix-blend-multiply bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] z-[999]" />
    </div>
  );
};

export default App;

