];

const VISUAL_STYLES: CubeVisualStyle[] = ['GLASS', 'CRYSTAL', 'METAL', 'NEON', 'GHOST', 'DARK', 'PLASMA', 'CHROME', 'LAVA', 'AETHER', 'VOID'];

export const MemoryGame: React.FC<MemoryGameProps> = ({ stats, words, targetWords, onNext, onFail, onExit }) => {
  const [selected, setSelected] = useState<Set<number>>(new Set());
  const [isRevealing, setIsRevealing] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [results, setResults] = useState<boolean[]>([]);
  const [showQuitModal, setShowQuitModal] = useState(false);

  const currentCubeVisualStyle = useMemo(() => {
    const randomIndex = Math.floor(Math.random() * VISUAL_STYLES.length);
    return VISUAL_STYLES[randomIndex];
  }, [words]);

  const displayWords = useMemo(() => words.map((word, i) => ({ 
    word, 
    color: GEÇİT_PALETİ[i % 5], 
    pos: GRID_POSITIONS[i % 10] 
  })), [words]);

  const correctIndices = useMemo(() => new Set(displayWords.map((item, i) => targetWords.includes(item.word) ? i : -1).filter(i => i !== -1)), [displayWords, targetWords]);

  const handleWordClick = (i: number) => {
    if (isRevealing || isMenuOpen) return;
    SoundManager.getInstance().playPop();
    setSelected(prev => {
      const n = new Set(prev);
      if (n.has(i)) n.delete(i); else if (n.size < 5) n.add(i);
      return n;
    });
  };

  const handleSubmit = () => {
    if (selected.size < 5 || isRevealing || isMenuOpen) return;
    setIsRevealing(true);

    const res: boolean[] = [];
    let correct = 0;

    const selectedIndices = Array.from(selected);
    selectedIndices.forEach(idx => {
      const isCorrect = correctIndices.has(idx);
      res.push(isCorrect);
      if (isCorrect) correct++;
    });

    setResults(res);

    if (correct >= 3) SoundManager.getInstance().playSuccess();
    else SoundManager.getInstance().playFail();

    setTimeout(() => {
      if (correct >= 3) {
        onNext(correct);
      } else {
        onFail();
        setIsRevealing(false);
        setSelected(new Set());
        setResults([]);
      }
    }, 2500);
  };

  return (
    <div className="absolute inset-0 bg-[#262A2E] flex flex-col overflow-hidden">
      <ParticleBackground speedMultiplier={0.3 * stats.difficultyFactor} level={stats.level} />
      {/* Paper grain overlay */}
      <div className="absolute inset-0 opacity-[0.12] mix-blend-multiply bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] pointer-events-none z-[5]" />

      <div 
        className={`fixed inset-0 z-[250] bg-black/20 backdrop-blur-lg transition-opacity duration-500 pointer-events-none ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} 
      />

      <div className={`z-40 pt-10 px-8 flex flex-col items-center gap-6 shrink-0 transition-all duration-500 ${isMenuOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
        <div className="bg-black/60 backdrop-blur-3xl border-[3px] border-white/10 px-6 py-3 rounded-[28px] shadow-2xl flex flex-col items-center border-b-[5px] border-b-[#0f172a]">
            <span className="text-[9px] font-[900] text-[#7B99A5] tracking-[0.5em] uppercase opacity-60 mb-1.5">HAFIZA GEÇİDİ</span>
            <div className="flex gap-3">
                {[0,1,2,3,4].map(i => {
                  const isSel = selected.size > i;
                  const res = results[i];
                  let dotClass = isSel ? 'bg-[#7B99A5] shadow-[0_0_12px_#7B99A5]' : 'bg-white/5 border border-white/10';
                  if (isRevealing && res !== undefined) dotClass = res ? 'bg-[#9FAF90] shadow-[0_0_15px_#9FAF90] border-white' : 'bg-[#D98A7F] border-white';
                  return <div key={i} className={`w-4 h-4 rounded-md border-2 transition-all duration-700 ${dotClass} ${isRevealing && res ? 'animate-pulse' : ''}`} />;
                })}
            </div>
        </div>
      </div>

      <div className={`flex-1 relative z-10 perspective-[2000px] min-h-0 transition-all duration-500 ${isMenuOpen ? 'blur-md brightness-50' : ''}`}>
          {displayWords.map((item, i) => {
            const isSel = selected.has(i);
            const isCorrect = correctIndices.has(i);

            return (
              <div 
                key={i} 
                onClick={() => handleWordClick(i)}
                style={{ 
                  position: 'absolute', 
                  top: item.pos.t, 
                  left: item.pos.l, 
                  transform: 'translate(-50%, -50%)', 
                  zIndex: isSel ? 200 : 10 + i,
                  willChange: 'transform',
                  padding: '8px' 
                }}
                className={`transition-all duration-700 opacity-100 ${isRevealing && !isSel ? 'pointer-events-none' : ''}`}
              >
                <Cube3D 
                  width={120} 
                  height={58}
                  depth={32} 
                  label={item.word} 
                  color={item.color.bg} 
                  isSelected={isSel}
                  visualStyle={currentCubeVisualStyle}
                  status={isRevealing && isSel ? (isCorrect ? 'success' : 'fail') : 'idle'}
                  speed={selected.size >= 5 || isRevealing ? 0 : 3.5} 
                  rotationAxis="X" 
                  delay={i * 0.05}
                />
              </div>
            );
          })}
      </div>

      <div className={`px-10 pb-10 z-[100] mt-auto shrink-0 transition-all duration-500 ${isMenuOpen ? 'blur-md pointer-events-none' : 'opacity-100'}`}>
        <Button 
          variant={selected.size >= 5 ? "green" : "cyan"}
          onClick={handleSubmit} 
          disabled={selected.size < 5 || isRevealing} 
          className="w-full !py-6 !text-3xl !rounded-[40px] !border-b-[12px] shadow-2xl active:!border-b-[3px] active:!translate-y-2 transition-all tracking-widest"
        >
          {isRevealing ? 'DOĞRULANIYOR...' : 'GEÇİDİ AÇ'}
        </Button>
      </div>

      <div className="fixed right-4 bottom-4 z-[300]">
        <SideMenu onExit={() => setShowQuitModal(true)} onToggle={setIsMenuOpen} isMinimal={true} expandDirection="up" />
      </div>

      {showQuitModal && <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />}
    </div>
  );
};

