import React, { useEffect, useRef, memo, useMemo } from 'react';

interface ParticleBackgroundProps {
  speedMultiplier?: number;
  level?: number;
}

// Kelly Boesch Palette
const PALETTE = ['#D98A7F', '#9FAF90', '#D4AF37', '#7B99A5'];

export const ParticleBackground: React.FC<ParticleBackgroundProps> = memo(({ speedMultiplier = 1, level = 1 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const themeColor = useMemo(() => {
    return PALETTE[level % PALETTE.length];
  }, [level]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    // Collage Elements
    let elements: Array<{
      x: number;
      y: number;
      size: number;
      type: 'DOT' | 'STAIN';
      vx: number;
      vy: number;
      alpha: number;
      rotation: number;
      rotV: number;
    }> = [];

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      init();
    };

    const init = () => {
      elements = [];

      // Vintage Dots (Strategically placed points)
      for (let i = 0; i < 20; i++) {
        elements.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          size: Math.random() * 4 + 2,
          type: 'DOT',
          vx: (Math.random() - 0.5) * 0.05,
          vy: (Math.random() - 0.5) * 0.05,
          alpha: Math.random() * 0.4 + 0.1,
          rotation: 0,
          rotV: 0
        });
      }

      // Paper Stains (Large soft strokes)
      for (let i = 0; i < 3; i++) {
        elements.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          size: Math.random() * (canvas.width * 0.6) + 200,
          type: 'STAIN',
          vx: (Math.random() - 0.5) * 0.02,
          vy: (Math.random() - 0.5) * 0.02,
          alpha: 0.08,
          rotation: Math.random() * Math.PI,
          rotV: (Math.random() - 0.5) * 0.001
        });
      }
    };

    const draw = () => {
      ctx.fillStyle = '#F2E9E1'; // Base Paper
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      elements.forEach((e) => {
        ctx.save();
        ctx.translate(e.x, e.y);
        ctx.rotate(e.rotation);

        if (e.type === 'DOT') {
          ctx.beginPath();
          ctx.arc(0, 0, e.size, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(38, 42, 46, ${e.alpha})`; // Dark Grey Matte
          ctx.fill();
        } else {
          // Soft Painted Stroke/Stain
          const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, e.size);
          grad.addColorStop(0, `${themeColor}${Math.floor(e.alpha * 255).toString(16).padStart(2, '0')}`);
          grad.addColorStop(1, 'transparent');
          ctx.fillStyle = grad;
          ctx.fillRect(-e.size, -e.size, e.size * 2, e.size * 2);
        }

        ctx.restore();

        e.x += e.vx * speedMultiplier;
        e.y += e.vy * speedMultiplier;
        e.rotation += e.rotV * speedMultiplier;

        // Wrap
        if (e.x < -e.size) e.x = canvas.width + e.size;
        if (e.x > canvas.width + e.size) e.x = -e.size;
        if (e.y < -e.size) e.y = canvas.height + e.size;
        if (e.y > canvas.height + e.size) e.y = -e.size;
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    window.addEventListener('resize', resize);
    resize();
    draw();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, [speedMultiplier, themeColor]);

  return (
    <div className="absolute inset-0 w-full h-full pointer-events-none z-[0] overflow-hidden">
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full" />
      {/* High grain overlay */}
      <div className="absolute inset-0 opacity-[0.25] mix-blend-multiply bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')]" />
    </div>
  );
});

