      </span>
      <div className="absolute inset-0 border border-white/5 rounded-[24px] pointer-events-none" />
    </button>
  );
};

import React, { memo } from 'react';

export type RotationAxis = 'X' | 'Y' | 'XY' | 'TUMBLE';
export type CubeVisualStyle = 'GLASS' | 'CRYSTAL' | 'METAL' | 'NEON' | 'GHOST' | 'DARK' | 'PLASMA' | 'CHROME' | 'LAVA' | 'AETHER' | 'VOID' | 'FLASHCARD';

interface Cube3DProps {
  size?: number;
  width?: number; 
  height?: number; 
  depth?: number; 
  className?: string;
  speed?: number;
  opacity?: number;
  label?: string;
  centerLabel?: string; 
  faceLabels?: string[]; 
  isGlassy?: boolean;
  color?: string;
  rotationAxis?: RotationAxis;
  visualStyle?: CubeVisualStyle;
  status?: 'idle' | 'success' | 'fail';
  delay?: number;
  isRevealed?: boolean;
  isSelected?: boolean;
}

export const Cube3D: React.FC<Cube3DProps> = memo(({ 
  size = 32,
  width,
  height,
  depth,
  className = "", 
  speed = 4,
  opacity = 1,
  label = "",
  centerLabel = "",
  faceLabels,
  isGlassy = true,
  color = "rgba(34, 211, 238, 1)",
  rotationAxis = 'XY',
  visualStyle = 'GLASS',
  status = 'idle',
  delay = 0,
  isRevealed = true,
  isSelected = false
}) => {
  const isSuccess = status === 'success';
  const isFail = status === 'fail';
  const mainText = (centerLabel || label);

  const w = width || size;
  const h = height || size;
  const d = depth || size;

  const overlap = 1.5; 

  const getRotationClass = () => {
    if (isSelected || isSuccess || speed === 0) return "";
    switch (rotationAxis) {
      case 'X': return "animate-cube-x";
      case 'Y': return "animate-cube-y";
      case 'XY': return "animate-cube-xy";
      case 'TUMBLE': return "animate-cube-tumble";
      default: return "animate-cube-xy";
    }
  };

  const renderCube = () => {
    let baseColor = color;
    if (isSuccess) baseColor = '#9FAF90'; // Sage for success
    if (isFail) baseColor = '#D98A7F'; // Coral for fail

    const faces = [
      { id: 'front', rot: 'rotateY(0deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'back', rot: 'rotateY(180deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'right', rot: 'rotateY(90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'left', rot: 'rotateY(-90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'top', rot: 'rotateX(90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
      { id: 'bottom', rot: 'rotateX(-90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
    ];

    return (
      <div className="w-full h-full relative" style={{ transformStyle: 'preserve-3d' }}>
        {faces.map((f, i) => {
          const faceText = (faceLabels && faceLabels[i]) ? faceLabels[i] : mainText;

          let faceStyles: React.CSSProperties = {
            position: 'absolute',
            width: f.fw, 
            height: f.fh, 
            left: (w - f.fw) / 2, 
            top: (h - f.fh) / 2, 
            transform: `${f.rot} translate3d(0, 0, ${f.tz}px)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backfaceVisibility: 'hidden',
            borderRadius: visualStyle === 'FLASHCARD' ? '12px 14px 10px 15px' : Math.min(w, h) * 0.2, 
            transformStyle: 'preserve-3d',
            overflow: 'hidden'
          };

          switch(visualStyle) {
            case 'FLASHCARD':
              faceStyles.background = isSelected ? '#ffffff' : '#F2E9E1';
              faceStyles.border = isSelected ? `4px solid #6A1B1D` : `2px solid rgba(38, 42, 46, 0.15)`;
              faceStyles.boxShadow = isSelected 
                ? `0 15px 30px rgba(0,0,0,0.2), inset 0 0 10px rgba(0,0,0,0.05)` 
                : `0 4px 0 rgba(0,0,0,0.1), inset 0 0 15px rgba(0,0,0,0.02)`;
              break;
            case 'CRYSTAL':
              faceStyles.background = `linear-gradient(135deg, ${baseColor}88 0%, #ffffff88 50%, ${baseColor}88 100%)`;
              faceStyles.border = `4px solid #ffffffaa`;
              faceStyles.boxShadow = `inset 0 0 20px #ffffff44, 0 0 15px ${baseColor}44`;
              faceStyles.backdropFilter = 'blur(12px)';
              break;
            case 'NEON':
              faceStyles.background = `rgba(2, 6, 23, 0.95)`;
              faceStyles.border = `2.5px solid ${baseColor}`;
              faceStyles.boxShadow = `0 0 12px ${baseColor}, 0 0 25px ${baseColor}44, inset 0 0 15px ${baseColor}88, inset 0 0 2px rgba(255,255,255,0.6)`;
              break;
            default: // GLASS (Standard)
              faceStyles.background = isGlassy ? `linear-gradient(135deg, ${baseColor}66 0%, ${baseColor}11 100%)` : baseColor;
              faceStyles.border = isSelected ? '5px solid #ffffff' : `3.5px solid ${baseColor}`;
              faceStyles.backdropFilter = isGlassy ? 'blur(8px)' : 'none';
              faceStyles.boxShadow = `inset 0 0 15px ${baseColor}44`;
          }

          if (isSelected && visualStyle !== 'FLASHCARD') {
            faceStyles.borderColor = '#ffffff';
            faceStyles.borderWidth = '6px';
          }

          return (
            <div key={i} style={faceStyles}>
              {/* Paper Texture Overlay */}
              <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] opacity-10 pointer-events-none" />

              {visualStyle !== 'FLASHCARD' && (
                <div className="absolute inset-0 bg-gradient-to-br from-white/30 via-transparent to-black/20 pointer-events-none opacity-80" />
              )}

              {faceText && (
                <span 
                  className={`font-[900] select-none transition-all duration-700 uppercase whitespace-nowrap px-2 z-10
                    ${isRevealed ? 'opacity-100 scale-100' : 'opacity-0 scale-50'}`}
                  style={{ 
                    fontSize: Math.min(f.fw * 0.8 / (faceText.length || 1), f.fh * 0.7),
                    textShadow: visualStyle === 'FLASHCARD' 
                      ? 'none' 
                      : '0 2px 10px rgba(0,0,0,1), 0 0 15px rgba(0,0,0,0.5)',
                    transform: 'translateZ(12px)',
                    color: visualStyle === 'FLASHCARD' ? '#262A2E' : (visualStyle === 'GHOST' || visualStyle === 'AETHER' ? baseColor : 'white'),
                    fontFamily: visualStyle === 'FLASHCARD' ? 'Courier, monospace' : 'inherit'
                  }}
                >
                  {faceText}
                </span>
              )}

              {isSelected && !isSuccess && !isFail && f.id === 'front' && visualStyle === 'FLASHCARD' && (
                <div className="absolute top-2 right-2 w-7 h-7 bg-[#6A1B1D] rounded-lg flex items-center justify-center shadow-lg z-20 animate-bounce">
                  <span className="text-[14px] text-white font-black">✓</span>
                </div>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  const isDrifting = !isSuccess && !isFail && !isSelected && speed > 0 && rotationAxis !== 'X' && rotationAxis !== 'Y' && visualStyle !== 'FLASHCARD';

  return (
    <div 
      className={`relative ${className} ${isDrifting ? 'animate-cube-drift' : ''}`} 
      style={{ 
        width: w, 
        height: h, 
        perspective: '1200px', 
        transformStyle: 'preserve-3d',
        opacity
      }}
    >
      <div 
        className={`w-full h-full ${getRotationClass()}`}
        style={{ 
          transformStyle: 'preserve-3d',
          '--cube-speed': `${isFail ? 0.35 : (speed || 4)}s`,
          transform: (isSelected || isSuccess || speed === 0) ? 'rotateX(0deg) rotateY(0deg)' : 'none',
          transition: 'transform 0.8s cubic-bezier(0.34, 1.56, 0.64, 1)'
        } as any}
      >
        {renderCube()}
      </div>
    </div>
  );
});

