                  if (isRevealing && res !== undefined) dotClass = res ? 'bg-[#9FAF90] border-[#262A2E]/20' : 'bg-[#D98A7F] border-[#262A2E]/20';
                  return <div key={i} className={`w-4 h-4 rounded-md border-2 transition-all duration-700 ${dotClass} ${isRevealing && res ? 'animate-pulse' : ''}`} />;
