    sm: "px-4 py-1.5 text-[10px]",
    md: "px-6 py-3 text-lg",
    lg: "px-10 py-5 text-2xl"
  };

  return (
    <button 
      onClick={handleInternalClick} 
      disabled={disabled}
      className={`
        ${baseStyles} 
        ${variants[variant as keyof typeof variants] || variants.cyan} 
        ${sizes[size]} 
        ${disabled ? 'opacity-30 grayscale cursor-not-allowed halftone-shadow' : 'cursor-pointer'}
        ${className}
      `}
    >
      {/* Halftone Top Shine (Matte highlight) */}
      <div className="absolute top-0 left-0 right-0 h-1/2 bg-white/5 pointer-events-none" />

      {/* High-Contrast Grain */}
      <div className="absolute inset-0 opacity-[0.15] mix-blend-overlay bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] pointer-events-none" />

      <span className="relative z-10 letterpress-text">
        {children}
      </span>
    </button>
  );
};

import React, { memo } from 'react';

export type RotationAxis = 'X' | 'Y' | 'XY' | 'TUMBLE';
export type CubeVisualStyle = 'GLASS' | 'CRYSTAL' | 'METAL' | 'NEON' | 'GHOST' | 'DARK' | 'PLASMA' | 'CHROME' | 'LAVA' | 'AETHER' | 'VOID' | 'FLASHCARD' | 'CERAMIC';

interface Cube3DProps {
  size?: number;
  width?: number; 
  height?: number; 
  depth?: number; 
  className?: string;
  speed?: number;
  opacity?: number;
  label?: string;
  centerLabel?: string; 
  faceLabels?: string[]; 
  isGlassy?: boolean;
  color?: string;
  rotationAxis?: RotationAxis;
  visualStyle?: CubeVisualStyle;
  status?: 'idle' | 'success' | 'fail';
  delay?: number;
  isRevealed?: boolean;
  isSelected?: boolean;
}

export const Cube3D: React.FC<Cube3DProps> = memo(({ 
  size = 32,
  width,
  height,
  depth,
  className = "", 
  speed = 4,
  opacity = 1,
  label = "",
  centerLabel = "",
  faceLabels,
  isGlassy = true,
  color = "#F2E9E1",
  rotationAxis = 'XY',
  visualStyle = 'CERAMIC',
  status = 'idle',
  delay = 0,
  isRevealed = true,
  isSelected = false
}) => {
  const isSuccess = status === 'success';
  const isFail = status === 'fail';
  const mainText = (centerLabel || label);

  const w = width || size;
  const h = height || size;
  const d = depth || size;

  const overlap = 1.0; 

  const getRotationClass = () => {
    if (isSelected || isSuccess || speed === 0) return "";
    switch (rotationAxis) {
      case 'X': return "animate-cube-x";
      case 'Y': return "animate-cube-y";
      case 'XY': return "animate-cube-xy";
      case 'TUMBLE': return "animate-cube-tumble";
      default: return "animate-cube-xy";
    }
  };

  const renderCube = () => {
    let baseColor = color;
    if (isSuccess) baseColor = '#9FAF90'; 
    if (isFail) baseColor = '#D98A7F'; 

    const faces = [
      { id: 'front', rot: 'rotateY(0deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'back', rot: 'rotateY(180deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'right', rot: 'rotateY(90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'left', rot: 'rotateY(-90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'top', rot: 'rotateX(90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
      { id: 'bottom', rot: 'rotateX(-90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
    ];

    return (
      <div className="w-full h-full relative" style={{ transformStyle: 'preserve-3d' }}>
        {faces.map((f, i) => {
          const faceText = (faceLabels && faceLabels[i]) ? faceLabels[i] : mainText;

          let faceStyles: React.CSSProperties = {
            position: 'absolute',
            width: f.fw, 
            height: f.fh, 
            left: (w - f.fw) / 2, 
            top: (h - f.fh) / 2, 
            transform: `${f.rot} translate3d(0, 0, ${f.tz}px)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backfaceVisibility: 'hidden',
            borderRadius: '6px 4px 8px 5px', // Irregular hand-cut feel
            transformStyle: 'preserve-3d',
            overflow: 'hidden',
            backgroundColor: isSelected ? '#ffffff' : baseColor,
            border: isSelected ? '2px solid #6A1B1D' : '1px solid rgba(0,0,0,0.1)',
            backgroundImage: "url('https://www.transparenttextures.com/patterns/egg-shell.png')"
          };

          // Halftone ink drop effect for letters
          const textStyle: React.CSSProperties = {
            fontSize: Math.min(f.fw * 0.8 / (faceText?.length || 1), f.fh * 0.75),
            color: '#1A1C1E',
            opacity: 0.85,
            fontFamily: 'Courier, monospace',
            transform: 'translateZ(2px)',
            mixBlendMode: 'multiply'
          };

          return (
            <div key={i} style={faceStyles}>
              {/* Ceramic Surface Glaze */}
              <div className="absolute inset-0 bg-gradient-to-br from-white/20 via-transparent to-black/10 pointer-events-none" />

              {/* Dirt/Age Spots Overlay */}
              <div className="absolute inset-0 opacity-[0.05] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]" />

              {faceText && (
                <span 
                  className={`font-[900] select-none transition-all duration-700 uppercase whitespace-nowrap px-2 z-10
                    ${isRevealed ? 'opacity-100 scale-100' : 'opacity-0 scale-50'}`}
                  style={textStyle}
                >
                  {faceText}
                </span>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div 
      className={`relative ${className}`} 
      style={{ 
        width: w, 
        height: h, 
        perspective: '1200px', 
        transformStyle: 'preserve-3d',
        opacity
      }}
    >
      <div 
        className={`w-full h-full ${getRotationClass()}`}
        style={{ 
          transformStyle: 'preserve-3d',
          '--cube-speed': `${speed || 4}s`,
          transform: (isSelected || isSuccess || speed === 0) ? 'rotateX(0deg) rotateY(0deg)' : 'none',
          transition: 'transform 0.8s cubic-bezier(0.34, 1.56, 0.64, 1)'
        } as any}
      >
        {renderCube()}
      </div>
    </div>
  );
});

