  rotationAxis = 'XY',
  visualStyle = 'CERAMIC',
  status = 'idle',
  delay = 0,
  isRevealed = true,
  isSelected = false
}) => {
  const isSuccess = status === 'success';
  const isFail = status === 'fail';
  const mainText = (centerLabel || label);

  const w = width || size;
  const h = height || size;
  const d = depth || size;

  const overlap = 0.5; 

  const getRotationClass = () => {
    if (isSelected || isSuccess || speed === 0) return "";
    switch (rotationAxis) {
      case 'X': return "animate-cube-x";
      case 'Y': return "animate-cube-y";
      case 'XY': return "animate-cube-xy";
      case 'TUMBLE': return "animate-cube-tumble";
      default: return "animate-cube-xy";
    }
  };

  const renderCube = () => {
    let baseColor = color;
    if (isSuccess) baseColor = '#9FAF90'; 
    if (isFail) baseColor = '#D98A7F'; 

    const faces = [
      { id: 'front', rot: 'rotateY(0deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'back', rot: 'rotateY(180deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'right', rot: 'rotateY(90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'left', rot: 'rotateY(-90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'top', rot: 'rotateX(90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
      { id: 'bottom', rot: 'rotateX(-90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
    ];

    return (
      <div className="w-full h-full relative" style={{ transformStyle: 'preserve-3d' }}>
        {faces.map((f, i) => {
          const faceText = (faceLabels && faceLabels[i]) ? faceLabels[i] : mainText;

          let faceStyles: React.CSSProperties = {
            position: 'absolute',
            width: f.fw, 
            height: f.fh, 
            left: (w - f.fw) / 2, 
            top: (h - f.fh) / 2, 
            transform: `${f.rot} translate3d(0, 0, ${f.tz}px)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backfaceVisibility: 'hidden',
            borderRadius: '4px 3px 5px 2px', 
            transformStyle: 'preserve-3d',
            overflow: 'hidden',
            backgroundColor: isSelected ? '#ffffff' : baseColor,
            border: isSelected ? '1.5px solid #6A1B1D' : '1px solid rgba(0,0,0,0.1)',
            backgroundImage: "url('https://www.transparenttextures.com/patterns/egg-shell.png')",
            // Studio light simulation per face
            boxShadow: 'inset 2px 2px 2px rgba(255,255,255,0.4), inset -1px -1px 2px rgba(0,0,0,0.1)'
          };

          const textStyle: React.CSSProperties = {
            fontSize: Math.min(f.fw * 0.75 / (faceText?.length || 1), f.fh * 0.7),
            color: '#1A1C1E',
            opacity: 0.85,
            fontFamily: 'Courier, monospace',
            transform: 'translateZ(1px)',
            mixBlendMode: 'multiply',
            fontWeight: 900
          };

          return (
            <div key={i} style={faceStyles}>
              {/* Studio lighting gradient shadow to simulate depth from outside light source */}
              <div className="absolute inset-0 bg-gradient-to-br from-white/10 via-transparent to-black/20 pointer-events-none" />

              {/* Material Grain */}
              <div className="absolute inset-0 opacity-[0.08] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]" />

              {faceText && (
                <span 
                  className={`font-[900] select-none transition-all duration-700 uppercase whitespace-nowrap px-1 z-10 ink-bleed
                    ${isRevealed ? 'opacity-100 scale-100' : 'opacity-0 scale-50'}`}
                  style={textStyle}
                >
                  {faceText}
                </span>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div 
      className={`relative ${className}`} 
      style={{ 
        width: w, 
        height: h, 
        perspective: '1200px', 
        transformStyle: 'preserve-3d',
        opacity
      }}
    >
      {/* Physical Drop Shadow (Matte and soft) */}
      <div 
        className="absolute inset-2 bg-black/20 blur-md translate-x-3 translate-y-3 rounded-md"
        style={{ transform: 'translateZ(-10px)' }}
      />
      <div 
        className={`w-full h-full ${getRotationClass()}`}
        style={{ 
          transformStyle: 'preserve-3d',
          '--cube-speed': `${speed || 4}s`,
          transform: (isSelected || isSuccess || speed === 0) ? 'rotateX(0deg) rotateY(0deg)' : 'none',
          transition: 'transform 0.8s cubic-bezier(0.34, 1.56, 0.64, 1)'
        } as any}
      >
        {renderCube()}
      </div>
    </div>
  );
});

import React from 'react';
import { SoundManager } from '../managers/SoundManager';

interface ButtonProps {
  children: React.ReactNode;
  onClick: () => void;
  variant?: 'cyan' | 'indigo' | 'pink' | 'amber' | 'green' | 'coral' | 'white' | 'ribbon' | 'bakelite';
  className?: string;
  size?: 'sm' | 'md' | 'lg';
  disabled?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  onClick, 
  variant = 'cyan', 
  className = '',
  size = 'md',
  disabled = false
}) => {
  const handleInternalClick = () => {
    if (!disabled) {
      SoundManager.getInstance().playClick();
      onClick();
    }
  };

  const baseStyles = "relative font-[900] uppercase tracking-tighter rounded-sm flex items-center justify-center border border-[#262A2E]/50 overflow-hidden select-none active:translate-y-1 transition-all duration-200";

  const variants = {
    cyan: "bg-[#7B99A5] text-[#262A2E] border-b-[6px] border-[#4A5E68]", 
    indigo: "bg-[#9FAF90] text-[#262A2E] border-b-[6px] border-[#5E6A56]", 
    pink: "bg-[#D98A7F] text-[#F2E9E1] border-b-[6px] border-[#8C4F48]", 
    amber: "bg-[#D4AF37] text-[#262A2E] border-b-[6px] border-[#8C7424]", 
    green: "bg-[#A3B18A] text-[#262A2E] border-b-[6px] border-[#588157]",
    coral: "bg-[#BC4749] text-[#F2E9E1] border-b-[8px] border-b-[#8c2a2b] border-x-[1.5px] border-t-[1.5px] border-t-white/10",
    white: "bg-[#F2E9E1] text-[#262A2E] border-b-[6px] border-[#D6C5B3]",
    bakelite: "bg-[#262A2E] text-[#F2E9E1] border-b-[8px] border-b-black border-x-[2px] border-t-[2px] border-t-white/5",
    ribbon: "bg-[#6A1B1D] text-[#F2E9E1] border-b-[8px] border-[#262A2E]" 
  };

  const sizes = {
    sm: "px-4 py-1.5 text-[10px]",
    md: "px-6 py-3 text-lg",
    lg: "px-10 py-5 text-2xl"
  };

  return (
    <div className={`relative ${className}`}>
      {/* Physical Studio Shadow (External soft shadow) */}
      <div className="absolute inset-0 bg-black/15 blur-sm translate-x-1.5 translate-y-1.5 rounded-sm" />

      <button 
        onClick={handleInternalClick} 
        disabled={disabled}
        className={`
          ${baseStyles} 
          ${variants[variant as keyof typeof variants] || variants.cyan} 
          ${sizes[size]} 
          ${disabled ? 'opacity-30 grayscale cursor-not-allowed' : 'cursor-pointer'}
          w-full
        `}
      >
        {/* Studio Lighting Rim (Top-left highlight edge) */}
        <div className="absolute inset-0 border-t-[1.5px] border-l-[1.5px] border-white/20 pointer-events-none" />

        {/* Matte Surface Grain */}
        <div className="absolute inset-0 opacity-[0.22] mix-blend-overlay bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] pointer-events-none" />

        <span className="relative z-10 letterpress-ink drop-shadow-[0_1px_0px_rgba(255,255,255,0.1)]">
          {children}
        </span>
      </button>
    </div>
  );
};

