  { target: "SİNYAL", distractors: ["SİMSAR", "SİNYALİ", "SİNSİCE"] },
  { target: "SPEKTRUM", distractors: ["SPEKÜLER", "SPEKÜLÜM", "SPEKTROM"] },
  { target: "GRAVİTE", distractors: ["GRAVÜRE", "GRAVİTİ", "GRAVATLAR"] },
  { target: "PARTİKÜL", distractors: ["PATİKALI", "PARTİKÜLER", "PARTİKÜLÜ"] },
  { target: "NEBULA", distractors: ["PUSULA", "NEBULAR", "NEBÜLAS"] },
  { target: "VAKUM", distractors: ["BAKIM", "VAKUMU", "VAKUMLU"] },
  { target: "FOTON", distractors: ["KOTON", "FOTONİK", "FOTONU"] },
  { target: "RADYANT", distractors: ["VARYANT", "RADYAN", "RADYANTLI"] },
  { target: "REAKTÖR", distractors: ["REFAKAT", "REAKTİF", "REAKTÖRÜ"] },
  { target: "İVMELEME", distractors: ["İZLELEME", "İMGELEME", "İMLEMECE"] },
  { target: "HÜCRESEL", distractors: ["ZÜMRESEL", "SÜRESEL", "HÜCRESİ"] },
  { target: "MUTASYON", distractors: ["MOTİVASYON", "MUTASYONLU", "KUTASYON"] },
  { target: "İLETKEN", distractors: ["İZLENEN", "İLETİLEN", "İLETKENLİ"] },
  { target: "YALITKAN", distractors: ["YALITIM", "YALITLAN", "YALITKANS"] },
  { target: "GERİLİM", distractors: ["GERİLEYİŞ", "GERİLEME", "GERİLİMLİ"] },
  { target: "ADAPTÖR", distractors: ["ADAPTASYON", "ADAPTİVE", "ADAPTÖRÜ"] },
  { target: "KARANLIK", distractors: ["KABARIK", "KARARLIK", "KARANLAK"] }
];

const COLORS = ["#7B99A5", "#D4AF37", "#D98A7F", "#9FAF90", "#A3B18A"];
const MEMORIZE_DURATION = 30; 
const BASE_ROUND_TIME = 10;

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void; onUpdateStats: (s: Partial<UserStats>) => void }> = ({ stats, onComplete, onExit, onUpdateStats }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);

  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [rotationOffset, setRotationOffset] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showQuitModal, setShowQuitModal] = useState(false);

  const [isTimeFrozen, setIsTimeFrozen] = useState(false);
  const [showHintMenu, setShowHintMenu] = useState(false);

  const timerRef = useRef<number | null>(null);

  const puzzleRounds = useMemo(() => {
    return [...ALL_ROUNDS_POOL].sort(() => Math.random() - 0.5).slice(0, 5);
  }, []);

  const activeRoundData = puzzleRounds[currentRound];
  const activeOptions = useMemo(() => [activeRoundData.target, ...activeRoundData.distractors].sort(() => Math.random() - 0.5), [activeRoundData]);

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || isMenuOpen || isTransitioning || showQuitModal) return;
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if ((isTimeFrozen || showHintMenu) && gamePhase === 'MEMORIZE') return prev;
        const nextTime = prev - 0.05;
        if (gamePhase === 'MEMORIZE' && nextTime <= 0) {
          setGamePhase('GUESS');
          SoundManager.getInstance().playPop();
          return dynamicRoundTime;
        }
        if (gamePhase === 'GUESS' && nextTime <= 0) {
          handleChoice("TIME_UP");
          return dynamicRoundTime;
        }
        return nextTime;
      });
      if (gamePhase === 'MEMORIZE' && !isTimeFrozen && !showHintMenu) {
          setRotationOffset(prev => prev + (0.4 * stats.difficultyFactor));
      }
    }, 50);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [choiceStatus, selectedChoice, isMenuOpen, isTransitioning, currentRound, showQuitModal, dynamicRoundTime, stats.difficultyFactor, gamePhase, isTimeFrozen, showHintMenu]);

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle' || isTransitioning) return;
    setSelectedChoice(choice);
    const isCorrect = choice === activeRoundData.target;
    setChoiceStatus(isCorrect ? 'success' : 'fail');
    if (isCorrect) {
      SoundManager.getInstance().playSuccess();
      setSessionScore(s => s + 100);
    } else {
      SoundManager.getInstance().playFail();
    }

    setTimeout(() => {
      if (currentRound === puzzleRounds.length - 1) {
        onComplete(sessionScore, puzzleRounds.map(r => r.target), puzzleRounds.flatMap(r => r.distractors));
      } else {
        setCurrentRound(r => r + 1);
        setGamePhase('MEMORIZE');
        setTimeLeft(MEMORIZE_DURATION);
        setChoiceStatus('idle');
        setSelectedChoice(null);
      }
    }, 2000);
  };

  const ringItems = activeRoundData.target.split("").map((char, i) => ({ char, color: COLORS[i % COLORS.length] }));

  const renderRing = () => {
    const dist = 130;
    const isSuccess = choiceStatus === 'success';

    return (
      <div className="relative w-full h-full flex items-center justify-center transition-all duration-700">

        {/* Physical Waxed Thread Connection (Matte black string) */}
        {!isSuccess && gamePhase === 'MEMORIZE' && (
          <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-40 animate-string">
            <circle 
              cx="50%" cy="50%" r={dist} 
              fill="none" 
              stroke="#1A1C1E" 
              strokeWidth="1.5" 
              strokeDasharray="1,2" 
            />
          </svg>
        )}

        {ringItems.map((item, idx) => {
          const angle = (idx / ringItems.length) * 360 + rotationOffset;
          const rad = (angle * Math.PI) / 180;
          let x = isSuccess ? (idx - (ringItems.length / 2 - 0.5)) * 62 : Math.cos(rad) * dist;
          let y = isSuccess ? 0 : Math.sin(rad) * dist;

          return (
            <div key={idx} className="absolute transition-all duration-700" style={{ transform: `translate3d(${x}px, ${y}px, 0)` }}>
              <Cube3D 
                size={60} 
                label={gamePhase === 'GUESS' && !isSuccess ? '?' : item.char} 
                color="#F2E9E1" 
                visualStyle="CERAMIC" 
                status={choiceStatus} 
                speed={0} 
              />
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="absolute inset-0 bg-[#E6D5C3] flex flex-col overflow-hidden">
      <ParticleBackground speedMultiplier={0.2} />

      {/* Heavy Print Grain */}
      <div className="absolute inset-0 opacity-[0.25] mix-blend-multiply bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] pointer-events-none z-[5]" />

      <div className="pt-10 px-8 flex justify-between items-start z-20 shrink-0">
        <div className="bg-[#262A2E] px-4 py-1.5 border border-white/10 shadow-xl">
          <span className="text-[#F2E9E1] text-[10px] font-black tracking-widest uppercase ink-bleed">OBSERVATIO</span>
        </div>
        <div className="text-4xl font-[900] text-[#1A1C1E] letterpress-ink">{sessionScore}</div>
      </div>

      <div className="flex-1 relative z-10">{renderRing()}</div>

      <div className="px-8 pb-14 flex flex-col gap-6 z-20 shrink-0">
        {/* Physical Timeline Bar */}
        <div className="w-full h-2.5 bg-black/15 border border-black/10 p-0.5 rounded-sm overflow-hidden">
          <div className="h-full bg-[#BC4749] border-r border-white/20 transition-all duration-500" style={{ width: `${(timeLeft / MEMORIZE_DURATION) * 100}%` }} />
        </div>

        <div className="grid grid-cols-2 gap-4">
          {activeOptions.map((opt, i) => (
            <Button 
              key={i} 
              variant="white"
              onClick={() => handleChoice(opt)} 
              className={`!h-24 !text-2xl !bg-[#F2E9E1] !text-[#1A1C1E] !border-black/20 ${selectedChoice && selectedChoice !== opt ? 'opacity-20' : ''}`}
              disabled={!!selectedChoice}
            >
              {gamePhase === 'GUESS' ? opt : '...'}
            </Button>
          ))}
        </div>
      </div>
      <div className="fixed right-4 bottom-4"><SideMenu onExit={() => setShowQuitModal(true)} isMinimal={true} expandDirection="up" /></div>
      {showQuitModal && <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />}
    </div>
  );
};

