import React, { useEffect, useRef, memo } from 'react';

interface ParticleBackgroundProps {
  speedMultiplier?: number;
  level?: number;
}

export const ParticleBackground: React.FC<ParticleBackgroundProps> = memo(({ speedMultiplier = 1 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let elements: Array<{
      x: number;
      y: number;
      w: number;
      h: number;
      type: 'STAIN' | 'FIBER' | 'DUST';
      vx: number;
      vy: number;
      alpha: number;
      rotation: number;
      color: string;
    }> = [];

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      init();
    };

    const init = () => {
      elements = [];
      const count = 35;
      const colors = ['#1A1C1E', '#6A1B1D', '#8C7424', '#5E6A56'];

      for (let i = 0; i < count; i++) {
        const type = Math.random() > 0.7 ? 'FIBER' : Math.random() > 0.4 ? 'DUST' : 'STAIN';
        elements.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          w: type === 'FIBER' ? Math.random() * 20 + 10 : Math.random() * 4 + 2,
          h: type === 'FIBER' ? 0.5 : Math.random() * 4 + 2,
          type,
          vx: (Math.random() - 0.5) * 0.08,
          vy: (Math.random() - 0.5) * 0.08,
          alpha: Math.random() * 0.12 + 0.03,
          rotation: Math.random() * Math.PI,
          color: colors[Math.floor(Math.random() * colors.length)]
        });
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      elements.forEach((e) => {
        ctx.save();
        ctx.translate(e.x, e.y);
        ctx.rotate(e.rotation);
        ctx.globalAlpha = e.alpha;

        ctx.fillStyle = e.color;
        if (e.type === 'STAIN') {
          ctx.beginPath();
          ctx.ellipse(0, 0, e.w, e.h, 0, 0, Math.PI * 2);
          ctx.fill();
        } else if (e.type === 'FIBER') {
          ctx.fillRect(-e.w/2, -e.h/2, e.w, e.h);
        } else {
          ctx.fillRect(-e.w/2, -e.h/2, e.w, e.w);
        }

        ctx.restore();

        e.x += e.vx * speedMultiplier;
        e.y += e.vy * speedMultiplier;

        if (e.x < 0) e.x = canvas.width;
        if (e.x > canvas.width) e.x = 0;
        if (e.y < 0) e.y = canvas.height;
        if (e.y > canvas.height) e.y = 0;
      });

      requestAnimationFrame(draw);
    };

    resize();
    draw();
    window.addEventListener('resize', resize);
    return () => window.removeEventListener('resize', resize);
  }, [speedMultiplier]);

  return (
    <div className="absolute inset-0 w-full h-full pointer-events-none z-[0]">
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full" />
    </div>
  );
});

