import { auth, fetchCloudStats, syncUserStats, reconcileStats } from './lib/firebase';
import { onAuthStateChanged, User } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

const STORAGE_KEY = 'lumina_stats';
const DEFAULT_BG = "https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&q=80&w=1080&h=1920";
const MISSIONS_REFRESH_INTERVAL = 24 * 60 * 60 * 1000;

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.LOADING);
  const [hubSubView, setHubSubView] = useState<HubSubView>(HubSubView.MAIN);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { console.error(e); }
    }
    return {
      coins: 2063, hearts: 5, stars: 12, level: 1,
      lastLifeRefillTime: Date.now(),
      hintsFreeze: 3, hintsReveal: 3,
      claimedMissions: [],
      lastMissionsRefresh: Date.now(),
      difficultyFactor: 1.0, performanceHistory: [],
      streak: 0, maxStreak: 0
    };
  });

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      setCurrentUser(user);
      if (user) {
        setIsSyncing(true);
        const cloudData = await fetchCloudStats(user.uid);
        if (cloudData) {
          const merged = reconcileStats(stats, cloudData);
          setStats(merged);
        }
        setIsSyncing(false);
      }
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stats));
    if (currentUser) {
      const timeout = setTimeout(async () => {
        setIsSyncing(true);
        await syncUserStats(currentUser.uid, stats, currentUser.displayName || "", currentUser.photoURL || "");
        setIsSyncing(false);
      }, 2000);
      return () => clearTimeout(timeout);
    }
  }, [stats, currentUser]);

  const [targetWords, setTargetWords] = useState<string[]>([]);
  const [fullWordPool, setFullWordPool] = useState<string[]>([]);
  const [showChest, setShowChest] = useState(false);
  const [bonusEarned, setBonusEarned] = useState(0);
  const [sessionScore, setSessionScore] = useState(0);
  const [starsEarnedInLevel, setStarsEarnedInLevel] = useState(0);
  const [transitionState, setTransitionState] = useState<'idle' | 'animating'>('idle');

  const changeGameState = (newState: GameState) => {
    setTransitionState('animating');
    setTimeout(() => {
      setGameState(newState);
      setTransitionState('idle');
    }, 300);
  };

  const updateStats = (updates: Partial<UserStats>) => {
    setStats(prev => ({ ...prev, ...updates }));
  };

  const handleStartGame = () => {
    if (stats.hearts > 0) {
      setSessionScore(0);
      changeGameState(GameState.WORD_PUZZLE);
    } else {
      setHubSubView(HubSubView.SHOP);
    }
  };

  const handleExitWithPenalty = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.HUB);
  };

  const handlePuzzleComplete = (earned: number, allTargets: string[], allDistractors: string[]) => {
    setSessionScore(earned);
    setTargetWords(allTargets);
    const pooledWords = [...allTargets, ...allDistractors].sort(() => Math.random() - 0.5);
    setFullWordPool(pooledWords);
    changeGameState(GameState.MEMORY_PREPARE);
  };

  const handleGameComplete = (correctCount: number) => {
    let stars = correctCount === 5 ? 3 : correctCount >= 4 ? 2 : 1;
    let bonus = correctCount * 50;
    setStarsEarnedInLevel(stars);
    setBonusEarned(bonus);
    changeGameState(GameState.LEVEL_COMPLETE);
  };

  const handleLevelFail = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.LEVEL_FAIL);
  };

  const handleBuyItem = (cost: number, type: 'HEART' | 'FREEZE' | 'REVEAL', amount: number) => {
    if (stats.coins < cost) return;
    setStats(prev => {
      const next = { ...prev, coins: prev.coins - cost };
      if (type === 'HEART') next.hearts = Math.min(5, prev.hearts + amount);
      if (type === 'FREEZE') next.hintsFreeze += amount;
      if (type === 'REVEAL') next.hintsReveal += amount;
      return next;
    });
  };

  const renderScreen = () => {
    switch (gameState) {
      case GameState.LOADING: return <LoadingScreen onFinished={() => changeGameState(GameState.HUB)} />;
      case GameState.HUB: return <HubScreen stats={stats} currentUser={currentUser} isSyncing={isSyncing} hubSubView={hubSubView} setHubSubView={setHubSubView} onStartGame={handleStartGame} onAddCoins={(amt) => updateStats({ coins: stats.coins + amt })} onBuyHearts={(c, a) => handleBuyItem(c, 'HEART', a)} onOpenChest={() => setShowChest(true)} onClaimMission={(id, reward) => updateStats({ coins: stats.coins + reward, claimedMissions: [...stats.claimedMissions, id] })} />;
      case GameState.WORD_PUZZLE: return <WordPuzzle stats={stats} onComplete={handlePuzzleComplete} onExit={handleExitWithPenalty} onUpdateStats={updateStats} />;
      case GameState.MEMORY_PREPARE: return <MemoryTransitionModal onConfirm={() => changeGameState(GameState.MEMORY_GAME)} onExit={handleExitWithPenalty} />;
      case GameState.MEMORY_GAME: return <MemoryGame stats={stats} backgroundUrl={DEFAULT_BG} words={fullWordPool} targetWords={targetWords} onNext={handleGameComplete} onFail={handleLevelFail} onExit={handleExitWithPenalty} initialScore={sessionScore} />;
      case GameState.LEVEL_COMPLETE: return <LevelCompleteModal level={stats.level} coinsEarned={sessionScore + bonusEarned} starsEarned={starsEarnedInLevel} onContinue={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); handleStartGame(); }} onMenu={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); changeGameState(GameState.HUB); }} />;
      case GameState.LEVEL_FAIL: return <LevelFailModal hearts={stats.hearts} lastLifeRefillTime={stats.lastLifeRefillTime} onRetry={() => { if(stats.hearts > 0) changeGameState(GameState.WORD_PUZZLE); else setHubSubView(HubSubView.SHOP); }} onShop={() => { changeGameState(GameState.HUB); setHubSubView(HubSubView.SHOP); }} onExit={() => changeGameState(GameState.HUB)} />;
      default: return <LoadingScreen />;
    }
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-[#262A2E] overflow-hidden select-none">
      {/* Surreal Background Element */}
      <svg className="giant-gear top-[-100px] left-[-100px]" viewBox="0 0 100 100">
        <path fill="currentColor" className="text-black" d="M50 35a15 15 0 1 0 0 30 15 15 0 0 0 0-30zm0 4a11 11 0 1 1 0 22 11 11 0 0 1 0-22zM48 2l2 8h-4l2-8zm13.7 4.1l-1.5 8.3-3.9-1 1.5-8.3 3.9 1zm12.3 9.4l-4.7 6.9-3.2-2.3 4.7-6.9 3.2 2.3zM85.9 28l-6.9 4.7-2.3-3.2 6.9-4.7 2.3 3.2zM94.9 44l-8.3 1.5-1-3.9 8.3-1.5 1 3.9zM98 60l-8.3-1.5 1-3.9 8.3 1.5-1 3.9zm-9.4 13.7l-6.9-4.7 3.2-2.3 6.9 4.7-3.2 2.3zm-12.3 12.3l-4.7-6.9 3.2-2.3 4.7 6.9-3.2 2.3zM56 94.9l-1.5-8.3 3.9-1 1.5 8.3-3.9 1zm-16 3.1l-1.5-8.3 3.9-1 1.5 8.3-3.9 1zm-13.7-9.4l1.5-8.3 3.9 1-1.5 8.3-3.9-1zm-12.3-12.3l4.7-6.9 3.2 2.3-4.7 6.9-3.2-2.3zm-9.4-13.7l6.9-4.7 2.3 3.2-6.9 4.7-2.3-3.2zM5.1 44l8.3-1.5 1 3.9-8.3 1.5-1-3.9zM2 28l8.3 1.5-1 3.9-8.3-1.5 1-3.9zM6.1 13.7l6.9 4.7-3.2 2.3-6.9-4.7 3.2-2.3zm9.4-12.3l4.7 6.9-3.2 2.3-4.7-6.9 3.2-2.3zM44 2l-1.5 8.3-3.9-1L40 2h4z" />
      </svg>

      <div className="shadowbox-container">
        <div className={`w-full h-full transition-all duration-500 ease-out ${transitionState === 'animating' ? 'opacity-0 scale-95 blur-md' : 'opacity-100 scale-100'}`}>
          {renderScreen()}
        </div>
      </div>

      {showChest && <ChestModal onClose={() => setShowChest(false)} onReward={(amt) => updateStats({ coins: stats.coins + amt })} />}
    </div>
  );
};

export default App;

import React, { memo } from 'react';

export type RotationAxis = 'X' | 'Y' | 'XY' | 'TUMBLE';
export type CubeVisualStyle = 'GLASS' | 'CRYSTAL' | 'METAL' | 'NEON' | 'GHOST' | 'DARK' | 'PLASMA' | 'CHROME' | 'LAVA' | 'AETHER' | 'VOID' | 'FLASHCARD' | 'CERAMIC';

interface Cube3DProps {
  size?: number;
  width?: number; 
  height?: number; 
  depth?: number; 
  className?: string;
  speed?: number;
  opacity?: number;
  label?: string;
  centerLabel?: string; 
  faceLabels?: string[]; 
  isGlassy?: boolean;
  color?: string;
  rotationAxis?: RotationAxis;
  visualStyle?: CubeVisualStyle;
  status?: 'idle' | 'success' | 'fail';
  delay?: number;
  isRevealed?: boolean;
  isSelected?: boolean;
}

export const Cube3D: React.FC<Cube3DProps> = memo(({ 
  size = 32,
  width,
  height,
  depth,
  className = "", 
  speed = 4,
  opacity = 1,
  label = "",
  centerLabel = "",
  faceLabels,
  isGlassy = false,
  color = "#F2E9E1",
  rotationAxis = 'XY',
  visualStyle = 'CERAMIC',
  status = 'idle',
  delay = 0,
  isRevealed = true,
  isSelected = false
}) => {
  const isSuccess = status === 'success';
  const isFail = status === 'fail';
  const mainText = (centerLabel || label);

  const w = width || size;
  const h = height || size;
  const d = depth || size;

  const overlap = 0.5; 

  const getRotationClass = () => {
    if (isSelected || isSuccess || speed === 0) return "";
    switch (rotationAxis) {
      case 'X': return "animate-cube-x";
      case 'Y': return "animate-cube-y";
      case 'XY': return "animate-cube-xy";
      case 'TUMBLE': return "animate-cube-tumble";
      default: return "animate-cube-xy";
    }
  };

  const renderCube = () => {
    let baseColor = color;
    if (isSuccess) baseColor = '#9FAF90'; 
    if (isFail) baseColor = '#D98A7F'; 

    const faces = [
      { id: 'front', rot: 'rotateY(0deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'back', rot: 'rotateY(180deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'right', rot: 'rotateY(90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'left', rot: 'rotateY(-90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'top', rot: 'rotateX(90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
      { id: 'bottom', rot: 'rotateX(-90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
    ];

    return (
      <div className="w-full h-full relative" style={{ transformStyle: 'preserve-3d' }}>
        {faces.map((f, i) => {
          const faceText = (faceLabels && faceLabels[i]) ? faceLabels[i] : mainText;

          let faceStyles: React.CSSProperties = {
            position: 'absolute',
            width: f.fw, 
            height: f.fh, 
            left: (w - f.fw) / 2, 
            top: (h - f.fh) / 2, 
            transform: `${f.rot} translate3d(0, 0, ${f.tz}px)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backfaceVisibility: 'hidden',
            borderRadius: '4px 3px 2px 6px', 
            transformStyle: 'preserve-3d',
            overflow: 'hidden',
            backgroundColor: isSelected ? '#ffffff' : baseColor,
            border: isSelected ? '2px solid #BC4749' : '1px solid rgba(0,0,0,0.15)',
            backgroundImage: "url('https://www.transparenttextures.com/patterns/egg-shell.png')",
            // Matte Finish Shading
            boxShadow: 'inset 1.5px 1.5px 0 rgba(255,255,255,0.4), inset -2px -2px 0 rgba(0,0,0,0.1)'
          };

          const textStyle: React.CSSProperties = {
            fontSize: Math.min(f.fw * 0.75 / (faceText?.length || 1), f.fh * 0.6),
            color: '#1A1C1E',
            opacity: 0.9,
            fontFamily: "'Bowlby One SC', cursive",
            transform: 'translateZ(3px) rotate(-1.5deg)',
            mixBlendMode: 'multiply',
            fontWeight: 900
          };

          return (
            <div key={i} style={faceStyles}>
              {/* Studio lighting Simulation per face */}
              <div className="absolute inset-0 bg-gradient-to-br from-white/10 via-transparent to-black/20 pointer-events-none" />

              {/* Material Grain */}
              <div className="absolute inset-0 opacity-[0.15] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/linen.png')]" />

              {faceText && (
                <span 
                  className={`select-none transition-all duration-700 uppercase whitespace-nowrap px-1 z-10 ink-bleed color-fringe
                    ${isRevealed ? 'opacity-100 scale-100' : 'opacity-0 scale-50'}`}
                  style={textStyle}
                >
                  {faceText}
                </span>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div 
      className={`relative ${className}`} 
      style={{ 
        width: w, 
        height: h, 
        perspective: '1200px', 
        transformStyle: 'preserve-3d',
        opacity
      }}
    >
      {/* Physical Halftone Shadow for Shadowbox Depth */}
      <div 
        className="absolute inset-2 bg-black/15 blur-[1.5px] translate-x-4 translate-y-4 rounded-md"
        style={{ 
          transform: 'translateZ(-15px)',
          backgroundImage: 'radial-gradient(circle, rgba(0,0,0,0.4) 1.2px, transparent 1.2px)',
          backgroundSize: '4px 4px'
        }}
      />
      <div 
        className={`w-full h-full ${getRotationClass()}`}
        style={{ 
          transformStyle: 'preserve-3d',
          '--cube-speed': `${speed || 4}s`,
          transform: (isSelected || isSuccess || speed === 0) ? 'rotateX(0deg) rotateY(0deg)' : 'none',
          transition: 'transform 0.8s cubic-bezier(0.34, 1.56, 0.64, 1)'
        } as any}
      >
        {renderCube()}
      </div>
    </div>
  );
});

