export const Button: React.FC<ButtonProps> = ({ 
  children, 
  onClick, 
  variant = 'cyan', 
  className = '',
  size = 'md',
  disabled = false
}) => {
  const handleInternalClick = () => {
    if (!disabled) {
      SoundManager.getInstance().playClick();
      onClick();
    }
  };

  const baseStyles = "relative display-font uppercase tracking-tighter rounded-sm flex items-center justify-center border border-[#262A2E]/60 overflow-hidden select-none active:translate-y-1 transition-all duration-150 halftone-shadow";

  const variants = {
    cyan: "bg-[#7B99A5] text-[#1A1C1E] border-b-[8px] border-[#4A5E68]", 
    indigo: "bg-[#9FAF90] text-[#1A1C1E] border-b-[8px] border-[#5E6A56]", 
    pink: "bg-[#D98A7F] text-[#F2E9E1] border-b-[8px] border-[#8C4F48]", 
    amber: "bg-[#D4AF37] text-[#1A1C1E] border-b-[8px] border-[#8C7424]", 
    green: "bg-[#A3B18A] text-[#1A1C1E] border-b-[8px] border-[#588157]",
    coral: "bg-[#BC4749] text-[#F2E9E1] border-b-[10px] border-[#8C2A2B] border-t-white/10",
    white: "bg-[#F2E9E1] text-[#1A1C1E] border-b-[8px] border-[#D6C5B3]",
    bakelite: "bg-[#262A2E] text-[#F2E9E1] border-b-[12px] border-black border-t-white/5",
    ribbon: "bg-[#6A1B1D] text-[#F2E9E1] border-b-[10px] border-[#262A2E]" 
  };

  const sizes = {
    sm: "px-4 py-2 text-[10px]",
    md: "px-8 py-4 text-xl",
    lg: "px-12 py-6 text-3xl"
  };

  return (
    <div className={`relative ${className}`}>
      <button 
        onClick={handleInternalClick} 
        disabled={disabled}
        className={`
          ${baseStyles} 
          ${variants[variant as keyof typeof variants] || variants.cyan} 
          ${sizes[size]} 
          ${disabled ? 'opacity-30 grayscale cursor-not-allowed' : 'cursor-pointer'}
