import React, { useState, useEffect } from 'react';
import { Cube3D } from '../components/Cube3D';

interface LoadingScreenProps {
  backgroundUrl?: string;
  onFinished?: () => void;
}

export const LoadingScreen: React.FC<LoadingScreenProps> = ({ backgroundUrl, onFinished }) => {
  const [progress, setProgress] = useState(0);
  const [isAssembling, setIsAssembling] = useState(false);
  const letters = "LUMINA".split("");

  const technicolorColors = [
    "#D98A7F", // Coral
    "#9FAF90", // Sage
    "#D4AF37", // Mustard
    "#7B99A5", // Dusty Blue
    "#A3B18A", // Khaki Sage
    "#BC4749"  // Deep Coral
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return Math.min(prev + 0.8, 100);
      });
    }, 20);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (progress === 100) {
      const timer = setTimeout(() => {
        setIsAssembling(true);
        setTimeout(() => { if (onFinished) onFinished(); }, 1200);
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [progress, onFinished]);

  return (
    <div className="absolute inset-0 bg-[#7B99A5] flex flex-col items-center justify-center p-8 overflow-hidden">

      {/* Background Paper Texture */}
      <div className="absolute inset-0 opacity-40 bg-[url('https://www.transparenttextures.com/patterns/linen.png')] mix-blend-multiply" />

      {/* Studio Lighting - Top Left */}
      <div className="absolute inset-0 bg-gradient-to-br from-white/10 via-transparent to-black/20 pointer-events-none" />

      {/* Mid-Century Stamped Logo */}
      <div className={`z-20 text-center mb-16 relative transition-all duration-1000 ${isAssembling ? 'opacity-0 scale-95 blur-md' : 'opacity-100'}`}>
        <h1 className="text-7xl font-[900] tracking-tighter text-[#1A1C1E] display-font ink-bleed color-fringe">
          LUMINA
        </h1>
        <div className="h-1 w-24 bg-[#1A1C1E]/20 mx-auto mt-4" />
        <p className="text-[#1A1C1E] font-[900] text-[10px] tracking-[0.8em] mt-4 uppercase opacity-40 display-font">PROTOKOL ONAYI</p>
      </div>

      {/* Floating Matte Cubes */}
      <div className="relative w-80 h-80 mb-24 z-30 flex items-center justify-center">
        {letters.map((char, i) => {
          const orbitRotation = (progress * (1 + i * 0.1) + (i * 60));
          const orbitRadius = 110;

          const x = isAssembling ? (i - 2.5) * 52 : Math.cos(orbitRotation * Math.PI / 180) * orbitRadius;
          const y = isAssembling ? 0 : Math.sin(orbitRotation * Math.PI / 180) * orbitRadius;

          return (
            <div 
              key={i}
              className="absolute transition-all duration-[1000ms] ease-[cubic-bezier(0.34,1.56,0.64,1)]"
              style={{
                transform: `translate(${x}px, ${y}px)`,
                zIndex: isAssembling ? 100 : 10
              }}
            >
              <Cube3D 
                size={48} 
                speed={0} 
                label={char}
                visualStyle="CERAMIC"
                color={technicolorColors[i]}
              />
            </div>
          );
        })}
      </div>

      <div className={`w-full max-w-[240px] z-20 flex flex-col items-center transition-all duration-700 ${isAssembling ? 'opacity-0' : 'opacity-100'}`}>
        <div className="h-3 w-full bg-black/15 border border-black/10 p-0.5 rounded-sm overflow-hidden halftone-shadow">
          <div 
            className="h-full bg-[#D4AF37] transition-all duration-300 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
        <span className="text-[10px] font-[900] tracking-[0.5em] text-[#1A1C1E] uppercase mt-6 opacity-30 display-font">
          YÜKLENİYOR
        </span>
      </div>
    </div>
  );
};

