import React, { useState, useEffect } from 'react';
import { UserStats } from '../types';
import { Button } from './Button';
import { SoundManager } from '../managers/SoundManager';

interface MissionsModalProps {
  onClose?: () => void;
  stats: UserStats;
  onClaimReward: (id: number, reward: number) => void;
}

const MISSIONS_REFRESH_INTERVAL = 24 * 60 * 60 * 1000;

export const MissionsModal: React.FC<MissionsModalProps> = ({ onClose, stats, onClaimReward }) => {
  const [timeLeft, setTimeLeft] = useState<string>("");

  useEffect(() => {
    const updateTimer = () => {
      const now = Date.now();
      const nextReset = stats.lastMissionsRefresh + MISSIONS_REFRESH_INTERVAL;
      const diff = Math.max(0, nextReset - now);
      const hours = Math.floor(diff / (1000 * 60 * 60));
      const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((diff % (1000 * 60)) / 1000);
      setTimeLeft(`${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`);
    };
    updateTimer();
    const interval = setInterval(updateTimer, 1000);
    return () => clearInterval(interval);
  }, [stats.lastMissionsRefresh]);

  const missionDefinitions = [
    { id: 1, title: "3 GEÇİT TAMAMLA", progress: Math.floor((stats.level - 1) / 6), total: 3, reward: 250, color: "#7B99A5", icon: "🛰️" },
    { id: 2, title: "500 COIN BİRİKTİR", progress: stats.coins, total: 500, reward: 100, color: "#D4AF37", icon: "🪙" },
    { id: 3, title: "10 YILDIZ TOPLA", progress: stats.stars, total: 10, reward: 400, color: "#BC4749", icon: "🎯" },
  ];

  return (
    <div className="w-full h-full flex flex-col bg-[#E6D5C3] overflow-hidden relative">
      <div className="absolute inset-0 opacity-40 bg-[url('https://www.transparenttextures.com/patterns/linen.png')] mix-blend-multiply pointer-events-none" />

      {onClose && (
        <button onClick={onClose} className="absolute top-8 right-8 w-12 h-12 bg-[#262A2E] border-2 border-white/10 rounded-sm flex items-center justify-center shadow-xl active:scale-90 transition-all z-[120]">
          <svg viewBox="0 0 24 24" fill="none" stroke="#F2E9E1" strokeWidth="4" className="w-5 h-5"><path d="M18 6L6 18M6 6l12 12" /></svg>
        </button>
      )}

      <div className="pt-24 pb-8 px-10 text-center shrink-0 z-20">
        <h1 className="text-6xl font-[900] text-[#1A1C1E] tracking-tighter uppercase display-font ink-bleed color-fringe">
          GÖREVLER
        </h1>
        <div className="mt-4 bg-[#262A2E]/5 border-y border-black/5 py-2">
           <span className="text-[9px] font-black text-[#1A1C1E]/30 uppercase tracking-[0.5em] display-font">SONRAKİ AKTARIM: {timeLeft}</span>
        </div>
      </div>

      <div className="flex-1 px-8 pb-32 flex flex-col gap-6 overflow-y-auto custom-scrollbar relative z-10">
        {missionDefinitions.map((mission) => {
          const isDone = mission.progress >= mission.total;
          const isClaimed = stats.claimedMissions.includes(mission.id);

          return (
            <div key={mission.id} className={`w-full bg-[#F2E9E1] border-2 border-black/5 rounded-sm p-6 halftone-shadow relative overflow-hidden flex flex-col ${isClaimed ? 'opacity-40 grayscale' : ''}`}>
               <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-5">
                    <div className="w-14 h-14 bg-[#262A2E]/5 rounded-sm flex items-center justify-center text-3xl border border-black/5 grayscale opacity-50">
                      {mission.icon}
                    </div>
                    <div>
                      <h4 className="text-[#1A1C1E] font-[900] text-lg uppercase tracking-tighter leading-none mb-1 display-font ink-bleed">{mission.title}</h4>
                      <span className="text-[10px] font-black tracking-widest text-[#BC4749] display-font">+{mission.reward} 🪙 ÖDÜL</span>
                    </div>
                  </div>

                  {isDone && !isClaimed && (
                    <Button 
                      variant="amber" 
                      onClick={() => {
                        SoundManager.getInstance().playCoin();
                        onClaimReward(mission.id, mission.reward);
                      }}
                      className="!py-2 !px-4 !text-[10px] !w-24 !border-b-[4px]"
                    >
                      KAYDET
                    </Button>
                  )}
               </div>

               {/* Manual Gauge Progress - Typewriter style */}
               <div className="flex flex-col gap-2">
                  <div className="flex justify-between items-center text-[8px] font-black uppercase tracking-[0.3em] opacity-40 display-font">
                    <span>İLERLEME DURUMU</span>
                    <span>{Math.min(mission.progress, mission.total)} / {mission.total}</span>
                  </div>
                  <div className="w-full h-3 bg-black/5 rounded-sm border border-black/5 p-0.5">
                    <div 
                      className="h-full transition-all duration-1000" 
                      style={{ 
                        width: `${(Math.min(mission.progress, mission.total) / mission.total) * 100}%`,
                        backgroundColor: mission.color
                      }} 
                    />
                  </div>
               </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { SoundManager } from '../managers/SoundManager';

interface SideMenuProps {
  onExit: () => void;
  onToggle?: (isOpen: boolean) => void;
  className?: string;
  isMinimal?: boolean; 
  expandDirection?: 'up' | 'down';
}

export const SideMenu: React.FC<SideMenuProps> = ({ 
  onExit, 
  onToggle, 
  className = "", 
  isMinimal = false,
  expandDirection = 'down'
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [musicMuted, setMusicMuted] = useState(false);

  const handleToggle = () => {
    const newState = !isOpen;
    setIsOpen(newState);
    if (onToggle) onToggle(newState);
  };

  const handleMuteToggle = () => {
    const newMuted = !musicMuted;
    setMusicMuted(newMuted);
    SoundManager.getInstance().setMute(newMuted);
  };

  const menuButtons = [
    {
      id: 'exit',
      icon: (
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="w-4 h-4 ink-bleed">
          <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4M16 17l5-5-5-5M21 12H9" />
        </svg>
      ),
      color: "bg-[#BC4749]", // Deep Coral
      borderColor: "border-black/20",
      onClick: () => {
        setIsOpen(false);
        if (onToggle) onToggle(false);
        onExit();
      }
    },
    {
      id: 'music',
      icon: (
        <div className="relative ink-bleed">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="w-4 h-4">
            <path d="M9 18V5l12-2v13M9 18a3 3 0 1 1-6 0 3 3 0 0 1 6 0zm12-2a3 3 0 1 1-6 0 3 3 0 0 1 6 0z" />
          </svg>
          {musicMuted && <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-5 h-0.5 bg-black/40 rotate-45 rounded-full" />}
        </div>
      ),
      color: "bg-[#7B99A5]", // Dusty Blue
      borderColor: "border-black/20",
      onClick: handleMuteToggle
    }
  ];

  if (isMinimal) {
    const expandStyles = expandDirection === 'up' 
      ? 'bottom-[48px] origin-bottom' 
      : 'top-[48px] origin-top';

    return (
      <div className={`relative flex flex-col items-center z-[130] ${className}`}>
        <div className={`absolute ${expandStyles} flex flex-col gap-3 transition-all duration-500 z-[140] ${isOpen ? 'scale-100 opacity-100 translate-y-0' : 'scale-0 opacity-0 translate-y-[-10px] pointer-events-none'}`}>
          {menuButtons.map((btn) => (
            <button
              key={btn.id}
              onClick={btn.onClick}
              className={`w-10 h-10 rounded-sm ${btn.color} border-2 ${btn.borderColor} flex items-center justify-center text-[#F2E9E1] shadow-md active:translate-y-1 transition-all border-b-[6px] halftone-shadow relative overflow-hidden`}
            >
              <div className="absolute inset-0 bg-white/5 pointer-events-none" />
              {btn.icon}
            </button>
          ))}
        </div>

        <button
          onClick={handleToggle}
          className={`w-10 h-10 rounded-sm bg-[#262A2E] border-2 border-white/10 flex items-center justify-center text-[#F2E9E1] shadow-lg active:translate-y-1 transition-all relative overflow-hidden z-[150] halftone-shadow ${isOpen ? 'rotate-90' : ''}`}
        >
          <div className="absolute inset-0 bg-white/5" />
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" className="w-5 h-5 ink-bleed">
            <path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.08a2 2 0 0 1-1-1.74v-.5a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.38a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z"/><circle cx="12" cy="12" r="3"/></svg>
        </button>
      </div>
    );
  }

  return null; // Minimal dışı kullanımı şu anlık ana HUB yönetiyor
};

import React, { useState, useEffect } from 'react';
import { GameState, UserStats, HubSubView } from './types';
import { LoadingScreen } from './screens/LoadingScreen';
import { HubScreen } from './screens/HubScreen';
import { MemoryGame } from './screens/MemoryGame';
import { WordPuzzle } from './screens/WordPuzzle';
import { LevelCompleteModal } from './components/LevelCompleteModal';
import { LevelFailModal } from './components/LevelFailModal';
import { ChestModal } from './components/ChestModal';
import { MemoryTransitionModal } from './components/MemoryTransitionModal';
import { auth, fetchCloudStats, syncUserStats, reconcileStats } from './lib/firebase';
import { onAuthStateChanged, User } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

const STORAGE_KEY = 'lumina_stats';
const DEFAULT_BG = "https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&q=80&w=1080&h=1920";

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.LOADING);
  const [hubSubView, setHubSubView] = useState<HubSubView>(HubSubView.MAIN);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { console.error(e); }
    }
    return {
      coins: 2063, hearts: 5, stars: 12, level: 1,
      lastLifeRefillTime: Date.now(),
      hintsFreeze: 3, hintsReveal: 3,
      claimedMissions: [],
      lastMissionsRefresh: Date.now(),
      difficultyFactor: 1.0, performanceHistory: [],
      streak: 0, maxStreak: 0
    };
  });

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      setCurrentUser(user);
      if (user) {
        setIsSyncing(true);
        const cloudData = await fetchCloudStats(user.uid);
        if (cloudData) {
          const merged = reconcileStats(stats, cloudData);
          setStats(merged);
        }
        setIsSyncing(false);
      }
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stats));
    if (currentUser) {
      const timeout = setTimeout(async () => {
        setIsSyncing(true);
        await syncUserStats(currentUser.uid, stats, currentUser.displayName || "", currentUser.photoURL || "");
        setIsSyncing(false);
      }, 2000);
      return () => clearTimeout(timeout);
    }
  }, [stats, currentUser]);

  const [targetWords, setTargetWords] = useState<string[]>([]);
  const [fullWordPool, setFullWordPool] = useState<string[]>([]);
  const [showChest, setShowChest] = useState(false);
  const [bonusEarned, setBonusEarned] = useState(0);
  const [sessionScore, setSessionScore] = useState(0);
  const [starsEarnedInLevel, setStarsEarnedInLevel] = useState(0);
  const [transitionState, setTransitionState] = useState<'idle' | 'animating'>('idle');

  const changeGameState = (newState: GameState) => {
    setTransitionState('animating');
    setTimeout(() => {
      setGameState(newState);
      setTransitionState('idle');
    }, 400);
  };

  const updateStats = (updates: Partial<UserStats>) => {
    setStats(prev => ({ ...prev, ...updates }));
  };

  const handleStartGame = () => {
    if (stats.hearts > 0) {
      setSessionScore(0);
      changeGameState(GameState.WORD_PUZZLE);
    } else {
      setHubSubView(HubSubView.SHOP);
    }
  };

  const handleExitWithPenalty = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.HUB);
  };

  const handlePuzzleComplete = (earned: number, allTargets: string[], allDistractors: string[]) => {
    setSessionScore(earned);
    setTargetWords(allTargets);
    const pooledWords = [...allTargets, ...allDistractors].sort(() => Math.random() - 0.5);
    setFullWordPool(pooledWords);
    changeGameState(GameState.MEMORY_PREPARE);
  };

  const handleGameComplete = (correctCount: number) => {
    let stars = correctCount === 5 ? 3 : correctCount >= 4 ? 2 : 1;
    let bonus = correctCount * 50;
    setStarsEarnedInLevel(stars);
    setBonusEarned(bonus);
    changeGameState(GameState.LEVEL_COMPLETE);
  };

  const handleLevelFail = () => {
    updateStats({ hearts: Math.max(0, stats.hearts - 1) });
    changeGameState(GameState.LEVEL_FAIL);
  };

  const handleBuyItem = (cost: number, type: 'HEART' | 'FREEZE' | 'REVEAL', amount: number) => {
    if (stats.coins < cost) return;
    setStats(prev => {
      const next = { ...prev, coins: prev.coins - cost };
      if (type === 'HEART') next.hearts = Math.min(5, prev.hearts + amount);
      if (type === 'FREEZE') next.hintsFreeze += amount;
      if (type === 'REVEAL') next.hintsReveal += amount;
      return next;
    });
  };

  const renderScreen = () => {
    switch (gameState) {
      case GameState.LOADING: return <LoadingScreen onFinished={() => changeGameState(GameState.HUB)} />;
      case GameState.HUB: return <HubScreen stats={stats} currentUser={currentUser} isSyncing={isSyncing} hubSubView={hubSubView} setHubSubView={setHubSubView} onStartGame={handleStartGame} onAddCoins={(amt) => updateStats({ coins: stats.coins + amt })} onBuyHearts={(c, a) => handleBuyItem(c, 'HEART', a)} onOpenChest={() => setShowChest(true)} onClaimMission={(id, reward) => updateStats({ coins: stats.coins + reward, claimedMissions: [...stats.claimedMissions, id] })} />;
      case GameState.WORD_PUZZLE: return <WordPuzzle stats={stats} onComplete={handlePuzzleComplete} onExit={handleExitWithPenalty} onUpdateStats={updateStats} />;
      case GameState.MEMORY_PREPARE: return <MemoryTransitionModal onConfirm={() => changeGameState(GameState.MEMORY_GAME)} onExit={handleExitWithPenalty} />;
      case GameState.MEMORY_GAME: return <MemoryGame stats={stats} backgroundUrl={DEFAULT_BG} words={fullWordPool} targetWords={targetWords} onNext={handleGameComplete} onFail={handleLevelFail} onExit={handleExitWithPenalty} initialScore={sessionScore} />;
      case GameState.LEVEL_COMPLETE: return <LevelCompleteModal level={stats.level} coinsEarned={sessionScore + bonusEarned} starsEarned={starsEarnedInLevel} onContinue={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); handleStartGame(); }} onMenu={() => { setStats(p => ({...p, level: p.level + 1, coins: p.coins + sessionScore + bonusEarned, stars: p.stars + starsEarnedInLevel})); changeGameState(GameState.HUB); }} />;
      case GameState.LEVEL_FAIL: return <LevelFailModal hearts={stats.hearts} lastLifeRefillTime={stats.lastLifeRefillTime} onRetry={() => { if(stats.hearts > 0) changeGameState(GameState.WORD_PUZZLE); else setHubSubView(HubSubView.SHOP); }} onShop={() => { changeGameState(GameState.HUB); setHubSubView(HubSubView.SHOP); }} onExit={() => changeGameState(GameState.HUB)} />;
      default: return <LoadingScreen />;
    }
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-[#E6D5C3] overflow-hidden select-none">
      {/* Heavy Paper Texture Overlay */}
      <div className="absolute inset-0 opacity-[0.45] bg-[url('https://www.transparenttextures.com/patterns/linen.png')] mix-blend-multiply pointer-events-none z-[10000]" />

      {/* Surreal Background Instrument - Stamped Ink Effect */}
      <div className="giant-gear top-[-200px] left-[-200px] ink-bleed opacity-[0.05]">
        <svg viewBox="0 0 100 100">
          <path fill="currentColor" d="M50 35a15 15 0 1 0 0 30 15 15 0 0 0 0-30zm0 4a11 11 0 1 1 0 22 11 11 0 0 1 0-22zM48 2l2 8h-4l2-8zm13.7 4.1l-1.5 8.3-3.9-1 1.5-8.3 3.9 1zm12.3 9.4l-4.7 6.9-3.2-2.3 4.7-6.9 3.2 2.3zM85.9 28l-6.9 4.7-2.3-3.2 6.9-4.7 2.3 3.2zM94.9 44l-8.3 1.5-1-3.9 8.3-1.5 1 3.9zM98 60l-8.3-1.5 1-3.9 8.3 1.5-1 3.9zm-9.4 13.7l-6.9-4.7 3.2-2.3 6.9-4.7-3.2 2.3zm-12.3 12.3l-4.7-6.9 3.2-2.3 4.7 6.9-3.2 2.3zM56 94.9l-1.5-8.3 3.9-1 1.5 8.3-3.9 1zm-16 3.1l-1.5-8.3 3.9-1 1.5 8.3-3.9 1zm-13.7-9.4l1.5-8.3 3.9 1-1.5 8.3-3.9-1zm-12.3-12.3l4.7-6.9 3.2 2.3-4.7 6.9-3.2-2.3zm-9.4-13.7l6.9-4.7 2.3 3.2-6.9 4.7-2.3-3.2zM5.1 44l8.3-1.5 1 3.9-8.3 1.5-1-3.9zM2 28l8.3 1.5-1 3.9-8.3-1.5-1-3.9zM6.1 13.7l6.9 4.7-3.2 2.3-6.9-4.7 3.2-2.3zm9.4-12.3l4.7 6.9-3.2 2.3-4.7-6.9 3.2-2.3zM44 2l-1.5 8.3-3.9-1L40 2h4z" />
        </svg>
      </div>

      <div className="shadowbox-container">
        <div className={`w-full h-full transition-all duration-600 ease-out ${transitionState === 'animating' ? 'opacity-0 scale-98 blur-sm' : 'opacity-100 scale-100'}`}>
          {renderScreen()}
        </div>
      </div>

      {showChest && <ChestModal onClose={() => setShowChest(false)} onReward={(amt) => updateStats({ coins: stats.coins + amt })} />}
    </div>
  );
};

