const BASE_NAMES = ["DÜNYA", "MARS", "VENÜS", "MERKÜR", "JÜPİTER", "SATÜRN", "URANÜS", "NEPTÜN", "PLÜTON", "LUMINA"];

const PLANETS = Array.from({ length: 100 }, (_, i) => {
  const id = i + 1;
  const name = id === 100 ? "LUMINA" : `${BASE_NAMES[i % (BASE_NAMES.length - 1)]}-${Math.floor(i / 10) + 1}`;

  // Kelly Boesch Technicolor Palette
  const paletteColors = ['#7B99A5', '#D98A7F', '#9FAF90', '#D4AF37', '#A3B18A'];
  const planetColor = id === 100 ? '#D4AF37' : paletteColors[i % paletteColors.length];

  return {
    id,
    name,
    color: planetColor
  };
});

