        </h1>
        <p className="text-[#1A1C1E]/30 font-black text-[10px] tracking-[0.5em] uppercase mt-4 display-font">KOZMİK ARŞİV KAYITLARI</p>
      </div>

      {/* Navigation Controls - Physical Bakelite Buttons */}
      <div className="absolute right-8 top-1/2 -translate-y-1/2 flex flex-col gap-6 z-[120]">
        <button onClick={scrollToTop} className="w-14 h-14 bg-[#7B99A5] border-b-[8px] border-black/20 rounded-sm flex items-center justify-center text-[#F2E9E1] shadow-xl active:translate-y-1 transition-all halftone-shadow">
