        <button onClick={scrollToBottom} className="w-14 h-14 bg-[#BC4749] border-b-[8px] border-black/20 rounded-sm flex items-center justify-center text-[#F2E9E1] shadow-xl active:translate-y-1 transition-all halftone-shadow">
