        </button>
      </div>

      <div ref={scrollContainerRef} className="flex-1 overflow-y-auto p-10 space-y-24 custom-scrollbar pb-60 pt-6 relative z-10">
        {sortedPlanets.map((planet) => {
          const isCompleted = currentLevel > planet.id * 6;
          const isCurrent = !isCompleted && currentLevel > (planet.id - 1) * 6;
          const isLocked = !isCompleted && !isCurrent;
          const isLumina = planet.id === 100;

          return (
            <div key={planet.id} id={`planet-${planet.id}`} className={`relative w-full flex flex-col items-center transition-all duration-700 ${isLocked ? 'opacity-30 scale-95' : 'opacity-100 scale-100'}`}>

              <div 
                className={`w-full bg-[#F2E9E1] border-2 border-black/5 rounded-sm p-8 shadow-md relative transition-all flex flex-col items-center halftone-shadow ${isCurrent ? 'rotate-1 scale-[1.02] border-[#D4AF37]/40' : ''}`}
