                <div className="absolute inset-0 opacity-[0.1] bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')] pointer-events-none" />

                <div className="relative z-10 flex flex-col items-center">
                    <div className={`mb-8 transition-all duration-1000 ${isCurrent ? 'scale-110' : 'scale-100'}`}>
                        {isLumina ? (
                          <Cube3D 
                            size={90} 
                            color={isLocked ? '#C8B6A2' : planet.color} 
                            speed={isLocked ? 0 : 2} 
                            label="L"
                            visualStyle="CERAMIC"
                            opacity={isLocked ? 0.3 : 1}
                            rotationAxis="TUMBLE"
                          />
                        ) : (
                          <Sphere3D 
                            size={76} 
                            color={planet.color} 
                            label={isLocked ? "?" : planet.id.toString()} 
                            isLocked={isLocked} 
                            isCurrent={isCurrent}
