                    {isCompleted ? (
                        <div className="px-5 py-2 bg-[#9FAF90] border-2 border-black/10 rounded-sm shadow-sm halftone-shadow border-b-[6px]">
                            <span className="text-[#1A1C1E] font-[900] text-[9px] uppercase tracking-[0.4em] display-font ink-bleed">TAMAMLANDI</span>
