                    )}
                </div>

                {/* Technical blueprint-like annotations */}
                <div className="absolute bottom-2 right-4 text-[8px] font-black text-black/5 uppercase tracking-widest display-font">
                   COORD: {planet.id * 14} / 1954-L
                </div>
              </div>

              {/* Connector Path (Dashed blueprint line) */}
              {planet.id !== 1 && (
                <div className="absolute -bottom-16 w-0.5 h-12 bg-dashed border-l border-black/10 opacity-30" />
