export const LevelCompleteModal: React.FC<LevelCompleteModalProps> = ({ 
  level, 
  coinsEarned, 
  starsEarned,
  onContinue,
  onMenu
}) => {
  const [visibleStars, setVisibleStars] = useState(0);
  const [displayCoins, setDisplayCoins] = useState(0);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    setIsLoaded(true);
    SoundManager.getInstance().playJackpot();

    const starTimer = setTimeout(() => {
      let count = 0;
      const interval = setInterval(() => {
        if (count < starsEarned) {
          count++;
          setVisibleStars(count);
          SoundManager.getInstance().playPop();
        } else {
          clearInterval(interval);
        }
      }, 500);
      return () => clearInterval(interval);
    }, 600);

    const coinTimer = setTimeout(() => {
      let start = 0;
      const end = coinsEarned;
      const counter = setInterval(() => {
        start += Math.ceil(coinsEarned / 30);
        if (start >= end) {
          setDisplayCoins(end);
          clearInterval(counter);
        } else {
          setDisplayCoins(start);
        }
      }, 30);
      return () => clearInterval(counter);
    }, 1200);

    return () => {
      clearTimeout(starTimer);
      clearTimeout(coinTimer);
    };
  }, [starsEarned, coinsEarned]);

  return (
    <div className="absolute inset-0 z-[500] flex flex-col items-center bg-[#1A1C1E] overflow-hidden font-montserrat select-none">
      <SuccessParticles />
      <div className="absolute inset-0 opacity-[0.3] bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] pointer-events-none z-[1]" />
      <div className="absolute inset-0 opacity-[0.15] bg-[url('https://www.transparenttextures.com/patterns/linen.png')] pointer-events-none z-[5]" />
      <div className="absolute top-0 left-0 right-0 h-1/2 bg-gradient-to-b from-white/[0.04] to-transparent pointer-events-none z-[2]" />

      <div className={`flex-1 w-full max-w-sm flex flex-col items-center px-10 pt-20 pb-10 z-10 transition-all duration-1000 ${isLoaded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'}`}>

