             <div className="w-2 h-2 rounded-full bg-[#9FAF90] opacity-50" />
             <span className="text-[11px] font-[900] text-[#9FAF90] tracking-[0.4em] uppercase ink-bleed opacity-70">SİNYAL ONAYLANDI</span>
          </div>

          <div className="relative mb-2">
