import React, { useState, useEffect } from 'react';
import { Button } from './Button';

interface LevelFailModalProps {
  hearts: number;
  lastLifeRefillTime: number;
  onRetry: () => void;
  onShop: () => void;
  onExit: () => void;
}

const REFILL_TIME = 10 * 60 * 1000;

export const LevelFailModal: React.FC<LevelFailModalProps> = ({ hearts, lastLifeRefillTime, onRetry, onShop, onExit }) => {
  const [countdown, setCountdown] = useState<string>("");

  useEffect(() => {
    if (hearts >= 5) return;
    const timer = setInterval(() => {
      const now = Date.now();
      const nextRefill = lastLifeRefillTime + REFILL_TIME;
      const remaining = Math.max(0, nextRefill - now);
      const mins = Math.floor(remaining / 60000);
      const secs = Math.floor((remaining % 60000) / 1000);
      setCountdown(`${mins}:${secs < 10 ? '0' : ''}${secs}`);
    }, 1000);
    return () => clearInterval(timer);
  }, [hearts, lastLifeRefillTime]);

  return (
    <div className="absolute inset-0 z-[500] flex flex-col items-center justify-center p-8 bg-[#D98A7F] overflow-hidden select-none">
      {/* Heavy Paper Grain Texture */}
      <div className="absolute inset-0 opacity-[0.4] bg-[url('https://www.transparenttextures.com/patterns/linen.png')] pointer-events-none z-[1]" />

      {/* Studio Lighting Shadow Simulation (Directional spotlight) */}
      <div className="absolute inset-0 bg-gradient-to-br from-white/10 via-transparent to-black/25 pointer-events-none z-[2]" />

      <div className={`flex-1 w-full max-w-sm flex flex-col items-center px-6 pt-20 pb-10 z-10 animate-[failPopIn_0.8s_ease-out]`}>

        {/* Header - Stamped Ink Style */}
        <div className="text-center w-full mb-12">
          <div className="inline-flex items-center gap-3 px-6 py-3 bg-[#1A1C1E]/10 border border-[#1A1C1E]/20 rounded-sm mb-10 halftone-shadow">
             <span className="text-[12px] font-[900] text-[#1A1C1E] tracking-[0.5em] uppercase ink-bleed opacity-60">SİSTEM HATASI</span>
          </div>

          <h1 className="text-[#1A1C1E] text-7xl font-[900] tracking-tighter uppercase leading-none display-font letterpress-ink ink-bleed color-fringe">
            BAĞLANTI<br/>KESİLDİ
          </h1>
          <p className="text-[#1A1C1E]/30 font-[900] text-[11px] tracking-[1em] uppercase mt-6">HATA KODU 1954-X</p>
        </div>

        {/* Physical Marble Fail Block */}
        <div className="relative mb-12 halftone-shadow">
          <div className="transform rotate-[3deg]">
            <div className="w-44 h-44 flex flex-col items-center justify-center p-6 border border-black/20 bg-[#E6D5C3] rounded-sm relative overflow-hidden">
              <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')]" />
              <span className="text-8xl letterpress-ink ink-bleed color-fringe filter grayscale relative z-10">💔</span>
              <div className="h-[2px] w-16 bg-[#1A1C1E]/10 my-4 relative z-10" />
              <div className="flex gap-2 relative z-10">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className={`w-3 h-3 rounded-full border border-black/10 ${i < hearts ? 'bg-[#BC4749]' : 'bg-black/5'}`} />
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Actions - Bakelite Style Buttons */}
        <div className="w-full mt-auto space-y-6">
          {hearts > 0 ? (
            <Button 
              variant="bakelite" 
              onClick={onRetry}
              className="w-full !py-8 !text-3xl"
            >
              YENİDEN DENE
            </Button>
          ) : (
            <Button 
              variant="white" 
              onClick={onShop}
              className="w-full !py-8 !text-3xl"
            >
              CAN AL {countdown ? `(${countdown})` : ''}
            </Button>
          )}

          <button 
            onClick={onExit}
            className="w-full py-4 text-[#1A1C1E]/20 hover:text-[#1A1C1E]/40 font-[900] uppercase text-[12px] tracking-[0.6em] transition-all display-font"
          >
            ANA KUMANDA
          </button>
        </div>
      </div>

      <style>{`
        @keyframes failPopIn {
          0% { opacity: 0; transform: scale(1.1) translateY(20px); filter: blur(10px); }
          100% { opacity: 1; transform: scale(1) translateY(0); filter: blur(0); }
        }
      `}</style>
    </div>
  );
};

