interface MissionsModalProps {
  onClose?: () => void;
  stats: UserStats;
  onClaimReward: (id: number, reward: number) => void;
}

const MISSIONS_REFRESH_INTERVAL = 24 * 60 * 60 * 1000;

const MissionStamp = ({ type }: { type: string }) => {
  switch (type) {
    case 'sat': return (
      <svg viewBox="0 0 24 24" fill="currentColor" className="w-8 h-8 opacity-60"><path d="M21 16.5C21 16.88 20.79 17.21 20.47 17.38L12.57 21.82C12.41 21.94 12.21 22 12 22C11.79 22 11.59 21.94 11.43 21.82L3.53 17.38C3.21 17.21 3 16.88 3 16.5V7.5C3 7.12 3.21 6.79 3.53 6.62L11.43 2.18C11.59 2.06 11.79 2 12 2C12.21 2 12.41 2.06 12.57 2.18L20.47 6.62C20.79 6.79 21 7.12 21 7.5V16.5Z" fill="none" stroke="currentColor" strokeWidth="2" /><path d="M12 22V12M12 12L3.5 7.5M12 12L20.5 7.5" stroke="currentColor" strokeWidth="1.5" /></svg>
    );
    case 'coin': return (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="w-8 h-8 opacity-60"><circle cx="12" cy="12" r="9" /><circle cx="12" cy="12" r="4" /></svg>
    );
    case 'target': return (
      <svg viewBox="0 0 24 24" fill="currentColor" className="w-8 h-8 opacity-60"><circle cx="12" cy="12" r="9" fill="none" stroke="currentColor" strokeWidth="2" /><circle cx="12" cy="12" r="5" fill="none" stroke="currentColor" strokeWidth="1.5" /><circle cx="12" cy="12" r="1" /></svg>
    );
    default: return null;
  }
};

export const MissionsModal: React.FC<MissionsModalProps> = ({ onClose, stats, onClaimReward }) => {
  const [timeLeft, setTimeLeft] = useState<string>("");

  useEffect(() => {
    const updateTimer = () => {
      const now = Date.now();
      const nextReset = stats.lastMissionsRefresh + MISSIONS_REFRESH_INTERVAL;
      const diff = Math.max(0, nextReset - now);
      const hours = Math.floor(diff / (1000 * 60 * 60));
      const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((diff % (1000 * 60)) / 1000);
      setTimeLeft(`${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`);
    };
    updateTimer();
    const interval = setInterval(updateTimer, 1000);
    return () => clearInterval(interval);
  }, [stats.lastMissionsRefresh]);

  const missionDefinitions = [
    { id: 1, title: "3 GEÇİT TAMAMLA", progress: Math.floor((stats.level - 1) / 6), total: 3, reward: 250, color: "#7B99A5", stampType: "sat" },
    { id: 2, title: "500 COIN BİRİKTİR", progress: stats.coins, total: 500, reward: 100, color: "#D4AF37", stampType: "coin" },
    { id: 3, title: "10 YILDIZ TOPLA", progress: stats.stars, total: 10, reward: 400, color: "#BC4749", stampType: "target" },
  ];

  return (
    <div className="w-full h-full flex flex-col bg-[#E6D5C3] overflow-hidden relative">
      <div className="absolute inset-0 opacity-40 bg-[url('https://www.transparenttextures.com/patterns/linen.png')] mix-blend-multiply pointer-events-none" />

      {onClose && (
        <button onClick={onClose} className="absolute top-8 right-8 w-12 h-12 bg-[#262A2E] border-2 border-white/10 rounded-sm flex items-center justify-center shadow-xl active:scale-90 transition-all z-[120]">
          <svg viewBox="0 0 24 24" fill="none" stroke="#F2E9E1" strokeWidth="4" className="w-5 h-5"><path d="M18 6L6 18M6 6l12 12" /></svg>
        </button>
      )}

      <div className="pt-24 pb-8 px-10 text-center shrink-0 z-20">
        <h1 className="text-6xl font-[900] text-[#1A1C1E] tracking-tighter uppercase display-font ink-bleed color-fringe">
          GÖREVLER
        </h1>
        <div className="mt-4 bg-[#262A2E]/5 border-y border-black/5 py-2">
           <span className="text-[9px] font-black text-[#1A1C1E]/30 uppercase tracking-[0.5em] display-font">SONRAKİ AKTARIM: {timeLeft}</span>
        </div>
      </div>

      <div className="flex-1 px-8 pb-32 flex flex-col gap-6 overflow-y-auto custom-scrollbar relative z-10">
        {missionDefinitions.map((mission) => {
          const isDone = mission.progress >= mission.total;
          const isClaimed = stats.claimedMissions.includes(mission.id);

          return (
            <div key={mission.id} className={`w-full bg-[#F2E9E1] border-2 border-black/5 rounded-sm p-6 halftone-shadow relative overflow-hidden flex flex-col ${isClaimed ? 'opacity-40 grayscale' : ''}`}>
               <div className="absolute inset-0 opacity-5 bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')]" />
               <div className="flex justify-between items-start mb-6 relative z-10">
                  <div className="flex items-center gap-5">
                    <div className="w-14 h-14 bg-[#262A2E]/5 rounded-sm flex items-center justify-center text-3xl border border-black/5 grayscale opacity-50 ink-bleed">
                      <MissionStamp type={mission.stampType} />
                    </div>
                    <div>
                      <h4 className="text-[#1A1C1E] font-[900] text-lg uppercase tracking-tighter leading-none mb-1 display-font ink-bleed">{mission.title}</h4>
                      <span className="text-[10px] font-black tracking-widest text-[#BC4749] display-font">+{mission.reward} 🪙 ÖDÜL</span>
                    </div>
                  </div>

                  {isDone && !isClaimed && (
                    <Button 
                      variant="amber" 
                      onClick={() => {
                        SoundManager.getInstance().playCoin();
                        onClaimReward(mission.id, mission.reward);
                      }}
                      className="!py-2 !px-4 !text-[10px] !w-24 !border-b-[4px]"
                    >
                      KAYDET
                    </Button>
                  )}
               </div>

               <div className="flex flex-col gap-2 relative z-10">
                  <div className="flex justify-between items-center text-[8px] font-black uppercase tracking-[0.3em] opacity-40 display-font">
                    <span>İLERLEME DURUMU</span>
                    <span>{Math.min(mission.progress, mission.total)} / {mission.total}</span>
                  </div>
                  <div className="w-full h-3 bg-black/5 rounded-sm border border-black/5 p-0.5">
                    <div 
                      className="h-full transition-all duration-1000" 
                      style={{ 
                        width: `${(Math.min(mission.progress, mission.total) / mission.total) * 100}%`,
                        backgroundColor: mission.color
                      }} 
                    />
                  </div>
               </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

