  <div className={`relative flex flex-col items-center justify-center p-4 w-full aspect-[4/5] transition-all duration-500 halftone-shadow
    ${isToday ? 'bg-[#D4AF37] scale-105 z-10 rotate-1' : 'bg-[#F2E9E1] -rotate-2'} 
    ${isClaimed ? 'opacity-30 grayscale' : ''}
    border-2 border-black/10 rounded-sm overflow-hidden`}>

    <div className="absolute inset-0 opacity-[0.15] bg-[url('https://www.transparenttextures.com/patterns/cardboard-flat.png')] pointer-events-none" />

    <span className="text-[10px] font-black text-black/40 tracking-[0.3em] uppercase mb-auto ink-bleed">DAY {day}</span>

    <div className="relative my-3 w-12 h-12 flex items-center justify-center text-[#1A1C1E]">
      <div className="w-10 h-10 rounded-full bg-[#8C7424] border-2 border-black/30 shadow-inner flex items-center justify-center">
         <CoinStamp />
      </div>
      {isClaimed && <div className="absolute inset-0 flex items-center justify-center text-[#6A1B1D] text-3xl font-black rotate-12 opacity-60">✕</div>}
    </div>

    <span className="text-sm font-black text-black/70 mt-auto tabular-nums">{amount}</span>

    <div className="absolute -left-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-[#E6D5C3] rounded-full border border-black/10 shadow-inner" />
    <div className="absolute -right-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-[#E6D5C3] rounded-full border border-black/10 shadow-inner" />
  </div>
);

export const ChestModal: React.FC<ChestModalProps> = ({ onClose, onReward }) => {
  const [isOpened, setIsOpened] = useState(false);
  const [claimedDays, setClaimedDays] = useState<number[]>([]);

  const handleOpen = () => {
    if (isOpened) return;
    setIsOpened(true);
    SoundManager.getInstance().playJackpot();
    setTimeout(() => {
        onReward(250);
        setClaimedDays([1]); 
    }, 500);
  };

  const rewards = [
    { day: 1, amount: 250 },
    { day: 2, amount: 300 },
    { day: 3, amount: 400 },
    { day: 4, amount: 500 },
    { day: 5, amount: 750 },
    { day: 6, amount: 1000 },
    { day: 7, amount: 2500 },
  ];

  return (
    <div className="absolute inset-0 z-[400] flex items-center justify-center p-6 bg-[#E6D5C3]/95 backdrop-blur-md">
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[95%] h-[85%] bg-[#D4AF37]/15 -rotate-2 rounded-lg pointer-events-none halftone-shadow" />
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] h-[80%] bg-[#D98A7F]/10 rotate-3 rounded-lg pointer-events-none halftone-shadow" />

      <div className="w-full max-w-sm flex flex-col items-center animate-[popIn_0.4s_ease-out] text-center relative z-10">
        <div className="relative mb-12 cursor-pointer group" onClick={handleOpen}>
           <div className={`relative transition-all duration-1000 transform ${isOpened ? 'scale-125 -translate-y-10' : 'hover:scale-105 active:scale-95'}`}>
              <div className={`w-44 h-36 bg-[#C2B280] border-2 border-black/15 shadow-2xl relative transition-all duration-1000 ${isOpened ? 'opacity-0 scale-50' : 'opacity-100'}`}>
                 <div className="absolute inset-0 opacity-[0.25] bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')]" />
                 <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-full h-2 bg-gradient-to-r from-[#6A1B1D] via-white to-[#6A1B1D] bg-[length:12px_100%] border-y border-black/10" />
                    <div className="absolute w-2 h-full bg-gradient-to-b from-[#6A1B1D] via-white to-[#6A1B1D] bg-[length:100%_12px] border-x border-black/10" />
                    <div className="absolute w-10 h-10 border-2 border-white rounded-full bg-[#6A1B1D] shadow-xl flex items-center justify-center -rotate-15 halftone-shadow">
                       <span className="text-white text-[10px] font-black">L</span>
                    </div>
                 </div>
                 <div className="absolute inset-0 border-t-4 border-l-4 border-white/20 pointer-events-none" />
              </div>

              {isOpened && (
                <div className="absolute inset-0 flex flex-col items-center justify-center animate-[floatReward_3s_ease-out_infinite]">
                  <div className="w-28 h-28 bg-[#D4AF37] rounded-full border-[6px] border-white shadow-2xl flex items-center justify-center halftone-shadow text-[#1A1C1E]">
                    <div className="scale-[2.5]"><CoinStamp /></div>
                  </div>
                  <div className="bg-[#F2E9E1] px-5 py-2 mt-6 border-2 border-black/10 rotate-3 halftone-shadow">
                    <span className="text-[#1A1C1E] font-black text-3xl tracking-tighter letterpress-ink color-fringe">+250</span>
                  </div>
                </div>
              )}
           </div>
        </div>

        <h2 className="text-5xl font-[900] text-[#1A1C1E] tracking-tighter mb-10 uppercase letterpress-ink color-fringe ink-bleed">
           {isOpened ? 'DEPOSITED' : 'STATION LOG'}
        </h2>

        <div className="grid grid-cols-4 gap-3 w-full mb-12">
          {rewards.map((r) => (
            <DailyRewardItem 
              key={r.day} 
              day={r.day} 
              amount={r.amount} 
              isClaimed={claimedDays.includes(r.day)} 
              isToday={r.day === 1} 
            />
          ))}
          <div className="col-span-1 bg-[#D98A7F]/15 border-2 border-dashed border-black/15 rounded-sm flex items-center justify-center halftone-shadow">
            <span className="text-[9px] font-black opacity-40 tracking-[0.5em] uppercase rotate-90 ink-bleed">QUEST</span>
          </div>
        </div>

        <div className="w-full flex flex-col gap-4">
          {isOpened ? (
            <Button 
              variant="bakelite" 
              onClick={onClose} 
              className="w-full !py-6 !text-2xl"
            >
              <div className="flex flex-col items-center">
                <span className="text-[10px] opacity-40 font-black uppercase tracking-[0.6em] mb-2 ink-bleed">STAMP RECORD</span>
                <span className="font-black">BACK TO COMMAND</span>
              </div>
            </Button>
          ) : (
            <div className="flex flex-col gap-4">
              <Button 
                variant="coral"
                onClick={handleOpen}
                className="w-full !py-7 !text-3xl"
              >
                UNWRAP LOG
              </Button>

              <button className="flex items-center justify-center gap-3 text-[11px] font-black text-black/40 uppercase tracking-[0.4em] hover:text-black/60 transition-colors py-2 group">
                <span className="ink-bleed">WATCH REEL FOR 2X</span>
                <div className="w-12 h-[1px] bg-black/20 group-hover:w-20 transition-all" />
              </button>
            </div>
          )}
        </div>
      </div>

      <style>{`
        @keyframes popIn {
          0% { transform: scale(0.6); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        @keyframes floatReward {
          0%, 100% { transform: translateY(0px) rotate(3deg); }
          50% { transform: translateY(-20px) rotate(-3deg); }
        }
      `}</style>
    </div>
  );
};

