  setHubSubView, 
  onStartGame, 
  onAddCoins, 
  onBuyHearts,
  onOpenChest,
  onClaimMission
}) => {
  const isMain = hubSubView === HubSubView.MAIN;
  const isLeftSideView = hubSubView === HubSubView.PLANETS || hubSubView === HubSubView.LEAGUE || hubSubView === HubSubView.SETTINGS;
  const isRightSideView = hubSubView === HubSubView.SHOP || hubSubView === HubSubView.MISSIONS || hubSubView === HubSubView.PROFILE;
  const stageTransform = isLeftSideView ? 'translateX(100%)' : isRightSideView ? 'translateX(-100%)' : 'translateX(0)';

  const navItems = [
    { view: HubSubView.PLANETS, color: '#7B99A5', icon: Icons.Planets },
    { view: HubSubView.LEAGUE, color: '#9FAF90', icon: Icons.League },
    { view: HubSubView.MAIN, isCustom: true, color: '#D4AF37', icon: Icons.Main },
    { view: HubSubView.MISSIONS, color: '#D98A7F', icon: Icons.Missions },
    { view: HubSubView.SHOP, color: '#BC4749', icon: Icons.Shop },
  ];

  return (
    <div className="absolute inset-0 flex flex-col overflow-hidden bg-[#E6D5C3]">
