        <div className="absolute top-28 left-8 flex flex-col gap-6 z-[40] pointer-events-auto">
          <button onClick={onOpenChest} className="w-14 h-14 bg-[#D4AF37] border-2 border-black/20 rounded-sm flex items-center justify-center active:translate-y-1 transition-all shadow-md halftone-shadow relative overflow-hidden group">
             <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/linen.png')]" />
             <div className="relative z-10 text-[#1A1C1E] grayscale group-hover:grayscale-0 transition-all ink-bleed">
               <Icons.Gift />
             </div>
          </button>
          <button onClick={() => onAddCoins(50)} className="w-14 h-14 bg-[#7B99A5] border-2 border-black/20 rounded-sm flex items-center justify-center active:translate-y-1 transition-all shadow-md halftone-shadow relative overflow-hidden group">
             <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/linen.png')]" />
             <div className="relative z-10 text-[#1A1C1E] grayscale group-hover:grayscale-0 transition-all ink-bleed">
               <Icons.TV />
             </div>
          </button>
        </div>
      </div>

      <div className="flex-1 w-full relative transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] z-[150]" style={{ transform: stageTransform }}>
        <div className="absolute top-0 -left-full w-full h-full z-[160] overflow-hidden bg-[#E6D5C3]">
          {hubSubView === HubSubView.PLANETS && <PlanetMenuModal onClose={() => setHubSubView(HubSubView.MAIN)} currentLevel={stats.level} />}
          {hubSubView === HubSubView.LEAGUE && <RankingModal onClose={() => setHubSubView(HubSubView.MAIN)} stats={stats} />}
          {hubSubView === HubSubView.SETTINGS && <SettingsModal onClose={() => setHubSubView(HubSubView.MAIN)} />}
        </div>

        <div className={`w-full h-full flex flex-col items-center transition-all duration-700 z-[10] ${!isMain ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}>
            <div className="flex-1 w-full flex flex-col items-center justify-center p-8 relative">
               <Portal3D level={stats.level} active={isMain} />
            </div>
            <div className={`w-full flex flex-col items-center mb-36 px-16 z-20 transition-opacity duration-500 ${!isMain ? 'opacity-0' : 'opacity-100'}`}>
                <Button variant="coral" onClick={onStartGame} className="w-full !h-24 !rounded-sm !text-5xl !border-b-[10px] !shadow-none halftone-shadow">BAŞLAT</Button>
                <p className="mt-8 text-[#1A1C1E]/30 font-[900] text-[10px] tracking-[0.8em] uppercase display-font">SİNYAL KARARLI</p>
            </div>
        </div>

        <div className="absolute top-0 left-full w-full h-full z-[160] overflow-hidden bg-[#E6D5C3]">
          {hubSubView === HubSubView.SHOP && <ShopModal coins={stats.coins} onBuyHearts={onBuyHearts} onClose={() => setHubSubView(HubSubView.MAIN)} />}
          {hubSubView === HubSubView.PROFILE && <ProfileModal level={stats.level} onClose={() => setHubSubView(HubSubView.MAIN)} />}
          {hubSubView === HubSubView.MISSIONS && <MissionsModal stats={stats} onClaimReward={onClaimMission} onClose={() => setHubSubView(HubSubView.MAIN)} />}
