                <button key={idx} onClick={() => setHubSubView(item.view as HubSubView)} className={`flex items-center justify-center relative transition-all duration-300 ${item.isCustom ? 'w-20 h-20 bg-[#F2E9E1] border-2 border-black/10 rounded-full -translate-y-8 shadow-xl halftone-shadow' : 'w-16 h-16'}`}>
                  <NavIcon active={hubSubView === item.view} color={item.color} IconComponent={item.icon} />
                </button>
              ))}
          </nav>
      </div>
    </div>
  );
};

