                  <div className="absolute top-1.5 right-1.5 w-1.5 h-1.5 bg-[#007FFF] rounded-full shadow-[0_0_6px_#007FFF] z-20 opacity-60" />
                  <div className="absolute bottom-1.5 left-1.5 w-1.5 h-1.5 bg-[#FFBF00] rounded-full shadow-[0_0_6px_#FFBF00] z-20 opacity-60" />
                </>
              )}

              {faceText && (
                <span 
                  className={`font-[900] select-none transition-all duration-700 uppercase whitespace-nowrap px-2 z-10
                    ${isRevealed ? 'opacity-100 scale-100' : 'opacity-0 scale-50'}`}
                  style={{ 
                    fontSize: Math.min(f.fw * 0.8 / (faceText.length || 1), f.fh * 0.7),
                    textShadow: visualStyle === 'ROYAL' 
                        ? '3px 3px 6px rgba(0,0,0,0.7), 0 0 12px rgba(255,223,0,0.6)'
                        : '0 2px 10px rgba(0,0,0,1)',
                    transform: 'translateZ(20px)',
                    color: visualStyle === 'ROYAL' ? '#4A3705' : 'white',
                    fontFamily: visualStyle === 'ROYAL' ? 'Montserrat' : 'inherit'
                  }}
                >
                  {faceText}
                </span>
              )}

              {/* Diamond cut highlights */}
              {visualStyle === 'ROYAL' && (
                <div className="absolute inset-0 border border-white/30 rotate-45 scale-[1.2] pointer-events-none" />
              )}
            </div>
          );
        })}
      </div>
    );
  };

  const isDrifting = !isSuccess && !isFail && !isSelected && speed > 0 && rotationAxis !== 'X' && rotationAxis !== 'Y';

  return (
    <div 
      className={`relative ${className} ${isDrifting ? 'animate-cube-drift' : ''}`} 
      style={{ 
        width: w, 
        height: h,
        perspective: '1000px',
        opacity
      }}
    >
      <div className={`w-full h-full ${getRotationClass()}`} style={{ transformStyle: 'preserve-3d', transition: 'all 0.5s ease-out' }}>
        {renderCube()}
      </div>
    </div>
  );
});

