          const orbitTransform = `translate(-50%, -50%) rotate(${currentRotation}deg) translateY(-120px)`;
          const assembledTransform = `translate(calc(-50% + ${assembleX}px), calc(-50% + ${assembleY}px)) rotate(0deg)`;

