import React, { memo } from 'react';

export type RotationAxis = 'X' | 'Y' | 'XY' | 'TUMBLE';
export type CubeVisualStyle = 'GLASS' | 'CRYSTAL' | 'METAL' | 'NEON' | 'GHOST' | 'DARK' | 'PLASMA' | 'CHROME' | 'LAVA' | 'AETHER' | 'VOID' | 'ROYAL';

interface Cube3DProps {
  size?: number;
  width?: number; 
  height?: number; 
  depth?: number; 
  className?: string;
  speed?: number;
  opacity?: number;
  label?: string;
  centerLabel?: string; 
  faceLabels?: string[]; 
  isGlassy?: boolean;
  color?: string;
  rotationAxis?: RotationAxis;
  visualStyle?: CubeVisualStyle;
  status?: 'idle' | 'success' | 'fail';
  delay?: number;
  isRevealed?: boolean;
  isSelected?: boolean;
}

export const Cube3D: React.FC<Cube3DProps> = memo(({ 
  size = 32,
  width,
  height,
  depth,
  className = "", 
  speed = 4,
  opacity = 1,
  label = "",
  centerLabel = "",
  faceLabels,
  isGlassy = true,
  color = "rgba(34, 211, 238, 1)",
  rotationAxis = 'XY',
  visualStyle = 'GLASS',
  status = 'idle',
  delay = 0,
  isRevealed = true,
  isSelected = false
}) => {
  const isSuccess = status === 'success';
  const isFail = status === 'fail';
  const mainText = (centerLabel || label);

  const w = width || size;
  const h = height || size;
  const d = depth || size;

  const overlap = 1.5; 

  const getRotationClass = () => {
    if (isSelected || isSuccess || speed === 0) return "";
    switch (rotationAxis) {
      case 'X': return "animate-cube-x";
      case 'Y': return "animate-cube-y";
      case 'XY': return "animate-cube-xy";
      case 'TUMBLE': return "animate-cube-tumble";
      default: return "animate-cube-xy";
    }
  };

  const renderCube = () => {
    let baseColor = color;
    if (isSuccess) baseColor = '#4ade80'; 
    if (isFail) baseColor = '#f87171';

    const faces = [
      { id: 'front', rot: 'rotateY(0deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'back', rot: 'rotateY(180deg)', tz: (d / 2), fw: w + overlap, fh: h + overlap },
      { id: 'right', rot: 'rotateY(90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'left', rot: 'rotateY(-90deg)', tz: (w / 2), fw: d + overlap, fh: h + overlap },
      { id: 'top', rot: 'rotateX(90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
      { id: 'bottom', rot: 'rotateX(-90deg)', tz: (h / 2), fw: w + overlap, fh: d + overlap },
    ];

    return (
      <div className="w-full h-full relative" style={{ transformStyle: 'preserve-3d' }}>
        {faces.map((f, i) => {
          const faceText = (faceLabels && faceLabels[i]) ? faceLabels[i] : mainText;

          let faceStyles: React.CSSProperties = {
            position: 'absolute',
            width: f.fw, 
            height: f.fh, 
            left: (w - f.fw) / 2, 
            top: (h - f.fh) / 2, 
            transform: `${f.rot} translate3d(0, 0, ${f.tz}px)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backfaceVisibility: 'hidden',
            borderRadius: Math.min(w, h) * 0.1, 
            transformStyle: 'preserve-3d',
            overflow: 'hidden'
          };

          switch(visualStyle) {
            case 'ROYAL':
              // High-gloss gold material with rich lighting
              faceStyles.background = `linear-gradient(135deg, #F7D021 0%, #B8860B 45%, #F7D021 55%, #DAA520 100%)`;
              faceStyles.border = `4px solid #FFF3A0`;
              faceStyles.boxShadow = `
                inset 0 0 15px rgba(0,0,0,0.6), 
                inset 3px 3px 0 rgba(255,255,255,0.7),
                0 5px 15px rgba(0,0,0,0.4),
                0 0 20px rgba(247,208,33,0.5)
              `;
              faceStyles.borderRadius = '12px';
              break;
            case 'CRYSTAL':
              faceStyles.background = `linear-gradient(135deg, ${baseColor}88 0%, #ffffff88 50%, ${baseColor}88 100%)`;
              faceStyles.border = `4px solid #ffffffaa`;
              faceStyles.boxShadow = `inset 0 0 20px #ffffff44, 0 0 15px ${baseColor}44`;
              faceStyles.backdropFilter = 'blur(12px)';
              break;
            case 'METAL':
              faceStyles.background = `linear-gradient(to bottom right, #ffffff66, #334155, #000000)`;
              faceStyles.border = `5px solid #94a3b8`;
              faceStyles.boxShadow = `inset 0 0 30px #000000aa`;
              break;
            case 'NEON':
              faceStyles.background = `rgba(2, 6, 23, 0.95)`;
              faceStyles.border = `2.5px solid ${baseColor}`;
              faceStyles.boxShadow = `0 0 12px ${baseColor}, 0 0 25px ${baseColor}44, inset 0 0 15px ${baseColor}88, inset 0 0 2px rgba(255,255,255,0.6)`;
              break;
            case 'PLASMA':
              faceStyles.background = `radial-gradient(circle, ${baseColor} 0%, transparent 80%)`;
              faceStyles.border = `2px solid rgba(255,255,255,0.1)`;
              faceStyles.boxShadow = `0 0 30px ${baseColor}aa, inset 0 0 50px ${baseColor}66`;
              faceStyles.backdropFilter = 'blur(5px)';
              break;
            case 'CHROME':
              faceStyles.background = `linear-gradient(160deg, #ffffff 0%, #94a3b8 40%, #0f172a 45%, #ffffff 50%, #1e293b 100%)`;
              faceStyles.border = `1px solid #ffffff`;
              faceStyles.boxShadow = `inset 0 0 10px rgba(0,0,0,0.5)`;
              break;
            case 'LAVA':
              faceStyles.background = `radial-gradient(circle, #f97316 0%, #450a0a 100%)`;
              faceStyles.border = `3px solid #fbbf24`;
              faceStyles.boxShadow = `0 0 20px #f97316, inset 0 0 15px #000000`;
              break;
            case 'AETHER':
              faceStyles.background = `rgba(255,255,255,0.05)`;
              faceStyles.border = `2px solid rgba(255,255,255,0.4)`;
              faceStyles.boxShadow = `0 0 15px rgba(255,255,255,0.2), inset 0 0 20px rgba(255,255,255,0.1)`;
              faceStyles.backdropFilter = 'blur(25px)';
              break;
            case 'VOID':
              faceStyles.background = `#000000`;
              faceStyles.border = `2px solid #a855f7`;
              faceStyles.boxShadow = `inset 0 0 30px #a855f7, 0 0 10px #a855f744`;
              break;
            case 'GHOST':
              faceStyles.background = `rgba(255,255,255,0.05)`;
              faceStyles.border = `1.5px dashed ${baseColor}88`;
              faceStyles.backdropFilter = 'blur(20px)';
              break;
            case 'DARK':
              faceStyles.background = `radial-gradient(circle, #1e1b4b, #020617)`;
              faceStyles.border = `3px solid #000000`;
              faceStyles.boxShadow = `inset 0 0 40px #000000`;
              break;
            default: // GLASS (Standard)
              faceStyles.background = isGlassy ? `linear-gradient(135deg, ${baseColor}66 0%, ${baseColor}11 100%)` : baseColor;
              faceStyles.border = isSelected ? '5px solid #ffffff' : `3.5px solid ${baseColor}`;
              faceStyles.backdropFilter = isGlassy ? 'blur(8px)' : 'none';
              faceStyles.boxShadow = `inset 0 0 15px ${baseColor}44`;
          }

          if (isSelected) {
            faceStyles.borderColor = '#ffffff';
            faceStyles.borderWidth = '6px';
          }

          return (
            <div key={i} style={faceStyles}>
              {/* Highlight Overlay */}
              <div className="absolute inset-0 bg-gradient-to-br from-white/40 via-transparent to-black/30 pointer-events-none opacity-80" />

              {/* Jewel accents for ROYAL style */}
              {visualStyle === 'ROYAL' && (
                <>
                  <div className="absolute top-1.5 left-1.5 w-2.5 h-2.5 bg-[#E62E2E] rounded-full shadow-[0_0_8px_#E62E2E,inset_1px_1px_2px_white] z-20" />
                  <div className="absolute bottom-1.5 right-1.5 w-2.5 h-2.5 bg-[#45B13D] rounded-full shadow-[0_0_8px_#45B13D,inset_1px_1px_2px_white] z-20" />
                  <div className="absolute top-1.5 right-1.5 w-1.5 h-1.5 bg-[#1845AD] rounded-full shadow-[0_0_6px_#1845AD] z-20 opacity-60" />
                  <div className="absolute bottom-1.5 left-1.5 w-1.5 h-1.5 bg-[#F7D021] rounded-full shadow-[0_0_6px_#F7D021] z-20 opacity-60" />
                </>
              )}

              {faceText && (
                <span 
                  className={`font-[900] select-none transition-all duration-700 uppercase whitespace-nowrap px-2 z-10
                    ${isRevealed ? 'opacity-100 scale-100' : 'opacity-0 scale-50'}`}
                  style={{ 
                    fontSize: Math.min(f.fw * 0.8 / (faceText.length || 1), f.fh * 0.7),
                    textShadow: visualStyle === 'ROYAL' 
                        ? '3px 3px 6px rgba(0,0,0,0.7), 0 0 12px rgba(255,223,0,0.6)'
                        : '0 2px 10px rgba(0,0,0,1)',
                    transform: 'translateZ(20px)',
                    color: visualStyle === 'ROYAL' ? '#4A3705' : 'white',
                    fontFamily: visualStyle === 'ROYAL' ? 'Montserrat' : 'inherit'
                  }}
                >
                  {faceText}
                </span>
              )}

              {/* Diamond cut highlights */}
              {visualStyle === 'ROYAL' && (
                <div className="absolute inset-0 border border-white/30 rotate-45 scale-[1.2] pointer-events-none" />
              )}
            </div>
          );
        })}
      </div>
    );
  };

  const isDrifting = !isSuccess && !isFail && !isSelected && speed > 0 && rotationAxis !== 'X' && rotationAxis !== 'Y';

  return (
    <div 
      className={`relative ${className} ${isDrifting ? 'animate-cube-drift' : ''}`} 
      style={{ 
        width: w, 
        height: h,
        perspective: '1000px',
        opacity
      }}
    >
      <div className={`w-full h-full ${getRotationClass()}`} style={{ transformStyle: 'preserve-3d', transition: 'all 0.5s ease-out' }}>
        {renderCube()}
      </div>
    </div>
  );
});

import React from 'react';
import { SoundManager } from '../managers/SoundManager';

interface ButtonProps {
  children: React.ReactNode;
  onClick: () => void;
  variant?: 'cyan' | 'indigo' | 'pink' | 'amber' | 'green' | 'coral' | 'white' | 'royal-red' | 'royal-gold';
  className?: string;
  size?: 'sm' | 'md' | 'lg';
  disabled?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  onClick, 
  variant = 'cyan', 
  className = '',
  size = 'md',
  disabled = false
}) => {
  const handleInternalClick = () => {
    if (!disabled) {
      SoundManager.getInstance().playClick();
      onClick();
    }
  };

  const baseStyles = "btn-spline relative font-[900] uppercase tracking-tighter rounded-[32px] flex items-center justify-center border-x-[3px] border-t-[3px] overflow-hidden select-none transition-all duration-200";

  const variants = {
    cyan: "bg-[#1845AD] text-white border-[#103078] border-t-[#4A7EDC] border-b-[10px] active:border-b-[2px] active:translate-y-[8px]",
    indigo: "bg-[#4F46E5] text-white border-[#3730A3] border-t-[#818CF8] border-b-[10px] active:border-b-[2px] active:translate-y-[8px]",
    pink: "bg-[#E62E2E] text-white border-[#A31D1D] border-t-[#FF6B6B] border-b-[10px] active:border-b-[2px] active:translate-y-[8px]",
    amber: "bg-[#F7D021] text-[#4A3705] border-[#B8860B] border-t-[#FFF3A0] border-b-[10px] active:border-b-[2px] active:translate-y-[8px]",
    green: "bg-[#45B13D] text-white border-[#2D7A27] border-t-[#85D67D] border-b-[10px] active:border-b-[2px] active:translate-y-[8px]",
    coral: "bg-[#E62E2E] text-white border-[#A31D1D] border-t-[#FF6B6B] border-b-[10px] active:border-b-[2px] active:translate-y-[8px]",
    white: "bg-white text-[#0f172a] border-[#cbd5e1] border-t-[#f8fafc] border-b-[10px] active:border-b-[2px] active:translate-y-[8px]",
    // Royal Match Red: Bulky, gummy, high gloss
    'royal-red': "bg-[#FF0033] text-white border-[#990022] border-t-[#FF6688] border-b-[16px] active:border-b-[4px] active:translate-y-[12px] shadow-[0_25px_50px_rgba(255,0,51,0.4)]",
    // Royal Match Gold: Metallic, ornate
    'royal-gold': "bg-gradient-to-b from-[#FFD700] to-[#B8860B] text-[#4A3705] border-[#8B4513] border-t-[#FFFACD] border-b-[12px] active:border-b-[3px] active:translate-y-[9px] shadow-[0_20px_40px_rgba(212,175,55,0.4)]"
  };

  const sizes = {
    sm: "px-5 py-2 text-xs",
    md: "px-8 py-4 text-xl",
    lg: "px-10 py-6 text-3xl"
  };

  return (
    <button 
      onClick={handleInternalClick} 
      disabled={disabled}
      className={`
        ${baseStyles} 
        ${variants[variant] || variants.cyan} 
        ${sizes[size]} 
        ${disabled ? 'opacity-40 grayscale cursor-not-allowed' : 'cursor-pointer'}
        ${className}
      `}
    >
      {/* High-gloss highlights (Chewing gum effect) */}
      <div className="absolute top-1 left-2 right-2 h-[40%] bg-gradient-to-b from-white/40 to-transparent rounded-full blur-[2px] pointer-events-none" />
      <div className="absolute bottom-1 left-4 right-4 h-[10%] bg-white/10 rounded-full blur-[1px] pointer-events-none" />

      {/* Shimmer animation */}
      {!disabled && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none">
          <div className="w-[40%] h-[200%] bg-white/20 blur-2xl absolute -top-[50%] -left-[100%] rotate-[25deg] animate-[shimmer_3s_infinite_linear]" />
        </div>
      )}

      <span className="relative z-10 drop-shadow-[0_3px_5px_rgba(0,0,0,0.5)]">
        {children}
      </span>

      {/* Ornate Inner Border */}
      <div className="absolute inset-[3px] border border-white/20 rounded-[28px] pointer-events-none" />
    </button>
  );
};

