import React, { useState, useEffect } from 'react';
import { Cube3D } from '../components/Cube3D';

interface LoadingScreenProps {
  onFinished?: () => void;
}

export const LoadingScreen: React.FC<LoadingScreenProps> = ({ onFinished }) => {
  const [progress, setProgress] = useState(0);
  const [isAssembling, setIsAssembling] = useState(false);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return Math.min(prev + 1.2, 100);
      });
    }, 25);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (progress === 100) {
      const timer = setTimeout(() => {
        setIsAssembling(true);
        setTimeout(() => onFinished?.(), 2000);
      }, 800);
      return () => clearTimeout(timer);
    }
  }, [progress, onFinished]);

  // Kozmik Yol Görseli: Dünyadan Lumina Küpüne
  const bgImage = "https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?auto=format&fit=crop&q=80&w=1920&h=1080";

  return (
    <div className="absolute inset-0 bg-[#020617] flex flex-col items-center justify-center p-8 overflow-hidden font-montserrat">

      {/* Path to Lumina Background */}
      <div className="absolute inset-0">
        <img 
          src={bgImage} 
          className="w-full h-full object-cover opacity-60 scale-110 animate-[planetDrift_30s_linear_infinite]"
          alt=""
        />
        {/* Earth Silhouette (Lower Left) */}
        <div className="absolute bottom-[-100px] left-[-100px] w-96 h-96 bg-blue-600/20 rounded-full blur-[100px]" />
        {/* Golden Path Dust */}
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] opacity-20" />
        <div className="absolute inset-0 bg-gradient-to-t from-[#020617] via-transparent to-transparent" />
      </div>

      {/* 3D CAST GOLD LOGO - DIAMOND CUT */}
      <div className={`z-20 text-center mb-16 relative transition-all duration-1000 ${isAssembling ? 'opacity-0 scale-75 blur-2xl' : 'opacity-100 scale-100'}`}>
        <div className="relative inline-block">
