import React, { memo } from 'react';

export type RotationAxis = 'X' | 'Y' | 'XY' | 'TUMBLE';
export type CubeVisualStyle = 'GLASS' | 'CRYSTAL' | 'METAL' | 'NEON' | 'GHOST' | 'DARK' | 'PLASMA' | 'CHROME' | 'LAVA' | 'AETHER' | 'VOID' | 'ROYAL';

interface Cube3DProps {
  size?: number;
  width?: number; 
  height?: number; 
  depth?: number; 
  className?: string;
  speed?: number;
  opacity?: number;
  label?: string;
  centerLabel?: string; 
  faceLabels?: string[]; 
  isGlassy?: boolean;
  color?: string;
  rotationAxis?: RotationAxis;
  visualStyle?: CubeVisualStyle;
  status?: 'idle' | 'success' | 'fail';
  delay?: number;
  isRevealed?: boolean;
  isSelected?: boolean;
}

export const Cube3D: React.FC<Cube3DProps> = memo(({ 
  size = 32,
  width,
  height,
  depth,
  className = "", 
  speed = 4,
  opacity = 1,
  label = "",
  centerLabel = "",
  faceLabels,
  isGlassy = true,
  color = "rgba(34, 211, 238, 1)",
  rotationAxis = 'XY',
  visualStyle = 'GLASS',
  status = 'idle',
  delay = 0,
  isRevealed = true,
  isSelected = false
}) => {
  const isSuccess = status === 'success';
  const isFail = status === 'fail';
  const mainText = (centerLabel || label);

  const w = width || size;
  const h = height || size;
  const d = depth || size;

  const overlap = 1.2; 

  const getRotationClass = () => {
    if (isSelected || isSuccess || speed === 0) return "";
    switch (rotationAxis) {
      case 'X': return "animate-cube-x";
      case 'Y': return "animate-cube-y";
      case 'XY': return "animate-cube-xy";
      case 'TUMBLE': return "animate-cube-tumble";
      default: return "animate-cube-xy";
    }
  };

  const renderCube = () => {
    let baseColor = color;
    if (isSuccess) baseColor = '#00C853'; // Emerald Green
    if (isFail) baseColor = '#D50000'; // Ruby Red

    const faces = [
      { id: 'front', rot: 'rotateY(0deg)', tz: (d / 2) },
      { id: 'back', rot: 'rotateY(180deg)', tz: (d / 2) },
      { id: 'right', rot: 'rotateY(90deg)', tz: (w / 2) },
      { id: 'left', rot: 'rotateY(-90deg)', tz: (w / 2) },
      { id: 'top', rot: 'rotateX(90deg)', tz: (h / 2) },
      { id: 'bottom', rot: 'rotateX(-90deg)', tz: (h / 2) },
    ];

    return (
      <div className="w-full h-full relative" style={{ transformStyle: 'preserve-3d' }}>
        {faces.map((f, i) => {
          const faceText = (faceLabels && faceLabels[i]) ? faceLabels[i] : mainText;

          let faceStyles: React.CSSProperties = {
            position: 'absolute',
            width: (f.id === 'top' || f.id === 'bottom') ? w : (f.id === 'left' || f.id === 'right') ? d : w,
            height: (f.id === 'top' || f.id === 'bottom') ? d : h,
            left: '50%',
            top: '50%',
            transform: `translate(-50%, -50%) ${f.rot} translateZ(${f.tz}px)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            backfaceVisibility: 'hidden',
            borderRadius: Math.min(w, h) * 0.15,
            transformStyle: 'preserve-3d',
            overflow: 'hidden'
          };

          // Pixar-Style Enamel Materyal Shader
          if (visualStyle === 'ROYAL' || isSuccess) {
            faceStyles.background = `radial-gradient(circle at 30% 30%, ${baseColor} 0%, ${baseColor} 60%, rgba(0,0,0,0.3) 100%)`;
            faceStyles.border = `4px solid rgba(255,255,255,0.5)`;
            faceStyles.boxShadow = `
              inset 0 0 20px rgba(0,0,0,0.4), 
              inset 4px 4px 10px rgba(255,255,255,0.7),
              0 10px 20px rgba(0,0,0,0.5)
            `;
          } else {
            faceStyles.background = isGlassy ? `linear-gradient(135deg, ${baseColor}aa 0%, ${baseColor}44 100%)` : baseColor;
            faceStyles.border = `3px solid ${baseColor}`;
            faceStyles.backdropFilter = isGlassy ? 'blur(10px)' : 'none';
          }

          return (
            <div key={i} style={faceStyles}>
              {/* Rim Light / Specular highlight (Anisotropic) */}
              <div className="absolute top-0 left-0 right-0 h-1/2 bg-gradient-to-b from-white/60 to-transparent pointer-events-none z-0" />

              {/* Embossed Letter Effect */}
              {faceText && (
                <span 
                  className={`font-[900] select-none transition-all duration-700 uppercase whitespace-nowrap px-2 z-10
                    ${isRevealed ? 'opacity-100 scale-100' : 'opacity-0 scale-50'}`}
                  style={{ 
                    fontSize: Math.min(w * 0.8 / (faceText.length || 1), h * 0.7),
                    color: 'white',
                    transform: 'translateZ(10px)',
                    // Stamped/Embossed look
                    textShadow: `
                      1px 1px 0px rgba(255,255,255,0.6),
                      2px 2px 0px rgba(255,255,255,0.4),
                      -1px -1px 0px rgba(0,0,0,0.4),
                      -2px -2px 10px rgba(0,0,0,0.6)
                    `
                  }}
                >
                  {faceText}
                </span>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div 
      className={`relative ${className}`} 
      style={{ width: w, height: h, perspective: '1000px', opacity }}
    >
      <div className={`w-full h-full ${getRotationClass()}`} style={{ transformStyle: 'preserve-3d', transition: 'all 0.5s ease-out' }}>
        {renderCube()}
      </div>
    </div>
  );
});

import React, { useState, useMemo, useEffect, useRef } from 'react';
