  { target: "ADAPTÖR", distractors: ["ADAPTASYON", "ADAPTİVE", "ADAPTÖRÜ"] },
  { target: "KARANLIK", distractors: ["KABARIK", "KARARLIK", "KARANLAK"] }
];

const COLORS = ["#0047FF", "#FFD700", "#00C853", "#D50000", "#818cf8"];
const MEMORIZE_DURATION = 30; 
const BASE_ROUND_TIME = 10;

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void; onUpdateStats: (s: Partial<UserStats>) => void }> = ({ stats, onComplete, onExit, onUpdateStats }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);

  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [rotationOffset, setRotationOffset] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [revealedIndex, setRevealedIndex] = useState(-1);
  const [roundResults, setRoundResults] = useState<( 'success' | 'fail' | null)[]>(new Array(5).fill(null));
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showQuitModal, setShowQuitModal] = useState(false);
  const [comboCount, setComboCount] = useState(0);

  const [showHintMenu, setShowHintMenu] = useState(false);
  const [isTimeFrozen, setIsTimeFrozen] = useState(false);
  const [hintUsedThisRound, setHintUsedThisRound] = useState(false);
  const [firstLetterFlash, setFirstLetterFlash] = useState(false);

  const timerRef = useRef<number | null>(null);

  const currentStyle = useMemo(() => 'STANDART', [currentRound]);
  const currentCubeVisualStyle = useMemo<CubeVisualStyle>(() => 'ROYAL', [currentRound]);

  const puzzleRounds = useMemo(() => {
    const minLength = stats.difficultyFactor > 1.6 ? 7 : stats.difficultyFactor > 1.2 ? 5 : 3;
    const filteredPool = ALL_ROUNDS_POOL.filter(item => item.target.length >= minLength);
    return [...filteredPool].sort(() => Math.random() - 0.5).slice(0, 5);
  }, [stats.difficultyFactor]);

  const activeRoundData = puzzleRounds[currentRound];
  const activeOptions = useMemo(() => {
    const target = activeRoundData.target;
    const distractors = activeRoundData.distractors;
    return [target, ...distractors].sort(() => Math.random() - 0.5);
  }, [activeRoundData]);

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || isMenuOpen || isTransitioning || showQuitModal) return;

    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if ((isTimeFrozen || showHintMenu) && gamePhase === 'MEMORIZE') return prev;
        const nextTime = prev - 0.05;
        if (gamePhase === 'MEMORIZE' && nextTime <= 0) {
          setGamePhase('GUESS');
          SoundManager.getInstance().playPop();
          return dynamicRoundTime;
        }
        if (gamePhase === 'GUESS' && nextTime <= 0) {
          handleChoice("TIME_UP");
          return dynamicRoundTime;
        }
        return nextTime;
      });

      if (gamePhase === 'MEMORIZE' && !isTimeFrozen && !showHintMenu) {
        setRotationOffset(prev => prev + (0.6 * stats.difficultyFactor));
      }
    }, 50);

    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [choiceStatus, selectedChoice, isMenuOpen, isTransitioning, currentRound, showQuitModal, dynamicRoundTime, stats.difficultyFactor, gamePhase, isTimeFrozen, hintUsedThisRound, showHintMenu]);

  useEffect(() => {
    if (choiceStatus === 'success') {
      let currentIdx = 0;
      const interval = setInterval(() => {
        setRevealedIndex(currentIdx);
        currentIdx++;
        if (currentIdx >= activeRoundData.target.length) clearInterval(interval);
      }, 150);
      return () => clearInterval(interval);
    } else {
      setRevealedIndex(-1);
    }
  }, [choiceStatus, activeRoundData.target]);

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle' || isTransitioning) return;
    setSelectedChoice(choice);
    setShowHintMenu(false);
    setTimeout(() => {
      const isCorrect = choice === activeRoundData.target;
      if (isCorrect) {
        SoundManager.getInstance().playSuccess();
        setComboCount(prev => prev + 1);
      } else {
        if (choice !== "TIME_UP") SoundManager.getInstance().playFail();
        setComboCount(0);
      }
      const points = Math.floor((100 + timeLeft * 10) * (1 + (comboCount * 0.1)));
      const nextResults = [...roundResults];
      setChoiceStatus(isCorrect ? 'success' : 'fail');
      nextResults[currentRound] = isCorrect ? 'success' : 'fail';
      const nextScore = isCorrect ? sessionScore + points : Math.max(0, sessionScore - 50);
      setSessionScore(nextScore);
      const delay = isCorrect ? (activeRoundData.target.length * 150 + 2000) : 1200;
      setTimeout(() => {
        setIsTransitioning(true);
        setTimeout(() => {
          if (currentRound === puzzleRounds.length - 1) {
            onComplete(nextScore, puzzleRounds.map(r => r.target), puzzleRounds.flatMap(r => r.distractors));
          } else {
            setCurrentRound(prev => prev + 1);
            setTimeLeft(MEMORIZE_DURATION);
            setGamePhase('MEMORIZE');
            setChoiceStatus('idle');
            setSelectedChoice(null);
            setRevealedIndex(-1);
            setRoundResults(nextResults);
            setIsTransitioning(false);
            setHintUsedThisRound(false);
          }
        }, 400);
      }, delay);
    }, 600); 
  };

  const ringItems = useMemo(() => {
    return activeRoundData.target.split("").map((char, i) => ({
      char,
      color: COLORS[i % COLORS.length]
    }));
  }, [activeRoundData]);

  const renderRing = () => {
    const dist = 120; 
    const isSuccess = choiceStatus === 'success';
    const dynamicSpacing = 64;
    const dynamicCubeSize = 72;

    return (
      <div className={`relative w-full h-full flex items-center justify-center transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-75 blur-lg' : 'opacity-100 scale-100'}`} style={{ transformStyle: 'preserve-3d' }}>

        {/* MAGIC GOLD CHAIN CONNECTIONS */}
        {isSuccess && ringItems.map((_, idx) => {
          if (idx === 0) return null;
          const xPos = (idx - 1 - (ringItems.length - 1) / 2) * dynamicSpacing + (dynamicSpacing / 2);
          const isVisible = revealedIndex >= idx;

          return (
            <div 
              key={`chain-${idx}`} 
              className="absolute flex items-center justify-center transition-all duration-500 z-0"
              style={{
                width: dynamicSpacing,
                left: `calc(50% + ${xPos}px)`,
                top: '50%',
                transform: 'translate(-50%, -50%) translateZ(5px)',
                opacity: isVisible ? 1 : 0
              }}
            >
              {/* Anisotropic Gold Link Effect */}
              <div className="w-full h-3 bg-gradient-to-r from-transparent via-[#FFD700] to-transparent shadow-[0_0_15px_#FFD700] blur-[1px] animate-pulse" />
              <div className="absolute flex gap-1">
                 {[1,2].map(c => <div key={c} className="w-4 h-6 border-[3px] border-[#FFD700] rounded-full rotate-45 shadow-[inset_0_0_5px_white,0_4px_8px_rgba(0,0,0,0.4)] bg-gradient-to-br from-[#FFFACD] via-[#FFD700] to-[#B8860B]" />)}
              </div>
            </div>
          );
        })}

        {/* PIXAR-STYLE CELEBRATION (Fireworks & Stars) */}
        {isSuccess && [...Array(25)].map((_, i) => {
          const tx = (Math.random() - 0.5) * 600;
          const ty = (Math.random() - 0.5) * 600;
          return (
            <div 
              key={`star-${i}`} 
              className="absolute animate-star-burst pointer-events-none text-2xl z-50"
              style={{
                left: '50%',
                top: '50%',
                '--tx': `${tx}px`,
                '--ty': `${ty}px`,
                animationDelay: `${Math.random() * 0.8}s`
              } as any}
            >
              {i % 2 === 0 ? '⭐' : '✨'}
            </div>
          );
        })}

        {ringItems.map((item, idx) => {
          const angle = (idx / ringItems.length) * 360 + rotationOffset;
          const rad = (angle * Math.PI) / 180;
          let x = 0, y = 0, z = 0, scale = 1;

          if (isSuccess) {
            x = (idx - (ringItems.length - 1) / 2) * dynamicSpacing;
            y = 0; z = 20; scale = 1.1 + (revealedIndex === idx ? 0.3 : 0);
          } else {
             x = Math.cos(rad) * dist; y = Math.sin(rad) * dist; z = 0;
          }

          return (
            <div key={`${currentRound}-${idx}`} className="absolute transition-all duration-300 ease-out" style={{ transform: `translate3d(${x}px, ${y}px, ${z}px) scale(${scale})`, transformStyle: 'preserve-3d', zIndex: (revealedIndex === idx) ? 300 : 20 }}>
              <Cube3D 
                size={isSuccess ? dynamicCubeSize : 64} 
                label={gamePhase === 'GUESS' && !isSuccess ? '?' : item.char} 
                color={item.color} 
                visualStyle={currentCubeVisualStyle} 
                status={choiceStatus} 
                isRevealed={true} 
                delay={idx * 0.05} 
                speed={(isSuccess || gamePhase === 'GUESS' || isTimeFrozen || showHintMenu) ? 0 : 4} 
              />
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="absolute inset-0 bg-[#020617] flex flex-col overflow-hidden">
      <ParticleBackground speedMultiplier={choiceStatus === 'success' ? 0.05 : 0.2} />

      <div className={`pt-10 px-8 flex justify-between items-start z-20 transition-opacity duration-500 ${isMenuOpen ? 'opacity-0' : 'opacity-100'}`}>
        <div className="flex gap-1.5 p-2 bg-black/40 backdrop-blur-2xl rounded-xl border border-white/10 shadow-2xl">
          {roundResults.map((res, i) => (
            <div key={i} className={`w-3 h-3 rounded-md border-2 transition-all duration-500 ${res === 'success' ? 'bg-[#00C853] border-white shadow-[0_0_10px_#00C853]' : res === 'fail' ? 'bg-[#D50000] border-white shadow-[0_0_10px_#D50000]' : i === currentRound ? 'bg-[#00E5FF] border-white animate-pulse' : 'bg-white/10 border-white/10'}`} />
          ))}
        </div>
        <div className="text-3xl font-[900] text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.4)]">{sessionScore.toLocaleString()}</div>
      </div>

      <div className={`flex-1 relative flex items-center justify-center perspective-[1500px] z-10 min-h-0 ${isMenuOpen ? 'blur-sm brightness-50' : ''}`}>{renderRing()}</div>

      <div className={`px-6 pb-10 flex flex-col gap-5 z-20 transition-all duration-700 shrink-0 ${isTransitioning || choiceStatus === 'success' ? 'opacity-0 translate-y-20' : 'opacity-100 translate-y-0'} ${isMenuOpen ? 'blur-sm' : ''}`}>
        <div className="w-full h-3 bg-black/60 rounded-full overflow-hidden relative border border-white/10 shadow-inner p-[1px]">
          <div className="h-full relative transition-all duration-300 rounded-full" style={{ width: `${(timeLeft / (gamePhase === 'MEMORIZE' ? MEMORIZE_DURATION : dynamicRoundTime)) * 100}%`, backgroundColor: gamePhase === 'MEMORIZE' ? '#00E5FF' : '#FFD700', boxShadow: '0 0 15px rgba(0,229,255,0.5)' }} />
        </div>

        <div className="grid grid-cols-2 gap-3">
          {activeOptions.map((opt, i) => (
            <Button 
              key={i} 
              variant={(selectedChoice === opt) ? (choiceStatus === 'success' ? 'green' : 'coral') : (['indigo', 'pink', 'amber', 'cyan'][i % 4] as any)} 
              onClick={() => handleChoice(opt)} 
              className={`w-full !h-24 !rounded-[36px] !text-[24px] !border-b-[12px] active:!border-b-[2px] transition-all duration-300 ${(selectedChoice !== null && selectedChoice !== opt) ? 'opacity-20 scale-90 blur-[2px]' : ''} ${gamePhase === 'MEMORIZE' ? 'pointer-events-none grayscale opacity-40' : ''}`} 
              disabled={selectedChoice !== null || (gamePhase !== 'GUESS' && gamePhase !== 'MEMORIZE')}
            >
              <span className="truncate w-full px-2 drop-shadow-md">{gamePhase === 'MEMORIZE' ? '???' : opt}</span>
            </Button>
          ))}
        </div>
      </div>

      <div className="fixed right-2 bottom-2 z-[300]"><SideMenu onExit={() => setShowQuitModal(true)} onToggle={setIsMenuOpen} isMinimal={true} expandDirection="up" /></div>
      {showQuitModal && <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />}
    </div>
  );
};

