  const baseStyles = "btn-spline relative font-[900] uppercase tracking-tighter rounded-[40px] flex items-center justify-center border-x-[4px] border-t-[4px] overflow-hidden select-none transition-all duration-200";

  const variants = {
    cyan: "bg-[#00E5FF] text-white border-[#0091A3] border-t-[#B2F9FF] border-b-[12px] active:border-b-[2px] active:translate-y-[10px] shadow-[0_20px_40px_rgba(0,229,255,0.3)]",
    indigo: "bg-[#4F46E5] text-white border-[#3730A3] border-t-[#818CF8] border-b-[12px] active:border-b-[2px] active:translate-y-[10px] shadow-[0_20px_40px_rgba(79,70,229,0.3)]",
