    green: "bg-[#00C853] text-white border-[#1B5E20] border-t-[#B9F6CA] border-b-[12px] active:border-b-[2px] active:translate-y-[10px] shadow-[0_20px_40px_rgba(0,200,83,0.3)]",
    coral: "bg-[#D50000] text-white border-[#7F0000] border-t-[#FF8A80] border-b-[12px] active:border-b-[2px] active:translate-y-[10px] shadow-[0_20px_40px_rgba(213,0,0,0.3)]",
