import React, { useState, useEffect } from 'react';

interface LoadingScreenProps {
  onFinished?: () => void;
}

export const LoadingScreen: React.FC<LoadingScreenProps> = ({ onFinished }) => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return Math.min(prev + 1.5, 100);
      });
    }, 20);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (progress === 100) {
      setTimeout(() => onFinished?.(), 1000);
    }
  }, [progress, onFinished]);

  const bgImage = "https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?auto=format&fit=crop&q=80&w=1920&h=1080";

  return (
    <div className="absolute inset-0 bg-[#010413] flex flex-col items-center justify-center p-8 overflow-hidden font-montserrat">

      <div className="absolute inset-0">
        <img 
          src={bgImage} 
          className="w-full h-full object-cover opacity-30 scale-110 animate-[planetDrift_30s_linear_infinite]"
          alt=""
        />
        <div className="absolute inset-0 bg-gradient-to-t from-[#010413] via-transparent to-transparent" />
      </div>

      {/* MINIMAL LOGO */}
      <div className="z-20 text-center mb-20 relative">
        <h1 
          className="text-8xl font-[900] tracking-[0.2em] text-transparent bg-clip-text bg-gradient-to-b from-white via-white to-white/40"
          style={{
            textShadow: '0 0 30px rgba(255,255,255,0.2)'
          }}
        >
          LUMINA
        </h1>
      </div>

      {/* MINIMAL PROGRESS BAR */}
      <div className="w-full max-w-[280px] z-20">
        <div className="relative w-full h-1.5 bg-white/5 rounded-full overflow-hidden border border-white/10">
          <div 
            className="h-full bg-white transition-all duration-300 ease-out shadow-[0_0_15px_white]"
            style={{ width: `${progress}%` }}
          />
        </div>
        <div className="mt-4 text-center">
          <span className="text-white/30 font-black text-[10px] tracking-[0.5em] uppercase">
            SİSTEM YÜKLENİYOR
          </span>
        </div>
      </div>

      <style>{`
        @keyframes planetDrift {
          0% { transform: scale(1.1) translate(0,0); }
          50% { transform: scale(1.15) translate(-10px, -5px); }
          100% { transform: scale(1.1) translate(0,0); }
        }
      `}</style>
    </div>
  );
};

import React from 'react';

interface Portal3DProps {
  level: number;
  active: boolean;
}

export const Portal3D: React.FC<Portal3DProps> = ({ level, active }) => {
  // Basamak sayısına göre font boyutunu ayarla (300 gibi sayılar sığsın diye)
  const getFontSize = () => {
    const digits = level.toString().length;
    if (digits >= 4) return 'text-[120px]';
    if (digits === 3) return 'text-[180px]';
    if (digits === 2) return 'text-[240px]';
    return 'text-[280px]';
  };

  return (
    <div className={`relative w-full h-full flex items-center justify-center transition-all duration-1000 ${active ? 'scale-100 opacity-100' : 'scale-90 opacity-40'}`}>

      {/* The Giant Floating 3D Number */}
      <div className="relative z-20 animate-[pureFloat_4s_infinite_ease-in-out] select-none pointer-events-none flex items-center justify-center w-full">
        <div className="relative flex items-center justify-center w-full">
          {/* Main 3D Extruded Number */}
          <span 
            className={`${getFontSize()} font-[900] text-white tracking-tighter leading-none block text-center transition-all duration-500`}
            style={{
              textShadow: `
                0 4px 0 #cbd5e1,
                0 10px 0 #94a3b8,
                0 18px 0 #64748b,
                0 24px 0 #475569,
                0 40px 80px rgba(0,0,0,0.6)
              `,
              filter: 'drop-shadow(0 0 40px rgba(255,255,255,0.1))'
            }}
          >
            {level}
          </span>

          {/* High Gloss Shine Overlay */}
          <div 
            className="absolute top-[20%] left-0 right-0 h-[30%] bg-gradient-to-b from-white/30 to-transparent blur-xl rounded-full opacity-50" 
            style={{ transform: 'rotate(-5deg) scaleX(0.7)' }}
          />
        </div>
      </div>

      <style>{`
        @keyframes pureFloat {
          0%, 100% { 
            transform: translateY(0) rotate(0deg); 
          }
          50% { 
            transform: translateY(-30px) rotate(1deg); 
          }
        }
      `}</style>
    </div>
  );
};

