import React from 'react';
import { SoundManager } from '../managers/SoundManager';

interface ButtonProps {
  children: React.ReactNode;
  onClick: () => void;
  variant?: 'cyan' | 'indigo' | 'pink' | 'amber' | 'green' | 'coral' | 'white' | 'royal-red' | 'royal-gold';
  className?: string;
  size?: 'sm' | 'md' | 'lg';
  disabled?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  onClick, 
  variant = 'cyan', 
  className = '',
  size = 'md',
  disabled = false
}) => {
  const handleInternalClick = () => {
    if (!disabled) {
      SoundManager.getInstance().playClick();
      onClick();
    }
  };

  const baseStyles = "relative font-[900] uppercase tracking-tighter rounded-[40px] flex items-center justify-center border-x-[4px] border-t-[4px] overflow-hidden select-none transition-all duration-200 cursor-pointer";

  const variants = {
    cyan: "bg-[#00E5FF] text-white border-[#0091A3] border-t-[#B2F9FF] border-b-[18px] active:border-b-[4px] active:translate-y-[14px] shadow-[0_25px_50px_rgba(0,229,255,0.4)]",
    indigo: "bg-[#4F46E5] text-white border-[#3730A3] border-t-[#818CF8] border-b-[18px] active:border-b-[4px] active:translate-y-[14px] shadow-[0_25px_50px_rgba(79,70,229,0.4)]",
    pink: "bg-[#F472B6] text-white border-[#9D174D] border-t-[#FBCFE8] border-b-[18px] active:border-b-[4px] active:translate-y-[14px] shadow-[0_25px_50px_rgba(244,114,182,0.4)]",
    amber: "bg-[#F7D021] text-[#4A3705] border-[#B8860B] border-t-[#FFF3A0] border-b-[18px] active:border-b-[4px] active:translate-y-[14px] shadow-[0_25px_50px_rgba(247,208,33,0.4)]",
    green: "bg-[#00C853] text-white border-[#1B5E20] border-t-[#B9F6CA] border-b-[18px] active:border-b-[4px] active:translate-y-[14px] shadow-[0_25px_50px_rgba(0,200,83,0.4)]",
    coral: "bg-[#D50000] text-white border-[#7F0000] border-t-[#FF8A80] border-b-[18px] active:border-b-[4px] active:translate-y-[14px] shadow-[0_25px_50px_rgba(213,0,0,0.4)]",
    white: "bg-white text-[#0f172a] border-[#cbd5e1] border-t-[#f8fafc] border-b-[18px] active:border-b-[4px] active:translate-y-[14px] shadow-[0_20px_40px_rgba(0,0,0,0.2)]",
    'royal-red': "bg-[#FF0033] text-white border-[#990022] border-t-[#FF6688] border-b-[20px] active:border-b-[4px] active:translate-y-[16px] shadow-[0_30px_60px_rgba(255,0,51,0.5)]",
    'royal-gold': "bg-gradient-to-b from-[#FFD700] via-[#FFD700] to-[#B8860B] text-[#4A3705] border-[#8B4513] border-t-[#FFFACD] border-b-[20px] active:border-b-[4px] active:translate-y-[16px] shadow-[0_30px_60px_rgba(212,175,55,0.6)]"
  };

  const sizes = {
    sm: "px-6 py-3 text-sm",
    md: "px-8 py-6 text-2xl",
    lg: "px-12 py-8 text-5xl"
  };

  return (
    <button 
      onClick={handleInternalClick} 
      disabled={disabled}
      className={`
        ${baseStyles} 
        ${variants[variant] || variants.cyan} 
        ${sizes[size]} 
        ${disabled ? 'opacity-40 grayscale cursor-not-allowed' : ''}
        ${className}
      `}
    >
      {/* Pixar-style Gummy Highlight */}
      <div className="absolute top-1 left-4 right-4 h-[40%] bg-gradient-to-b from-white/60 to-transparent rounded-full blur-[2px] pointer-events-none" />

      {/* Moving Shimmer (Diagonal Line) */}
      {!disabled && (
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none">
          <div className="w-[40%] h-[300%] bg-white/30 blur-2xl absolute -top-full -left-full rotate-[30deg] animate-[shimmer_5s_infinite_linear]" />
        </div>
      )}

      <span className="relative z-10 drop-shadow-[0_4px_6px_rgba(0,0,0,0.8)]">
        {children}
      </span>

      {/* Internal Decorative Border */}
      <div className="absolute inset-[6px] border border-white/20 rounded-[34px] pointer-events-none" />
    </button>
  );
};

import React from 'react';

interface Portal3DProps {
  level: number;
  active: boolean;
}

