    if (digits === 3) return 'text-[160px]';
    if (digits === 2) return 'text-[220px]';
    return 'text-[280px]';
  };

  return (
    <div className={`relative w-full h-full flex items-center justify-center transition-all duration-1000 ${active ? 'scale-100 opacity-100' : 'scale-90 opacity-40'}`}>

      {/* Giant 3D Enamel Number */}
      <div className="relative z-20 animate-[pureFloat_4s_infinite_ease-in-out] select-none pointer-events-none flex items-center justify-center w-full">
        <div className="relative flex items-center justify-center w-full">
          {/* Main 3D Number Body */}
          <span 
            className={`${getFontSize()} font-[900] text-white tracking-tighter leading-none block text-center transition-all duration-500`}
            style={{
              textShadow: `
                0 4px 0 #cbd5e1,
                0 12px 0 #94a3b8,
                0 24px 0 #64748b,
                0 32px 0 #475569,
                0 50px 100px rgba(0,0,0,0.8)
              `,
              filter: 'drop-shadow(0 0 40px rgba(255,255,255,0.2))'
            }}
          >
            {level}
          </span>

          {/* High Gloss Reflection Overlay */}
          <div 
            className="absolute top-[15%] left-0 right-0 h-[40%] bg-gradient-to-b from-white/40 to-transparent blur-2xl rounded-full opacity-60" 
            style={{ transform: 'rotate(-5deg) scaleX(0.8)' }}
          />

          {/* Rim Light (Bottom Shine) */}
          <div className="absolute bottom-[10%] left-1/2 -translate-x-1/2 w-[70%] h-4 bg-white/20 blur-md rounded-full" />
