      </div>

      <style>{`
        @keyframes pureFloat {
          0%, 100% { 
            transform: translateY(0) rotate(0.1deg); 
          }
          50% { 
            transform: translateY(-30px) rotate(-0.5deg); 
          }
        }
      `}</style>
    </div>
  );
};

