    <div 
      className={`absolute inset-[-15px] blur-3xl rounded-full transition-all duration-500 pointer-events-none ${active ? 'opacity-40 animate-pulse' : 'opacity-0'}`} 
      style={{ backgroundColor: color }} 
    />
    <div className={`relative z-10 text-4xl transition-all duration-500 ${active ? 'drop-shadow-[0_0_15px_rgba(255,255,255,0.8)]' : 'opacity-40'}`}>
      {icon}
    </div>
