        <Header 
          stats={stats} 
          userPhoto={currentUser?.photoURL}
          isSyncing={isSyncing}
          onSettings={() => setHubSubView(HubSubView.SETTINGS)} 
          onProfile={() => setHubSubView(HubSubView.PROFILE)} 
          onShop={() => setHubSubView(HubSubView.SHOP)} 
        />

        {/* Side Actions */}
        <div className="absolute top-24 left-4 flex flex-col gap-4 z-[40] pointer-events-auto">
          <button 
            onClick={onOpenChest}
            className="w-14 h-14 bg-white/10 border-[2px] border-white/20 rounded-2xl flex items-center justify-center active:translate-y-1 transition-all shadow-2xl"
          >
             <span className="text-2xl">🎁</span>
          </button>

          <button 
            onClick={() => onAddCoins(50)}
            className="w-14 h-14 bg-white/10 border-[2px] border-white/20 rounded-2xl flex items-center justify-center active:translate-y-1 transition-all shadow-2xl relative"
          >
             <span className="text-2xl">📺</span>
             <div className="absolute -bottom-1 -right-1 bg-white text-black text-[8px] font-black px-1.5 py-0.5 rounded-md border border-black">+50</div>
          </button>
