        <div className={`w-full h-full flex flex-col items-center transition-all duration-700 z-[10] ${!isMain ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}>
            <div className="flex-1 w-full flex flex-col items-center justify-center p-0 relative">
               <Portal3D level={stats.level} active={isMain} />
            </div>

            {/* Main Action Button - BAŞLAT */}
            <div className={`w-full flex flex-col items-center mb-28 px-10 z-20 transition-all duration-500 ${!isMain ? 'opacity-0' : 'opacity-100'}`}>
                <Button 
                  variant="white" 
                  onClick={onStartGame} 
                  className="w-full !h-28 !rounded-[40px] !text-5xl !bg-white !text-black !border-b-[15px] !border-b-gray-300 active:!border-b-0 active:!translate-y-4 !shadow-[0_40px_80px_rgba(255,255,255,0.1)] group relative overflow-hidden"
