                  BAŞLAT
                </Button>
            </div>
        </div>

        <div className="absolute top-0 left-full w-full h-full z-[160] overflow-hidden bg-[#010413]">
          {hubSubView === HubSubView.SHOP && <ShopModal coins={stats.coins} onBuyHearts={onBuyHearts} onClose={() => setHubSubView(HubSubView.MAIN)} />}
          {hubSubView === HubSubView.PROFILE && <ProfileModal level={stats.level} onClose={() => setHubSubView(HubSubView.MAIN)} />}
          {hubSubView === HubSubView.MISSIONS && <MissionsModal stats={stats} onClaimReward={onClaimMission} onClose={() => setHubSubView(HubSubView.MAIN)} />}
        </div>
      </div>

      {/* Bottom Nav */}
      <div className={`w-full h-[100px] z-[200] pb-safe bg-gradient-to-t from-[#010413] to-transparent backdrop-blur-xl border-t border-white/5`}>
          <nav className="w-full h-full flex px-8 items-center justify-between">
              {navItems.map((item, idx) => (
                <button 
                  key={idx} 
                  onClick={() => setHubSubView(item.view as HubSubView)} 
                  className={`flex items-center justify-center relative transition-all duration-300 ${item.isCustom ? 'w-20 h-20 bg-white/10 rounded-[28px] -translate-y-4 shadow-2xl border border-white/20' : 'w-14 h-14'}`}
                >
