                </button>
              ))}
          </nav>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { UserStats } from '../types';
import { Button } from '../components/Button';
import { QuitConfirmationModal } from '../components/QuitConfirmationModal';
import { SideMenu } from '../components/SideMenu';
import { ParticleBackground } from '../components/ParticleBackground';
import { Cube3D } from '../components/Cube3D';
import { SoundManager } from '../managers/SoundManager';

interface MemoryGameProps {
  stats: UserStats;
  backgroundUrl: string;
  words: string[];
  targetWords: string[];
  onNext: (correctCount: number) => void;
  onFail: () => void;
  onExit: () => void;
  initialScore?: number;
}

// Royal Match Vibrant Colors
const ROYAL_PALETTE = [
  { bg: '#0047FF', glow: '#00268a' }, // Royal Blue
  { bg: '#FFD700', glow: '#b8860b' }, // Gold
  { bg: '#00C853', glow: '#007a33' }, // Emerald
  { bg: '#D50000', glow: '#7f0000' }, // Ruby
  { bg: '#8B5CF6', glow: '#5b21b6' }, // Purple
];

const GRID_POSITIONS = [
  { t: '18%', l: '30%' }, { t: '18%', l: '70%' },
  { t: '33%', l: '30%' }, { t: '33%', l: '70%' },
  { t: '48%', l: '30%' }, { t: '48%', l: '70%' },
  { t: '63%', l: '30%' }, { t: '63%', l: '70%' },
  { t: '78%', l: '30%' }, { t: '78%', l: '70%' }
];

export const MemoryGame: React.FC<MemoryGameProps> = ({ stats, words, targetWords, onNext, onFail, onExit }) => {
  const [selected, setSelected] = useState<Set<number>>(new Set());
  const [isRevealing, setIsRevealing] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [results, setResults] = useState<boolean[]>([]);
  const [showQuitModal, setShowQuitModal] = useState(false);

  const displayWords = useMemo(() => words.map((word, i) => ({ 
    word, 
    color: ROYAL_PALETTE[i % ROYAL_PALETTE.length], 
    pos: GRID_POSITIONS[i % 10] 
  })), [words]);

  const correctIndices = useMemo(() => new Set(displayWords.map((item, i) => targetWords.includes(item.word) ? i : -1).filter(i => i !== -1)), [displayWords, targetWords]);

  const handleWordClick = (i: number) => {
    if (isRevealing || isMenuOpen) return;
    SoundManager.getInstance().playPop();
    setSelected(prev => {
      const n = new Set(prev);
      if (n.has(i)) n.delete(i); else if (n.size < 5) n.add(i);
      return n;
    });
  };

  const handleSubmit = () => {
    if (selected.size < 5 || isRevealing || isMenuOpen) return;
    setIsRevealing(true);

    const res: boolean[] = [];
    let correct = 0;

    const selectedIndices = Array.from(selected);
    selectedIndices.forEach(idx => {
      const isCorrect = correctIndices.has(idx);
      res.push(isCorrect);
      if (isCorrect) correct++;
    });

    setResults(res);

    if (correct >= 3) SoundManager.getInstance().playSuccess();
    else SoundManager.getInstance().playFail();

    setTimeout(() => {
      if (correct >= 3) {
        onNext(correct);
      } else {
        onFail();
        setIsRevealing(false);
        setSelected(new Set());
        setResults([]);
      }
    }, 2500);
  };

  return (
    <div className="absolute inset-0 bg-[#010413] flex flex-col overflow-hidden">
      <ParticleBackground speedMultiplier={0.1} />

      {/* Royal HUD Panel */}
      <div className={`z-40 pt-10 px-8 flex flex-col items-center gap-6 shrink-0 transition-all duration-500 ${isMenuOpen ? 'opacity-0' : 'opacity-100'}`}>
        <div className="bg-[#1e293b] border-x-[3px] border-t-[3px] border-white/20 border-b-[10px] border-b-black/40 px-10 py-4 rounded-[40px] shadow-2xl flex flex-col items-center relative overflow-hidden">
            <div className="absolute top-0 left-0 right-0 h-1/2 bg-gradient-to-b from-white/10 to-transparent" />
            <span className="text-[11px] font-[900] text-[#FFD700] tracking-[0.5em] uppercase mb-2 drop-shadow-md">KELİMELERİ SEÇ</span>
            <div className="flex gap-4">
                {[0,1,2,3,4].map(i => {
                  const isSel = selected.size > i;
                  const res = results[i];
                  let dotClass = isSel ? 'bg-[#00E5FF] border-white shadow-[0_0_15px_#00E5FF]' : 'bg-black/40 border-white/10';
                  if (isRevealing && res !== undefined) dotClass = res ? 'bg-[#00C853] shadow-[0_0_20px_#00C853] border-white' : 'bg-[#D50000] border-white';
                  return <div key={i} className={`w-6 h-6 rounded-xl border-[3px] transition-all duration-500 ${dotClass} ${isRevealing && res ? 'animate-pulse' : ''}`} />;
                })}
            </div>
        </div>
      </div>

      {/* Grid of Royal Cubes */}
      <div className={`flex-1 relative z-10 perspective-[2000px] min-h-0 transition-all duration-500 ${isMenuOpen ? 'blur-md brightness-50' : ''}`}>
          {displayWords.map((item, i) => {
            const isSel = selected.has(i);
            const isCorrect = correctIndices.has(i);

            return (
              <div 
                key={i} 
                onClick={() => handleWordClick(i)}
                style={{ 
                  position: 'absolute', 
                  top: item.pos.t, 
                  left: item.pos.l, 
                  transform: 'translate(-50%, -50%)', 
                  zIndex: isSel ? 200 : 10 + i,
                  willChange: 'transform',
                  padding: '8px' 
                }}
                className={`transition-all duration-700 opacity-100 active:scale-90 ${isRevealing && !isSel ? 'pointer-events-none' : ''}`}
              >
                <Cube3D 
                  width={140} 
                  height={68}
                  depth={40} 
                  label={item.word} 
                  color={item.color.bg} 
                  isSelected={isSel}
                  visualStyle="ROYAL"
                  status={isRevealing && isSel ? (isCorrect ? 'success' : 'fail') : 'idle'}
                  speed={0} 
                  rotationAxis="X" 
                  delay={i * 0.05}
                />
              </div>
            );
          })}
      </div>

      {/* Big Royal Button */}
      <div className={`px-10 pb-12 z-[100] mt-auto shrink-0 transition-all duration-500 ${isMenuOpen ? 'opacity-0' : 'opacity-100'}`}>
        <Button 
          variant={selected.size >= 5 ? "green" : "white"}
          onClick={handleSubmit} 
          disabled={selected.size < 5 || isRevealing} 
          className="w-full !py-8 !text-4xl !rounded-[45px] !border-b-[20px] shadow-[0_30px_60px_rgba(0,0,0,0.5)] active:!border-b-[4px] active:!translate-y-4 transition-all tracking-widest"
        >
          {isRevealing ? 'KONTROL...' : 'TAMAM!'}
        </Button>
      </div>

      <div className="fixed right-4 bottom-4 z-[300]">
        <SideMenu onExit={() => setShowQuitModal(true)} onToggle={setIsMenuOpen} isMinimal={true} expandDirection="up" />
      </div>

      {showQuitModal && <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />}
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { Button } from './Button';
import { Sphere3D } from './Sphere3D';
import { SoundManager } from '../managers/SoundManager';

interface LevelCompleteModalProps {
  level: number;
  coinsEarned: number;
  starsEarned: number;
  onContinue: () => void;
  onMenu: () => void;
}

const PALETTE_COLORS = ['#0047FF', '#FFD700', '#00C853', '#D50000', '#8B5CF6'];

export const LevelCompleteModal: React.FC<LevelCompleteModalProps> = ({ 
  level, 
  coinsEarned, 
  starsEarned,
  onContinue,
  onMenu
}) => {
  const [visibleStars, setVisibleStars] = useState(0);
  const [displayCoins, setDisplayCoins] = useState(0);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    setIsLoaded(true);
    SoundManager.getInstance().playJackpot();

    const starTimer = setTimeout(() => {
      let count = 0;
      const interval = setInterval(() => {
        if (count < starsEarned) {
          count++;
          setVisibleStars(count);
          SoundManager.getInstance().playPop();
        } else {
          clearInterval(interval);
        }
      }, 400);
      return () => clearInterval(interval);
    }, 600);

    const coinTimer = setTimeout(() => {
      let start = 0;
      const end = coinsEarned;
      const counter = setInterval(() => {
        start += 15;
        if (start >= end) {
          setDisplayCoins(end);
          clearInterval(counter);
        } else {
          setDisplayCoins(start);
        }
      }, 16);
      return () => clearInterval(counter);
    }, 1200);

    return () => {
      clearTimeout(starTimer);
      clearTimeout(coinTimer);
    };
  }, [starsEarned, coinsEarned]);

  return (
    <div className="absolute inset-0 z-[500] flex flex-col items-center bg-[#010413] overflow-hidden select-none">

      {/* Royal Background Shine */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_30%,_#0047FF44_0%,_transparent_70%)] pointer-events-none" />

      <div className={`flex-1 w-full max-w-sm flex flex-col items-center px-6 pt-12 pb-4 z-10 transition-all duration-1000 ${isLoaded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}>

        <div className="text-center w-full mb-8">
          <h1 className="text-white text-6xl font-[900] tracking-tighter uppercase leading-none drop-shadow-[0_8px_0_#00268a]">
            HARİKA!
          </h1>
          <p className="text-[#FFD700] font-[900] tracking-[0.4em] uppercase text-xs mt-4 drop-shadow-md">SEVİYE TAMAMLANDI</p>
        </div>

        {/* Victory Card */}
        <div className="w-full bg-[#1e293b] border-x-[4px] border-t-[4px] border-white/20 border-b-[20px] border-b-black/50 rounded-[50px] p-8 shadow-[0_40px_80px_rgba(0,0,0,0.6)] flex flex-col items-center gap-8 mb-10 relative overflow-hidden">
            <div className="absolute top-0 left-0 right-0 h-1/2 bg-gradient-to-b from-white/10 to-transparent pointer-events-none" />

            {/* Stars Row */}
            <div className="flex gap-4">
                {[1, 2, 3].map(i => (
                  <div key={i} className={`text-6xl transition-all duration-700 ${visibleStars >= i ? 'scale-125 rotate-[15deg] drop-shadow-[0_0_25px_#FFD700]' : 'opacity-10 scale-50'}`}>⭐</div>
                ))}
            </div>

            {/* Level Circle */}
            <div className="relative w-36 h-36 flex items-center justify-center">
                <div className="absolute inset-[-20px] bg-[#FFD700]/20 blur-[40px] rounded-full animate-pulse" />
                <div className="relative w-32 h-32 rounded-full bg-white border-b-[15px] border-b-gray-300 border-x-[2px] border-t-[2px] shadow-2xl flex items-center justify-center overflow-hidden">
                    <span className="text-[#010413] text-6xl font-[900] tracking-tighter drop-shadow-sm">{level}</span>
                    <div className="absolute top-0 left-0 right-0 h-1/2 bg-gradient-to-b from-black/5 to-transparent" />
                </div>
            </div>

            {/* Earnings Row */}
