import React, { useState, useEffect } from 'react';

interface LoadingScreenProps {
  onFinished?: () => void;
}

export const LoadingScreen: React.FC<LoadingScreenProps> = ({ onFinished }) => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return Math.min(prev + 1.2, 100);
      });
    }, 16);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (progress === 100) {
      setTimeout(() => onFinished?.(), 800);
    }
  }, [progress, onFinished]);

  return (
    <div className="absolute inset-0 bg-gradient-to-b from-[#0047FF] to-[#010413] flex flex-col items-center justify-center p-8 overflow-hidden font-montserrat">

