      </div>

      {/* ROYAL LOGO DESIGN */}
      <div className="z-20 text-center mb-16 relative group">
        <h1 
          className="text-8xl font-[900] tracking-tighter text-white drop-shadow-[0_12px_0_#00268a]"
          style={{
            filter: 'drop-shadow(0 0 20px rgba(255,255,255,0.3))'
          }}
