import React, { useState, useMemo, useEffect, useRef } from 'react';
import { UserStats } from '../types';
import { Cube3D, RotationAxis } from '../components/Cube3D';
import { SideMenu } from '../components/SideMenu';
import { ParticleBackground } from '../components/ParticleBackground';
import { Button } from '../components/Button';
import { SoundManager } from '../managers/SoundManager';
import { QuitConfirmationModal } from '../components/QuitConfirmationModal';

const ALL_ROUNDS_POOL = [
  { target: "EVRENSEL", distractors: ["EYLEMSEL", "EVRİMSEL", "ERDEMSEL"] },
  { target: "GALAKSİ", distractors: ["GALAKTİK", "GALAKSİN", "GALAKSI"] },
  { target: "YILDIZLAR", distractors: ["YALDIZLAR", "YALNIZLAR", "YILDIRLAR"] },
  { target: "YÖRÜNGE", distractors: ["GÖRÜNGE", "SÜRÜNGE", "YÖRÜNGEL"] },
  { target: "GEZEGEN", distractors: ["GEREKEN", "GELECEK", "GÖZEGEN"] },
  { target: "ATMOSFER", distractors: ["ATMACACI", "ATLASLAR", "ATMOSFERİK"] },
  { target: "KRİSTAL", distractors: ["KARTELA", "KONTROL", "KRİSTİL"] },
  { target: "ELEMENT", distractors: ["EMANETİ", "ELAMETİ", "EKLEMENT"] },
  { target: "MOLEKÜL", distractors: ["MODÜLER", "MAMULLER", "MOLEKÜLER"] },
  { target: "FREKANS", distractors: ["FRAKSİYON", "FREKANSLI", "FREKANSIM"] },
  { target: "AURORA", distractors: ["AVRUPA", "AVRORA", "AURORAL"] },
  { target: "SİNYAL", distractors: ["SİMSAR", "SİNYALİ", "SİNSİCE"] },
  { target: "NEBULA", distractors: ["PUSULA", "NEBULAR", "NEBÜLAS"] },
  { target: "HÜCRESEL", distractors: ["ZÜMRESEL", "SÜRESEL", "HÜCRESİ"] },
  { target: "KARANLIK", distractors: ["KABARIK", "KARARLIK", "KARANLAK"] }
];

const COLORS = ["#0047FF", "#FFD700", "#00C853", "#D50000", "#6366F1"];
const MEMORIZE_DURATION = 30; 
const BASE_ROUND_TIME = 10;
const ROTATION_MODES: RotationAxis[] = ['X', 'Y', 'XY'];

export const WordPuzzle: React.FC<{ stats: UserStats; onComplete: (e: number, t: string[], d: string[]) => void; onExit: () => void; onUpdateStats: (s: Partial<UserStats>) => void }> = ({ stats, onComplete, onExit, onUpdateStats }) => {
  const dynamicRoundTime = useMemo(() => BASE_ROUND_TIME / stats.difficultyFactor, [stats.difficultyFactor]);

  const [currentRound, setCurrentRound] = useState(0);
  const [timeLeft, setTimeLeft] = useState(MEMORIZE_DURATION);
  const [gamePhase, setGamePhase] = useState<'MEMORIZE' | 'GUESS'>('MEMORIZE');
  const [sessionScore, setSessionScore] = useState(0);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [rotationOffset, setRotationOffset] = useState(0);
  const [choiceStatus, setChoiceStatus] = useState<'idle' | 'success' | 'fail'>('idle');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [revealedIndex, setRevealedIndex] = useState(-1);
  const [roundResults, setRoundResults] = useState<( 'success' | 'fail' | null)[]>(new Array(5).fill(null));
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [showQuitModal, setShowQuitModal] = useState(false);
  const [comboCount, setComboCount] = useState(0);

  const timerRef = useRef<number | null>(null);

  const currentRotationAxis = useMemo(() => ROTATION_MODES[currentRound % ROTATION_MODES.length], [currentRound]);

  const puzzleRounds = useMemo(() => {
    const minLength = stats.difficultyFactor > 1.6 ? 7 : stats.difficultyFactor > 1.2 ? 5 : 3;
    const filteredPool = ALL_ROUNDS_POOL.filter(item => item.target.length >= minLength);
    return [...filteredPool].sort(() => Math.random() - 0.5).slice(0, 5);
  }, [stats.difficultyFactor]);

  const activeRoundData = puzzleRounds[currentRound];
  const activeOptions = useMemo(() => {
    const target = activeRoundData.target;
    const distractors = activeRoundData.distractors;
    return [target, ...distractors].sort(() => Math.random() - 0.5);
  }, [activeRoundData]);

  // Hint Logic: Show hint at 50% time left during GUESS phase
  const showHint = gamePhase === 'GUESS' && timeLeft < (dynamicRoundTime / 2) && choiceStatus === 'idle';

  useEffect(() => {
    if (choiceStatus !== 'idle' || selectedChoice || isMenuOpen || isTransitioning || showQuitModal) return;

    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        const nextTime = prev - 0.05;
        if (gamePhase === 'MEMORIZE' && nextTime <= 0) {
          handleFoundIt();
          return dynamicRoundTime;
        }
        if (gamePhase === 'GUESS' && nextTime <= 0) {
          handleChoice("TIME_UP");
          return dynamicRoundTime;
        }
        return nextTime;
      });

      if (gamePhase === 'MEMORIZE') {
        setRotationOffset(prev => prev + (0.75 * stats.difficultyFactor));
      }
    }, 50);

    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [choiceStatus, selectedChoice, isMenuOpen, isTransitioning, currentRound, showQuitModal, dynamicRoundTime, stats.difficultyFactor, gamePhase]);

  const handleFoundIt = () => {
    if (gamePhase !== 'MEMORIZE') return;
    SoundManager.getInstance().playPop();
    setGamePhase('GUESS');
    setTimeLeft(dynamicRoundTime);
  };

  const handleChoice = (choice: string) => {
    if (gamePhase !== 'GUESS' || selectedChoice || choiceStatus !== 'idle' || isTransitioning) return;
    setSelectedChoice(choice);

    setTimeout(() => {
      const isCorrect = choice === activeRoundData.target;
      if (isCorrect) {
        SoundManager.getInstance().playSuccess();
        setComboCount(prev => prev + 1);
      } else {
        if (choice !== "TIME_UP") SoundManager.getInstance().playFail();
        setComboCount(0);
      }
      const points = Math.floor((100 + timeLeft * 10) * (1 + (comboCount * 0.1)));
      const nextResults = [...roundResults];
      setChoiceStatus(isCorrect ? 'success' : 'fail');
      nextResults[currentRound] = isCorrect ? 'success' : 'fail';
      const nextScore = isCorrect ? sessionScore + points : Math.max(0, sessionScore - 50);
      setSessionScore(nextScore);

      const delay = isCorrect ? (activeRoundData.target.length * 150 + 1500) : 1200;
      setTimeout(() => {
        setIsTransitioning(true);
        setTimeout(() => {
          if (currentRound === puzzleRounds.length - 1) {
            onComplete(nextScore, puzzleRounds.map(r => r.target), puzzleRounds.flatMap(r => r.distractors));
          } else {
            setCurrentRound(prev => prev + 1);
            setTimeLeft(MEMORIZE_DURATION);
            setGamePhase('MEMORIZE');
            setChoiceStatus('idle');
            setSelectedChoice(null);
            setRevealedIndex(-1);
            setRoundResults(nextResults);
            setIsTransitioning(false);
          }
        }, 400);
      }, delay);
    }, 500); 
  };

  useEffect(() => {
    if (choiceStatus === 'success') {
      let currentIdx = 0;
      const interval = setInterval(() => {
        setRevealedIndex(currentIdx);
        currentIdx++;
        if (currentIdx >= activeRoundData.target.length) clearInterval(interval);
      }, 150);
      return () => clearInterval(interval);
    } else {
      setRevealedIndex(-1);
    }
  }, [choiceStatus, activeRoundData.target]);

  const ringItems = useMemo(() => {
    return activeRoundData.target.split("").map((char, i) => ({
      char,
      color: COLORS[i % COLORS.length]
    }));
  }, [activeRoundData]);

  const renderRing = () => {
    const dist = 130; 
    const isSuccess = choiceStatus === 'success';
    const dynamicSpacing = 68;
    const dynamicCubeSize = 76;

    return (
      <div className={`relative w-full h-full flex items-center justify-center transition-all duration-700 ${isTransitioning ? 'opacity-0 scale-75 blur-lg' : 'opacity-100 scale-100'}`} style={{ transformStyle: 'preserve-3d' }}>

        {isSuccess && ringItems.map((_, idx) => {
          if (idx === 0) return null;
          const xPos = (idx - 1 - (ringItems.length - 1) / 2) * dynamicSpacing + (dynamicSpacing / 2);
          const isVisible = revealedIndex >= idx;
          return (
            <div 
              key={`chain-${idx}`} 
              className="absolute flex items-center justify-center transition-all duration-500 z-0"
              style={{ width: dynamicSpacing, left: `calc(50% + ${xPos}px)`, top: '50%', transform: 'translate(-50%, -50%) translateZ(5px)', opacity: isVisible ? 1 : 0 }}
            >
              <div className="w-full h-4 bg-gradient-to-r from-[#FFD700] via-white to-[#FFD700] shadow-[0_0_15px_#FFD700] blur-[1px] rounded-full" />
            </div>
          );
        })}

        {ringItems.map((item, idx) => {
          const angle = (idx / ringItems.length) * 360 + rotationOffset;
          const rad = (angle * Math.PI) / 180;
          let x = 0, y = 0, z = 0, scale = 1;

          if (isSuccess) {
            x = (idx - (ringItems.length - 1) / 2) * dynamicSpacing;
            y = 0; z = 20; scale = 1.15 + (revealedIndex === idx ? 0.35 : 0);
          } else {
             x = Math.cos(rad) * dist; y = Math.sin(rad) * dist; z = 0;
          }

          return (
            <div key={`${currentRound}-${idx}`} className="absolute transition-all duration-400 ease-out" style={{ transform: `translate3d(${x}px, ${y}px, ${z}px) scale(${scale})`, transformStyle: 'preserve-3d', zIndex: (revealedIndex === idx) ? 300 : 20 }}>
              <Cube3D 
                size={isSuccess ? dynamicCubeSize : 68} 
                label={gamePhase === 'GUESS' && !isSuccess ? '?' : item.char} 
                color={item.color} 
                visualStyle="ROYAL" 
                rotationAxis={currentRotationAxis}
                status={choiceStatus} 
                isRevealed={true} 
                delay={idx * 0.05} 
                speed={(isSuccess || gamePhase === 'GUESS') ? 0 : 4} 
              />
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="absolute inset-0 bg-gradient-to-b from-[#0047FF] to-[#010413] flex flex-col overflow-hidden">
      <ParticleBackground speedMultiplier={choiceStatus === 'success' ? 0.05 : 0.2} />

      {/* ROYAL HUD HEADER */}
      <div className={`pt-12 px-8 flex justify-between items-center z-20 transition-opacity duration-500 ${isMenuOpen ? 'opacity-0' : 'opacity-100'}`}>
        <div className="bg-[#1E293B] border-x-[2px] border-t-[2px] border-white/20 border-b-[8px] border-b-[#0F172A] rounded-[24px] px-6 py-3 shadow-2xl flex flex-col items-center relative overflow-hidden">
            <div className="absolute top-0 left-0 right-0 h-1/2 bg-white/10" />
            <div className="flex gap-2 relative z-10">
              {roundResults.map((res, i) => (
                <div key={i} className={`w-5 h-5 rounded-lg border-2 transition-all duration-500 ${res === 'success' ? 'bg-[#00C853] border-white' : res === 'fail' ? 'bg-[#D50000] border-white' : i === currentRound ? 'bg-[#00E5FF] border-white animate-pulse' : 'bg-black/40 border-white/10'}`} />
              ))}
            </div>
            <span className="text-[10px] font-black text-white/40 tracking-[0.3em] uppercase mt-2">İLERLEME</span>
        </div>
        <div className="text-5xl font-[900] text-white drop-shadow-[0_6px_0_#00268a] tabular-nums">
            {sessionScore.toLocaleString()}
        </div>
      </div>

      <div className={`flex-1 relative flex items-center justify-center perspective-[1500px] z-10 min-h-0 ${isMenuOpen ? 'blur-sm brightness-50' : ''}`}>
        {renderRing()}
      </div>

      {/* Control Area with Styled Timer Bar */}
      <div className={`px-6 pb-14 flex flex-col gap-8 z-20 transition-all duration-700 shrink-0 ${isTransitioning || choiceStatus === 'success' ? 'opacity-0 translate-y-20' : 'opacity-100 translate-y-0'} ${isMenuOpen ? 'blur-sm' : ''}`}>

        {/* ROYAL TIMER BAR */}
        <div className="w-full flex flex-col items-center gap-2">
            <div className="w-full h-10 bg-[#0F172A] rounded-[20px] border-b-[6px] border-[#010413] border-x-[1.5px] border-t-[1.5px] border-t-white/10 shadow-inner p-[6px] relative overflow-hidden">
              <div 
                className="h-full relative transition-all duration-100 ease-linear rounded-full" 
                style={{ 
                    width: `${(timeLeft / (gamePhase === 'MEMORIZE' ? MEMORIZE_DURATION : dynamicRoundTime)) * 100}%`, 
                    backgroundColor: gamePhase === 'MEMORIZE' ? '#00E5FF' : '#FFD700', 
                    boxShadow: gamePhase === 'MEMORIZE' ? '0 0 20px #00E5FF' : '0 0 20px #FFD700' 
                }} 
              >
                <div className="absolute top-0 left-0 right-0 h-1/2 bg-white/30 rounded-full" />
              </div>
            </div>
            <span className="text-white/40 font-black text-[10px] tracking-[0.5em] uppercase">KALAN SÜRE</span>
        </div>

        {gamePhase === 'MEMORIZE' ? (
          <div className="w-full flex justify-center animate-[bounce_2s_infinite]">
            <Button 
              variant="royal-gold" 
              onClick={handleFoundIt}
              className="w-full !h-32 !rounded-[50px] !text-5xl !border-b-[20px] shadow-2xl active:!border-b-[4px] active:!translate-y-4"
            >
              BULDUM!
            </Button>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-4">
            {activeOptions.map((opt, i) => {
              const isTarget = opt === activeRoundData.target;
              return (
                <Button 
                  key={i} 
                  variant={(selectedChoice === opt) ? (choiceStatus === 'success' ? 'green' : 'coral') : (['indigo', 'pink', 'royal-red', 'cyan'][i % 4] as any)} 
                  onClick={() => handleChoice(opt)} 
                  className={`w-full !h-28 !rounded-[40px] !text-[26px] !border-b-[15px] active:!border-b-[2px] transition-all duration-300 ${
                    (selectedChoice !== null && selectedChoice !== opt) ? 'opacity-20 scale-95 blur-[2px]' : ''
                  } ${
                    showHint && isTarget ? 'animate-bounce !border-[#FFD700] shadow-[0_0_40px_#FFD700]' : ''
                  }`} 
                  disabled={selectedChoice !== null}
                >
                  <span className="truncate w-full px-2 drop-shadow-md">{opt}</span>
                </Button>
              );
            })}
          </div>
        )}
      </div>

      <div className="fixed right-4 bottom-4 z-[300]">
        <SideMenu onExit={() => setShowQuitModal(true)} onToggle={setIsMenuOpen} isMinimal={true} expandDirection="up" />
      </div>
      {showQuitModal && <QuitConfirmationModal onConfirm={onExit} onCancel={() => setShowQuitModal(false)} />}
    </div>
  );
};

import React from 'react';

interface Portal3DProps {
  level: number;
  active: boolean;
}

export const Portal3D: React.FC<Portal3DProps> = ({ level, active }) => {
  // Basamak sayısına göre font boyutunu ayarla - Overlap önlemek için küçültüldü
  const getFontSize = () => {
    const digits = level.toString().length;
    if (digits >= 4) return 'text-[100px]';
    if (digits === 3) return 'text-[130px]';
    if (digits === 2) return 'text-[180px]';
    return 'text-[240px]';
  };

  return (
    <div className={`relative w-full h-full flex items-center justify-center transition-all duration-1000 ${active ? 'scale-100 opacity-100' : 'scale-90 opacity-40'}`}>

      {/* Giant 3D Enamel Number */}
      <div className="relative z-20 animate-[pureFloat_4s_infinite_ease-in-out] select-none pointer-events-none flex items-center justify-center w-full">
        <div className="relative flex items-center justify-center w-full px-10">
          {/* Main 3D Number Body */}
          <span 
            className={`${getFontSize()} font-[900] text-white tracking-tighter leading-none block text-center transition-all duration-500`}
            style={{
              textShadow: `
                0 4px 0 #cbd5e1,
                0 10px 0 #94a3b8,
                0 20px 0 #64748b,
                0 28px 0 #475569,
                0 40px 80px rgba(0,0,0,0.8)
              `,
              filter: 'drop-shadow(0 0 30px rgba(255,255,255,0.15))'
            }}
          >
            {level}
          </span>

          {/* High Gloss Reflection Overlay */}
          <div 
            className="absolute top-[10%] left-0 right-0 h-[30%] bg-gradient-to-b from-white/30 to-transparent blur-3xl rounded-full opacity-50" 
            style={{ transform: 'rotate(-5deg) scaleX(0.7)' }}
          />

          {/* Rim Light (Bottom Shine) */}
          <div className="absolute bottom-[5%] left-1/2 -translate-x-1/2 w-[60%] h-3 bg-white/10 blur-xl rounded-full" />
        </div>
      </div>

      <style>{`
        @keyframes pureFloat {
          0%, 100% { 
            transform: translateY(0) rotate(0.1deg); 
          }
          50% { 
            transform: translateY(-20px) rotate(-0.3deg); 
          }
        }
      `}</style>
    </div>
  );
};

