                <div className="w-full bg-[#94a3b8] border-b-[10px] border-[#475569] border-x-[2px] border-t-[2px] border-t-white/30 rounded-t-[32px] h-20 flex flex-col items-center justify-center relative shadow-xl overflow-hidden">
                   <div className="absolute top-0 left-0 right-0 h-1/2 bg-white/20 pointer-events-none" />
